/// `calendar-iso-goto-week` / `calendar-iso-goto-date`: read an ISO
/// `year week weekday` and echo the Gregorian date.
fn calendar_iso_goto_week(cx: &mut Context) {
    ui::prompt(
        cx,
        "ISO year week weekday(1=Mon..7=Sun): ".into(),
        None,
        |_e: &Editor, _s: &str| Vec::new(),
        move |cx, input, event| {
            if event != PromptEvent::Validate {
                return;
            }
            let Some((y, w, dow)) = cal_three_ints(input) else {
                cx.editor.set_error("Need: year week weekday");
                return;
            };
            if !(1..=53).contains(&w) || !(1..=7).contains(&dow) {
                cx.editor.set_error("Week must be 1..53, weekday 1..7");
                return;
            }
            let g = zemacs_core::calendar::date_from_iso(y as i32, w as u32, dow as u32);
            cx.editor.set_status(format!(
                "ISO {y}-W{w:02}-{dow} = {} {}, {} (Gregorian)",
                zemacs_core::calendar::MONTH_NAMES[(g.month - 1) as usize],
                g.day,
                g.year
            ));
        },
    );
}

/// `calendar-astro-goto-day-number`: read an astronomical (Julian) day number
/// and echo the Gregorian date at that noon.
fn calendar_astro_goto_day_number(cx: &mut Context) {
    ui::prompt(
        cx,
        "Astronomical (Julian) day number: ".into(),
        None,
        |_e: &Editor, _s: &str| Vec::new(),
        move |cx, input, event| {
            if event != PromptEvent::Validate {
                return;
            }
            let jd: i64 = match input.trim().parse() {
                Ok(n) => n,
                Err(_) => {
                    cx.editor.set_error("Not a number");
                    return;
                }
            };
            // astro_day_number = to_serial + 2440588; Gregorian = from_serial(jd - 2440588).
            let g = zemacs_core::calendar::from_serial(jd - 2440588);
            cx.editor.set_status(format!(
                "Astro day {jd} = {} {}, {} (Gregorian noon)",
                zemacs_core::calendar::MONTH_NAMES[(g.month - 1) as usize],
                g.day,
                g.year
            ));
        },
    );
}

/// `calendar-mayan-goto-long-count`: read a Mayan long count `b k t u kin` and
/// echo the Gregorian date.
fn calendar_mayan_goto_long_count(cx: &mut Context) {
    ui::prompt(
        cx,
        "Mayan long count (baktun katun tun uinal kin): ".into(),
        None,
        |_e: &Editor, _s: &str| Vec::new(),
        move |cx, input, event| {
            if event != PromptEvent::Validate {
                return;
            }
            let nums: Vec<i64> = input
                .split(|c: char| c == '.' || c == ',' || c.is_whitespace())
                .filter(|t| !t.is_empty())
                .filter_map(|t| t.parse::<i64>().ok())
                .collect();
            if nums.len() != 5 {
                cx.editor
                    .set_error("Need five numbers: baktun katun tun uinal kin");
                return;
            }
            let f = zemacs_core::calendar::fixed_from_mayan_long_count(
                nums[0], nums[1], nums[2], nums[3], nums[4],
            );
            let g = zemacs_core::calendar::from_rd(f);
            cx.editor.set_status(format!(
                "Long count {}.{}.{}.{}.{} = {} {}, {} (Gregorian)",
                nums[0],
                nums[1],
                nums[2],
                nums[3],
                nums[4],
                zemacs_core::calendar::MONTH_NAMES[(g.month - 1) as usize],
                g.day,
                g.year
            ));
        },
    );
}

/// Emacs `occur` (`M-s o`): read a regexp, then list every line in the current
/// buffer that matches it in an `*Occur*` overlay whose entries jump back to the
/// source line. The regexp is read in the minibuffer; matching, jumping and the
/// `occur-mode` keys live in [`crate::ui::occur::Occur`].
/// Run occur for `input` against the document `doc_id`/`view_id`, pushing the
/// results overlay. Shared by the interactive `occur` prompt and `isearch_occur`
/// (which supplies the current search pattern directly). Takes `editor`/`jobs`
/// rather than a `Context` so it is callable from both a static command and a
/// prompt callback (which see different `Context` types).
fn occur_run(
    editor: &mut Editor,
    jobs: &mut Jobs,
    doc_id: DocumentId,
    view_id: ViewId,
    input: &str,
) {
    if input.is_empty() {
        return;
    }
    let re = match regex::Regex::new(input) {
        Ok(re) => re,
        Err(e) => {
            editor.set_error(format!("occur: invalid regexp: {e}"));
            return;
        }
    };
    let Some(text) = editor
        .documents()
        .find(|d| d.id() == doc_id)
        .map(|d| d.text().to_string())
    else {
        return;
    };
    let matches = zemacs_core::occur::occur(&text, |line| {
        re.find(line).map(|hit| line[..hit.start()].chars().count())
    });
    if matches.is_empty() {
        editor.set_status(format!("occur: no matches for {input}"));
        return;
    }
    let overlay = crate::ui::occur::Occur::new(doc_id, view_id, input.to_string(), matches);
    let call = crate::job::Callback::EditorCompositor(Box::new(
        move |_editor: &mut Editor, compositor: &mut crate::compositor::Compositor| {
            compositor.push(Box::new(overlay));
        },
    ));
    jobs.callback(async move { Ok(call) });
}

fn occur(cx: &mut Context) {
    let (view, doc) = current_ref!(cx.editor);
    let doc_id = doc.id();
    let view_id = view.id;
    ui::prompt(
        cx,
        "List lines matching regexp: ".into(),
        Some('/'),
        |_editor: &Editor, _input: &str| Vec::new(),
        move |cx, input, event| {
            if event != PromptEvent::Validate {
                return;
            }
            occur_run(cx.editor, cx.jobs, doc_id, view_id, input);
        },
    );
}

/// Emacs `rmail`: open the Rmail mail reader on the primary mail file
/// (`~/RMAIL`, `rmail-file-name`). A missing file opens an empty reader.
fn rmail(cx: &mut Context) {
    let path = zemacs_stdx::path::home_dir()
        .map(|h| h.join("RMAIL"))
        .unwrap_or_else(|_| std::path::PathBuf::from("RMAIL"));
    open_overlay(cx, move |editor| {
        let text = std::fs::read_to_string(&path).unwrap_or_default();
        let mailbox = zemacs_core::rmail::Mailbox::from_mbox(&text);
        if mailbox.is_empty() {
            editor.set_status(format!("rmail: no messages in {}", path.display()));
        }
        Ok(Box::new(crate::ui::rmail::Rmail::new(mailbox, path)) as Box<dyn Component>)
    });
}

