/// Emacs `animate-birthday-present`: animate the birthday-song text swooping
/// into place (self-animating overlay; see ui/animate.rs).
fn animate_birthday_present(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::animate::Animate::birthday_present()) as Box<dyn Component>)
    });
}

/// Emacs `dissociated-press`: scramble the current buffer's text with the
/// travesty generator (see ui/dissociate.rs). Uses 2 chars of continuity (the
/// emacs default) and reveals a bounded block; any key closes.
fn dissociated_press(cx: &mut Context) {
    let source = doc!(cx.editor).text().to_string();
    if source.trim().is_empty() {
        cx.editor
            .set_error("The buffer contains no text to start from");
        return;
    }
    let seed = fastrand::u64(..);
    open_overlay(cx, move |_editor| {
        Ok(
            Box::new(crate::ui::dissociate::Dissociate::new(&source, 2, seed))
                as Box<dyn Component>,
        )
    });
}

/// Emacs `dired-jump` (C-x C-j): open Dired on the current buffer's directory,
/// falling back to the working directory.
fn dired_jump(cx: &mut Context) {
    let dir = doc!(cx.editor)
        .path()
        .and_then(|p| p.parent().map(|p| p.to_path_buf()))
        .unwrap_or_else(zemacs_stdx::env::current_working_dir);
    open_overlay(cx, move |_editor| {
        crate::ui::dired::Dired::new(dir)
            .map(|d| Box::new(d) as Box<dyn Component>)
            .map_err(|e| format!("dired: {e}"))
    });
}

/// Emacs `dired-other-window` (C-x 4 d): open Dired on the workspace root. In
/// zemacs Dired is a full-screen modal overlay, so "other window" cannot show the
/// listing beside the current buffer; it opens the same overlay (marked partial).
fn dired_other_window(cx: &mut Context) {
    dired(cx);
}

/// Emacs `dired-jump-other-window` (C-x 4 C-j): like `dired-jump` but nominally
/// in another window. zemacs Dired is a modal overlay, so this is the same as
/// `dired-jump` (marked partial for the missing split semantics).
fn dired_jump_other_window(cx: &mut Context) {
    dired_jump(cx);
}

/// Emacs `dired-at-point` (ffap): read the file name around point in the current
/// buffer and open Dired on it — on its parent directory if it names a file. Pure
/// token extraction lives in `zemacs_core::dired::filename_at_point`.
fn dired_at_point(cx: &mut Context) {
    let name = {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text();
        let slice = text.slice(..);
        let cursor = doc.selection(view.id).primary().cursor(slice);
        let byte = text.char_to_byte(cursor);
        zemacs_core::dired::filename_at_point(&text.to_string(), byte)
    };
    let Some(name) = name else {
        cx.editor.set_error("dired-at-point: no file name at point");
        return;
    };
    // Resolve relative to the current buffer's directory, else the working dir.
    let base = doc!(cx.editor)
        .path()
        .and_then(|p| p.parent().map(|p| p.to_path_buf()))
        .unwrap_or_else(zemacs_stdx::env::current_working_dir);
    let target = if Path::new(&name).is_absolute() {
        PathBuf::from(&name)
    } else {
        base.join(&name)
    };
    // Dired the directory itself, or the parent when it names a regular file.
    let dir = if target.is_dir() {
        target
    } else {
        target
            .parent()
            .map(|p| p.to_path_buf())
            .unwrap_or_else(zemacs_stdx::env::current_working_dir)
    };
    open_overlay(cx, move |_editor| {
        crate::ui::dired::Dired::new(dir)
            .map(|d| Box::new(d) as Box<dyn Component>)
            .map_err(|e| format!("dired: {e}"))
    });
}

fn file_explorer_in_current_buffer_directory(cx: &mut Context) {
    let doc_dir = doc!(cx.editor)
        .path()
        .and_then(|path| path.parent().map(|path| path.to_path_buf()));

    let path = match doc_dir {
        Some(path) => path,
        None => {
            let cwd = zemacs_stdx::env::current_working_dir();
            if !cwd.exists() {
                cx.editor.set_error(
                    "Current buffer has no parent and current working directory does not exist",
                );
                return;
            }
            cx.editor.set_error(
                "Current buffer has no parent, opening file explorer in current working directory",
            );
            cwd
        }
    };

    if let Ok(picker) = ui::file_explorer(path, cx.editor) {
        cx.push_layer(Box::new(overlaid(picker)));
    }
}

fn file_explorer_in_current_directory(cx: &mut Context) {
    let cwd = zemacs_stdx::env::current_working_dir();
    if !cwd.exists() {
        cx.editor
            .set_error("Current working directory does not exist");
        return;
    }

    if let Ok(picker) = ui::file_explorer(cwd, cx.editor) {
        cx.push_layer(Box::new(overlaid(picker)));
    }
}

struct PathStyleConfig {
    directory_style: Style,
    number_style: Style,
    colon_style: Style,
}

impl PathStyleConfig {
    fn new(theme: &zemacs_view::Theme) -> Self {
        Self {
            directory_style: theme.get("ui.text.directory"),
            number_style: theme.get("constant.numeric.integer"),
            colon_style: theme.get("punctuation"),
        }
    }

    fn stylize<'a>(&self, path: Option<&'a Path>, line: Option<usize>) -> Cell<'a> {
        let mut spans = Vec::new();
        if let Some(path) = path {
            let directories = path
                .parent()
                .filter(|p| !p.as_os_str().is_empty())
                .map(|p| format!("{}{}", p.display(), std::path::MAIN_SEPARATOR))
                .unwrap_or_default();
            spans.push(Span::styled(directories, self.directory_style));
        }
        let filename = path.as_ref().map_or(SCRATCH_BUFFER_NAME.into(), |path| {
            path.file_name()
                .expect("all document names are normalized (can't end in `..`)")
                .to_string_lossy()
        });
        spans.push(Span::raw(filename));
        if let Some(line) = line {
            spans.extend([
                Span::styled(":", self.colon_style),
                Span::styled((line + 1).to_string(), self.number_style),
            ]);
        }

        Cell::from(Spans::from(spans))
    }
}

fn buffer_picker(cx: &mut Context) {
    buffer_picker_impl(cx, None, false);
}

/// SPC b N C-i : open an existing buffer in a split — a second view of that buffer's shared
/// Document, i.e. an indirect buffer of it (Spacemacs `make-indirect-buffer` from a buffer).
fn clone_indirect_from_buffer(cx: &mut Context) {
    buffer_picker_impl(cx, Some(Action::VerticalSplit), false);
}

/// SPC b w : go to the window already displaying the chosen buffer (focus it instead of reopening),
/// falling back to opening it in the current window. Spacemacs `spacemacs/goto-buffer-window`.
fn goto_buffer_window(cx: &mut Context) {
    buffer_picker_impl(cx, None, true);
}

/// Shared body for the buffer picker. When `force_action` is set, the chosen buffer always opens
/// with that action (e.g. always in a split). When `goto_window` is set, an existing window
/// already showing the buffer is focused instead of opening it again. Otherwise the picker's own
/// open action is used.
fn buffer_picker_impl(cx: &mut Context, force_action: Option<Action>, goto_window: bool) {
    let picker = build_buffer_picker(cx.editor, force_action, goto_window);
    cx.push_layer(picker);
}

/// Build the buffer-picker component from editor state. Shared by the `buffer_picker` family and the
/// `:buffers`/`:ls`/`:files` typable commands (which open it via an EditorCompositor job).
pub(crate) fn build_buffer_picker(
    editor: &mut Editor,
    force_action: Option<Action>,
    goto_window: bool,
) -> Box<dyn Component> {
    let current = view!(editor).doc;

    struct BufferMeta<'a> {
        id: DocumentId,
        path: Option<Cow<'a, Path>>,
        is_modified: bool,
        is_current: bool,
        focused_at: std::time::Instant,
    }

    let new_meta = |doc: &Document| BufferMeta {
        id: doc.id(),
        path: doc
            .path()
            .map(ToOwned::to_owned)
            .map(zemacs_stdx::path::get_relative_path),
        is_modified: doc.is_modified(),
        is_current: doc.id() == current,
        focused_at: doc.focused_at,
    };

    let mut items = editor
        .documents
        .values()
        .map(new_meta)
        .collect::<Vec<BufferMeta>>();

    // mru
    items.sort_unstable_by_key(|item| std::cmp::Reverse(item.focused_at));

    let columns = [
        PickerColumn::new("id", |meta: &BufferMeta, _| meta.id.to_string().into()),
        PickerColumn::new("flags", |meta: &BufferMeta, _| {
            let mut flags = String::new();
            if meta.is_modified {
                flags.push('+');
            }
            if meta.is_current {
                flags.push('*');
            }
            flags.into()
        }),
        PickerColumn::new("path", |meta: &BufferMeta, config: &PathStyleConfig| {
            config.stylize(meta.path.as_deref(), None)
        }),
    ];

    let initial_cursor =
        if editor.config().buffer_picker.start_position.is_previous() && !items.is_empty() {
            1
        } else {
            0
        };

    let picker = Picker::new(
        columns,
        2,
        items,
        PathStyleConfig::new(&editor.theme),
        move |cx, meta, action| {
            if goto_window {
                let existing = cx
                    .editor
                    .tree
                    .traverse()
                    .find(|(_, v)| v.doc == meta.id)
                    .map(|(id, _)| id);
                if let Some(view_id) = existing {
                    cx.editor.focus(view_id);
                    return;
                }
            }
            cx.editor.switch(meta.id, force_action.unwrap_or(action));
        },
    )
    .with_initial_cursor(initial_cursor)
    .with_preview(|editor, meta| {
        let doc = &editor.documents.get(&meta.id)?;
        let lines = doc.selections().values().next().map(|selection| {
            let cursor_line = selection.primary().cursor_line(doc.text().slice(..));
            (cursor_line, cursor_line)
        });
        Some((meta.id.into(), lines))
    });
    Box::new(overlaid(picker))
}

fn jumplist_picker(cx: &mut Context) {
    let picker = build_jumplist_picker(cx.editor);
    cx.push_layer(picker);
}

/// Build the jumplist picker from editor state (shared by the static command and `:jumps`).
pub(crate) fn build_jumplist_picker(editor: &mut Editor) -> Box<dyn Component> {
    struct JumpMeta<'a> {
        id: DocumentId,
        path: Option<Cow<'a, Path>>,
        selection: Selection,
        line_start: usize,
        text: String,
        is_current: bool,
    }

    for (view, _) in editor.tree.views_mut() {
        for doc_id in view.jumps.iter().map(|e| e.0).collect::<Vec<_>>().iter() {
            let doc = doc_mut!(editor, doc_id);
            view.sync_changes(doc);
        }
    }

    let new_meta = |view: &View, doc_id: DocumentId, selection: Selection| {
        let doc = doc!(editor, &doc_id);
        let text = doc.text().slice(..);
        let contents = selection
            .fragments(text)
            .map(Cow::into_owned)
            .collect::<Vec<_>>()
            .join(" ");
        let line_start = selection.primary().cursor_line(text);

        JumpMeta {
            id: doc_id,
            path: doc
                .path()
                .map(ToOwned::to_owned)
                .map(zemacs_stdx::path::get_relative_path),
            selection,
            line_start,
            text: contents,
            is_current: view.doc == doc_id,
        }
    };

    let columns = [
        ui::PickerColumn::new("id", |item: &JumpMeta, _| item.id.to_string().into()),
        ui::PickerColumn::new("path", |item: &JumpMeta, config: &PathStyleConfig| {
            config.stylize(item.path.as_deref(), Some(item.line_start))
        }),
        ui::PickerColumn::new("flags", |item: &JumpMeta, _| {
            let mut flags = Vec::new();
            if item.is_current {
                flags.push("*");
            }

            if flags.is_empty() {
                "".into()
            } else {
                format!(" ({})", flags.join("")).into()
            }
        }),
        ui::PickerColumn::new("contents", |item: &JumpMeta, _| item.text.as_str().into()),
    ];

    let picker = Picker::new(
        columns,
        1, // path
        editor.tree.views().flat_map(|(view, _)| {
            view.jumps
                .iter()
                .rev()
                .map(|(doc_id, selection)| new_meta(view, *doc_id, selection.clone()))
        }),
        PathStyleConfig::new(&editor.theme),
        |cx, meta, action| {
            cx.editor.switch(meta.id, action);
            let config = cx.editor.config();
            let (view, doc) = (view_mut!(cx.editor), doc_mut!(cx.editor, &meta.id));
            doc.set_selection(view.id, meta.selection.clone());
            if action.align_view(view, doc.id()) {
                view.ensure_cursor_in_view_center(doc, config.scrolloff);
            }
        },
    )
    .with_preview(|editor, meta| {
        let doc = &editor.documents.get(&meta.id)?;
        let line = meta.selection.primary().cursor_line(doc.text().slice(..));
        Some((meta.id.into(), Some((line, line))))
    });
    Box::new(overlaid(picker))
}

// ===========================================================================
// Quickfix list + location list (vim `:copen`/`:cnext`/`:lopen`/… family).
//
// The quickfix list is a single global list of jumpable `{path,line,col,text}`
// entries on the `Editor`; the location list is the same but scoped to a
// window (`View`). Entries are produced by parsing compiler/grep output with
// `qf_entry_from_line` (a small built-in 'errorformat'), then navigated and
// displayed by the commands below. See `commands/typed.rs` for the `:` wiring.
// ===========================================================================

/// Which list a quickfix operation targets.
#[derive(Clone, Copy, PartialEq, Eq)]
pub(crate) enum QfKind {
    Quickfix,
    Location,
}

/// Parse one line of compiler/grep output into a [`QfEntry`]. Recognises the
/// common `path:line[:col][: message]` shape (rustc, gcc, `rg --vimgrep`,
/// `grep -n`). Lines/cols in the input are 1-based (vim convention); the
/// returned entry is 0-based. Returns `None` for lines with no file reference
/// (so plain log noise is skipped, matching vim's errorformat behaviour).
pub(crate) fn qf_entry_from_line(line: &str) -> Option<QfEntry> {
    // Find the first whitespace-delimited token that looks like `path:line…`.
    for raw in line.split(char::is_whitespace) {
        let tok = raw.trim_matches(|c| matches!(c, ':' | ',' | '(' | ')' | '[' | ']' | '"' | '\''));
        let mut parts = tok.split(':');
        let path = parts.next()?;
        // Must look like a path (rejects timestamps like `12:34`).
        if path.is_empty() || !(path.contains('/') || path.contains('.')) {
            continue;
        }
        let Some(Ok(lineno)) = parts.next().map(|s| s.parse::<usize>()) else {
            continue;
        };
        if lineno == 0 {
            continue;
        }
        let col = parts
            .next()
            .and_then(|c| c.parse::<usize>().ok())
            .unwrap_or(1);
        // The remainder of the original line (after the matched token) is the
        // message; fall back to the whole trimmed line.
        let text = line
            .split_once(raw)
            .map(|(_, rest)| rest.trim_start_matches([':', ' ']).to_string())
            .filter(|s| !s.is_empty())
            .unwrap_or_else(|| line.trim().to_string());
        return Some(QfEntry {
            path: PathBuf::from(path),
            line: lineno - 1,
            col: col.saturating_sub(1),
            text,
        });
    }
    None
}

/// Parse a block of text (compiler output, a buffer, an expression) into
/// quickfix entries, skipping lines with no file reference.
pub(crate) fn qf_entries_from_text(text: &str) -> Vec<QfEntry> {
    text.lines().filter_map(qf_entry_from_line).collect()
}

/// Clamp/advance a list index by `delta`, staying within `[0, len)`. Returns
/// `None` when the list is empty. Saturates at the ends (vim does not wrap
/// `:cnext` past the last entry).
pub(crate) fn qf_advance_index(idx: Option<usize>, len: usize, delta: isize) -> Option<usize> {
    if len == 0 {
        return None;
    }
    match idx {
        // No entry selected yet: the first navigation lands on the first entry.
        None => Some(0),
        Some(cur) => Some((cur as isize + delta).clamp(0, len as isize - 1) as usize),
    }
}

fn qf_entries(editor: &Editor, kind: QfKind) -> Vec<QfEntry> {
    match kind {
        QfKind::Quickfix => editor.quickfix.clone(),
        QfKind::Location => view!(editor).loclist.clone(),
    }
}

/// A clone of a list's entries, for callers outside this module (`:cdo`).
pub(crate) fn qf_snapshot(editor: &Editor, kind: QfKind) -> Vec<QfEntry> {
    qf_entries(editor, kind)
}

const QF_HISTORY_MAX: usize = 10;

/// Push a freshly-created quickfix list onto the history stack (vim keeps the
/// last 10), dropping any lists newer than the current position first.
fn qf_history_push(editor: &mut Editor, list: Vec<QfEntry>) {
    let stack = &mut editor.quickfix_stack;
    if !stack.is_empty() {
        stack.truncate(editor.quickfix_stack_pos + 1);
    }
    stack.push(list);
    if stack.len() > QF_HISTORY_MAX {
        let overflow = stack.len() - QF_HISTORY_MAX;
        stack.drain(0..overflow);
    }
    editor.quickfix_stack_pos = stack.len().saturating_sub(1);
}

/// `:colder`/`:cnewer`: move `delta` steps through the quickfix history and
/// load that list as the active quickfix list.
pub(crate) fn qf_history_go(editor: &mut Editor, delta: isize) {
    let len = editor.quickfix_stack.len();
    if len == 0 {
        editor.set_error("quickfix list history is empty");
        return;
    }
    let pos = (editor.quickfix_stack_pos as isize + delta).clamp(0, len as isize - 1) as usize;
    if pos == editor.quickfix_stack_pos {
        editor.set_status(if delta < 0 {
            "at oldest list"
        } else {
            "at newest list"
        });
        return;
    }
    editor.quickfix_stack_pos = pos;
    editor.quickfix = editor.quickfix_stack[pos].clone();
    editor.quickfix_idx = (!editor.quickfix.is_empty()).then_some(0);
    editor.set_status(format!("quickfix list {} of {}", pos + 1, len));
}

/// `:chistory`: report the position in the quickfix history stack.
pub(crate) fn qf_history_info(editor: &mut Editor) {
    let len = editor.quickfix_stack.len();
    if len == 0 {
        editor.set_status("no quickfix lists");
    } else {
        editor.set_status(format!(
            "quickfix list {} of {}",
            editor.quickfix_stack_pos + 1,
            len
        ));
    }
}

fn qf_len(editor: &Editor, kind: QfKind) -> usize {
    match kind {
        QfKind::Quickfix => editor.quickfix.len(),
        QfKind::Location => view!(editor).loclist.len(),
    }
}

fn qf_index(editor: &Editor, kind: QfKind) -> Option<usize> {
    match kind {
        QfKind::Quickfix => editor.quickfix_idx,
        QfKind::Location => view!(editor).loclist_idx,
    }
}

fn qf_set_index(editor: &mut Editor, kind: QfKind, idx: Option<usize>) {
    match kind {
        QfKind::Quickfix => editor.quickfix_idx = idx,
        QfKind::Location => view_mut!(editor).loclist_idx = idx,
    }
}

/// Replace (or append to) a list's entries, resetting the current index to the
/// first entry when the list was previously empty/unset.
pub(crate) fn qf_set_entries(
    editor: &mut Editor,
    kind: QfKind,
    new_entries: Vec<QfEntry>,
    append: bool,
) -> usize {
    let added = new_entries.len();
    match kind {
        QfKind::Quickfix => {
            if append {
                editor.quickfix.extend(new_entries);
            } else {
                editor.quickfix = new_entries;
                editor.quickfix_idx = None;
                // A fresh list becomes a new entry in the `:colder`/`:cnewer`
                // history (append variants keep editing the current list).
                let snapshot = editor.quickfix.clone();
                qf_history_push(editor, snapshot);
            }
            if editor.quickfix_idx.is_none() && !editor.quickfix.is_empty() {
                editor.quickfix_idx = Some(0);
            }
        }
        QfKind::Location => {
            let view = view_mut!(editor);
            if append {
                view.loclist.extend(new_entries);
            } else {
                view.loclist = new_entries;
                view.loclist_idx = None;
            }
            if view.loclist_idx.is_none() && !view.loclist.is_empty() {
                view.loclist_idx = Some(0);
            }
        }
    }
    added
}

/// Open the file referenced by a quickfix entry and place the cursor there,
/// pushing the prior position onto the jumplist. Mirrors the inline jump used
/// by the global-search picker.
fn qf_jump_to(editor: &mut Editor, kind: QfKind, idx: usize, action: Action) {
    let entries = qf_entries(editor, kind);
    let Some(entry) = entries.get(idx).cloned() else {
        editor.set_error("quickfix list is empty");
        return;
    };
    qf_set_index(editor, kind, Some(idx));
    let id = match editor.open(&entry.path, action) {
        Ok(id) => id,
        Err(e) => {
            editor.set_error(format!("Failed to open '{}': {}", entry.path.display(), e));
            return;
        }
    };
    let scrolloff = editor.config().scrolloff;
    let doc = doc_mut!(editor, &id);
    let view = view_mut!(editor);
    let text = doc.text();
    if entry.line >= text.len_lines() {
        editor.set_error("the entry's line no longer exists (file changed)");
        return;
    }
    let line_start = text.line_to_char(entry.line);
    let line_len = text.line(entry.line).len_chars().saturating_sub(1);
    let pos = line_start + entry.col.min(line_len);
    push_jump(view, doc);
    doc.set_selection(view.id, Selection::point(pos));
    // vim quickfix jumps (`:cnext`/`:cc`/…) scroll minimally, not centered.
    view.ensure_cursor_in_view(doc, scrolloff);
}

/// `:cnext`/`:cprev` (and location twins): step the current index by `delta`
/// and jump. Reports vim's "no more items" at the boundary.
pub(crate) fn qf_step(editor: &mut Editor, kind: QfKind, delta: isize) {
    let len = qf_len(editor, kind);
    if len == 0 {
        editor.set_error("quickfix list is empty");
        return;
    }
    let cur = qf_index(editor, kind);
    let next = qf_advance_index(cur, len, delta);
    if next == cur
        && cur
            .map(|c| (delta > 0 && c + 1 >= len) || (delta < 0 && c == 0))
            .unwrap_or(false)
    {
        editor.set_status(if delta > 0 {
            "no more items"
        } else {
            "at top of list"
        });
    }
    if let Some(i) = next {
        qf_jump_to(editor, kind, i, Action::Replace);
    }
}

/// `:cnfile`/`:cpfile`: jump to the first entry of the next/previous file.
pub(crate) fn qf_step_file(editor: &mut Editor, kind: QfKind, forward: bool) {
    let entries = qf_entries(editor, kind);
    if entries.is_empty() {
        editor.set_error("quickfix list is empty");
        return;
    }
    let cur = qf_index(editor, kind).unwrap_or(0);
    let cur_path = entries.get(cur).map(|e| e.path.clone());
    let target = if forward {
        (cur + 1..entries.len()).find(|&i| Some(&entries[i].path) != cur_path.as_ref())
    } else {
        (0..cur)
            .rev()
            .find(|&i| Some(&entries[i].path) != cur_path.as_ref())
    };
    match target {
        Some(i) => qf_jump_to(editor, kind, i, Action::Replace),
        None => editor.set_status(if forward {
            "no more files"
        } else {
            "no previous files"
        }),
    }
}

/// `:cc [nr]`/`:ll [nr]`: jump to entry `nr` (1-based) or the current entry.
pub(crate) fn qf_jump_nth(editor: &mut Editor, kind: QfKind, nr: Option<usize>) {
    let len = qf_len(editor, kind);
    if len == 0 {
        editor.set_error("quickfix list is empty");
        return;
    }
    let idx = match nr {
        Some(n) if n >= 1 && n <= len => n - 1,
        Some(_) => {
            editor.set_error("entry number out of range");
            return;
        }
        None => qf_index(editor, kind).unwrap_or(0),
    };
    qf_jump_to(editor, kind, idx, Action::Replace);
}

/// The four cursor-relative quickfix motions (`:cabove`/`:cbelow`/`:cafter`/
/// `:cbefore` and their location-list twins).
#[derive(Clone, Copy)]
pub(crate) enum QfDir {
    Above,
    Below,
    After,
    Before,
}

/// True when a quickfix entry's stored path refers to the current buffer.
/// Entries may be relative (grep output) or absolute; match on the canonical
/// path when both resolve, else fall back to the raw path and the relative
/// path.
fn qf_entry_is_current(entry_path: &std::path::Path, doc_abs: Option<&std::path::Path>) -> bool {
    let Some(doc_abs) = doc_abs else {
        return false;
    };
    if entry_path == doc_abs {
        return true;
    }
    let entry_abs = if entry_path.is_absolute() {
        entry_path.to_path_buf()
    } else {
        std::env::current_dir().unwrap_or_default().join(entry_path)
    };
    match (
        std::fs::canonicalize(&entry_abs),
        std::fs::canonicalize(doc_abs),
    ) {
        (Ok(a), Ok(b)) => a == b,
        _ => entry_abs == doc_abs,
    }
}

/// `:cabove`/`:cbelow`/`:cafter`/`:cbefore` (and `:l…` twins): jump to the
/// entry relative to the current cursor position within the current buffer.
/// `count` selects the count-th stop in that direction (default 1). Delegates
/// the ordering rules to `zemacs_core::quickfix`.
pub(crate) fn qf_move_dir(editor: &mut Editor, kind: QfKind, dir: QfDir, count: usize) {
    use zemacs_core::quickfix::{self, Loc};

    // Read the current cursor position and buffer path.
    let (view, doc) = current_ref!(editor);
    let text = doc.text();
    let cursor_char = doc.selection(view.id).primary().cursor(text.slice(..));
    let cline = text.char_to_line(cursor_char);
    let ccol = cursor_char - text.line_to_char(cline);
    let doc_abs = doc.path().map(|p| p.to_path_buf());

    // Filter the active list to entries in the current buffer, preserving list
    // order, and remember each survivor's global index.
    let entries = qf_entries(editor, kind);
    let mut global: Vec<usize> = Vec::new();
    let mut locs: Vec<Loc> = Vec::new();
    for (i, e) in entries.iter().enumerate() {
        if qf_entry_is_current(&e.path, doc_abs.as_deref()) {
            global.push(i);
            locs.push(Loc::new(e.line, e.col));
        }
    }

    let cursor = Loc::new(cline, ccol);
    let hit = match dir {
        QfDir::Above => quickfix::above(&locs, cline, count),
        QfDir::Below => quickfix::below(&locs, cline, count),
        QfDir::After => quickfix::after(&locs, cursor, count),
        QfDir::Before => quickfix::before(&locs, cursor, count),
    };

    match hit {
        Some(local) => qf_jump_to(editor, kind, global[local], Action::Replace),
        None => editor.set_error("no more items"),
    }
}

/// Build the quickfix/location-list picker (the `:copen`/`:lopen` window).
pub(crate) fn build_qf_picker(editor: &mut Editor, kind: QfKind) -> Box<dyn Component> {
    let entries = qf_entries(editor, kind);
    let columns = [
        ui::PickerColumn::new("path", |item: &QfEntry, _| {
            zemacs_stdx::path::get_relative_path(item.path.clone())
                .to_string_lossy()
                .into_owned()
                .into()
        }),
        ui::PickerColumn::new("line", |item: &QfEntry, _| {
            (item.line + 1).to_string().into()
        }),
        ui::PickerColumn::new("text", |item: &QfEntry, _| item.text.as_str().into()),
    ];
    let picker = Picker::new(columns, 0, entries, (), move |cx, entry, action| {
        let kind = kind;
        // Locate this entry's index so navigation continues from here.
        let idx = qf_entries(cx.editor, kind)
            .iter()
            .position(|e| e == entry)
            .unwrap_or(0);
        qf_jump_to(cx.editor, kind, idx, action);
    })
    .with_preview(|_editor, entry: &QfEntry| {
        Some((entry.path.as_path().into(), Some((entry.line, entry.line))))
    });
    Box::new(overlaid(picker))
}

// --- Static (normal-mode-callable) quickfix commands ----------------------

fn quickfix_next(cx: &mut Context) {
    qf_step(cx.editor, QfKind::Quickfix, 1);
}
fn quickfix_prev(cx: &mut Context) {
    qf_step(cx.editor, QfKind::Quickfix, -1);
}
fn quickfix_first(cx: &mut Context) {
    qf_jump_nth(cx.editor, QfKind::Quickfix, Some(1));
}
fn quickfix_last(cx: &mut Context) {
    let len = qf_len(cx.editor, QfKind::Quickfix);
    qf_jump_nth(cx.editor, QfKind::Quickfix, (len > 0).then_some(len));
}
fn quickfix_open(cx: &mut Context) {
    let picker = build_qf_picker(cx.editor, QfKind::Quickfix);
    cx.push_layer(picker);
}

fn loclist_next(cx: &mut Context) {
    qf_step(cx.editor, QfKind::Location, 1);
}
fn loclist_prev(cx: &mut Context) {
    qf_step(cx.editor, QfKind::Location, -1);
}
fn loclist_first(cx: &mut Context) {
    qf_jump_nth(cx.editor, QfKind::Location, Some(1));
}
fn loclist_last(cx: &mut Context) {
    let len = qf_len(cx.editor, QfKind::Location);
    qf_jump_nth(cx.editor, QfKind::Location, (len > 0).then_some(len));
}
fn loclist_open(cx: &mut Context) {
    let picker = build_qf_picker(cx.editor, QfKind::Location);
    cx.push_layer(picker);
}

// --- Tabpage commands (vim `gt`/`gT`) -------------------------------------

/// Build the `:tabs` picker — one row per tabpage labelled by its focused
/// file, switching to the chosen tab on selection.
pub(crate) fn build_tabs_picker(editor: &mut Editor) -> Box<dyn Component> {
    struct TabItem {
        idx: usize,
        label: String,
        current: bool,
    }
    let current = editor.current_tab();
    let items: Vec<TabItem> = editor
        .tab_focused_docs()
        .into_iter()
        .enumerate()
        .map(|(idx, doc_id)| {
            let label = editor
                .documents
                .get(&doc_id)
                .and_then(|d| d.path())
                .map(|p| {
                    zemacs_stdx::path::get_relative_path(p.to_path_buf())
                        .to_string_lossy()
                        .into_owned()
                })
                .unwrap_or_else(|| "[scratch]".to_string());
            TabItem {
                idx,
                label,
                current: idx == current,
            }
        })
        .collect();
    let columns = [
        ui::PickerColumn::new("tab", |it: &TabItem, _| {
            format!("{}{}", it.idx + 1, if it.current { " *" } else { "" }).into()
        }),
        ui::PickerColumn::new("file", |it: &TabItem, _| it.label.as_str().into()),
    ];
    let picker = Picker::new(columns, 1, items, (), |cx, item, _action| {
        cx.editor.switch_tab(item.idx);
    });
    Box::new(overlaid(picker))
}

/// The tab that was active before the most recent switch, so `tab-recent` can
/// jump back to it. Updated by every tab-navigation command below.
static PREV_TAB: std::sync::atomic::AtomicUsize = std::sync::atomic::AtomicUsize::new(0);

fn record_prev_tab(editor: &Editor) {
    PREV_TAB.store(editor.current_tab(), std::sync::atomic::Ordering::Relaxed);
}

fn goto_next_tabpage(cx: &mut Context) {
    record_prev_tab(cx.editor);
    cx.editor.goto_next_tabpage();
}
fn goto_previous_tabpage(cx: &mut Context) {
    record_prev_tab(cx.editor);
    cx.editor.goto_previous_tabpage();
}
fn new_tab(cx: &mut Context) {
    cx.editor.new_tab();
}
fn close_tab(cx: &mut Context) {
    cx.editor.close_tab();
}
fn tab_only(cx: &mut Context) {
    cx.editor.tab_only();
}
fn goto_first_tabpage(cx: &mut Context) {
    record_prev_tab(cx.editor);
    cx.editor.switch_tab(0);
}
fn goto_last_tabpage(cx: &mut Context) {
    record_prev_tab(cx.editor);
    let n = cx.editor.tab_count();
    cx.editor.switch_tab(n.saturating_sub(1));
}

/// Emacs `tab-select`: switch to the `[count]`-th tab (1-based; default 1).
fn tab_select(cx: &mut Context) {
    let n = cx.count.map_or(1, |c| c.get());
    record_prev_tab(cx.editor);
    cx.editor.switch_tab(n.saturating_sub(1));
}

/// Emacs `tab-recent` (C-x t o): switch to the most recently visited tab.
fn tab_recent(cx: &mut Context) {
    let cur = cx.editor.current_tab();
    let prev = PREV_TAB
        .load(std::sync::atomic::Ordering::Relaxed)
        .min(cx.editor.tab_count().saturating_sub(1));
    cx.editor.switch_tab(prev);
    // Remember where we came from so repeated `tab-recent` toggles.
    PREV_TAB.store(cur, std::sync::atomic::Ordering::Relaxed);
}

/// Pin the current file to the project's harpoon list (jump to it later with
/// `harpoon_jump`/`SPC H 1..9` or the menu). Idempotent.
fn harpoon_add(cx: &mut Context) {
    let Some(path) = doc!(cx.editor).path().map(|p| p.to_path_buf()) else {
        cx.editor.set_error("Cannot pin a scratch buffer");
        return;
    };
    let slot = crate::harpoon::add(&path);
    let name = path
        .file_name()
        .map(|s| s.to_string_lossy().into_owned())
        .unwrap_or_default();
    cx.editor.set_status(format!("Harpoon {slot}: {name}"));
}

/// Open the harpoon mark at 1-based slot `n` (shared by the count + slot commands).
fn harpoon_open_slot(cx: &mut Context, n: usize) {
    match crate::harpoon::get(n) {
        Some(path) => {
            if let Err(e) = cx.editor.open(&path, Action::Replace) {
                cx.editor
                    .set_error(format!("unable to open \"{}\": {e}", path.display()));
            }
        }
        None => cx.editor.set_status(format!("No harpoon mark in slot {n}")),
    }
}

/// Jump to the harpoon mark at 1-based slot `cx.count` (default 1).
fn harpoon_jump(cx: &mut Context) {
    let n = cx.count.map(|c| c.get()).unwrap_or(1);
    harpoon_open_slot(cx, n);
}

fn harpoon_1(cx: &mut Context) {
    harpoon_open_slot(cx, 1);
}
fn harpoon_2(cx: &mut Context) {
    harpoon_open_slot(cx, 2);
}
fn harpoon_3(cx: &mut Context) {
    harpoon_open_slot(cx, 3);
}
fn harpoon_4(cx: &mut Context) {
    harpoon_open_slot(cx, 4);
}

/// Open the next / previous harpoon mark relative to the current file (wrapping).
/// If the current file isn't pinned, jumps to the first mark.
fn harpoon_cycle(cx: &mut Context, forward: bool) {
    let marks = crate::harpoon::list();
    if marks.is_empty() {
        cx.editor.set_status("No harpoon marks yet");
        return;
    }
    let cur = doc!(cx.editor).path().and_then(|p| {
        let cp = std::fs::canonicalize(p).unwrap_or_else(|_| p.to_path_buf());
        marks.iter().position(|m| *m == cp)
    });
    let len = marks.len();
    let idx = match cur {
        Some(i) if forward => (i + 1) % len,
        Some(i) => (i + len - 1) % len,
        None => 0,
    };
    let path = marks[idx].clone();
    if let Err(e) = cx.editor.open(&path, Action::Replace) {
        cx.editor
            .set_error(format!("unable to open \"{}\": {e}", path.display()));
    }
}

/// Open the next harpoon mark (wraps).
fn harpoon_next(cx: &mut Context) {
    harpoon_cycle(cx, true);
}

/// Open the previous harpoon mark (wraps).
fn harpoon_prev(cx: &mut Context) {
    harpoon_cycle(cx, false);
}

/// Line-level bookmarks (JetBrains Bookmarks): an ordered global list of `(file, line)`, distinct
/// from the file-level harpoon pins. Line numbers are captured at toggle time.
static BOOKMARKS: std::sync::Mutex<Vec<(std::path::PathBuf, usize)>> =
    std::sync::Mutex::new(Vec::new());

/// The current `(file, 0-based line)` under the cursor, if the buffer has a path.
fn current_file_line(cx: &Context) -> Option<(std::path::PathBuf, usize)> {
    let (view, doc) = current_ref!(cx.editor);
    let path = doc.path()?.to_path_buf();
    let text = doc.text();
    let line = text.char_to_line(doc.selection(view.id).primary().cursor(text.slice(..)));
    Some((path, line))
}

/// JetBrains "Toggle Bookmark" (F11): add or remove a bookmark on the current line.
fn bookmark_toggle(cx: &mut Context) {
    let Some((path, line)) = current_file_line(cx) else {
        cx.editor.set_error("Cannot bookmark a scratch buffer");
        return;
    };
    let mut marks = BOOKMARKS.lock().unwrap();
    if let Some(pos) = marks.iter().position(|(p, l)| *p == path && *l == line) {
        marks.remove(pos);
        cx.editor.set_status(format!(
            "Bookmark removed ({}:{})",
            path.display(),
            line + 1
        ));
    } else {
        marks.push((path.clone(), line));
        marks.sort();
        cx.editor
            .set_status(format!("Bookmark set ({}:{})", path.display(), line + 1));
    }
}

/// Jump to the next/previous bookmark across all files (wrapping), relative to the cursor.
fn bookmark_cycle(cx: &mut Context, forward: bool) {
    let marks = BOOKMARKS.lock().unwrap().clone();
    if marks.is_empty() {
        cx.editor
            .set_status("No bookmarks set (toggle with bookmark_toggle)");
        return;
    }
    let cur = current_file_line(cx);
    let target = match &cur {
        Some(c) if forward => marks.iter().find(|m| *m > c).or_else(|| marks.first()),
        Some(c) => marks.iter().rev().find(|m| *m < c).or_else(|| marks.last()),
        None => marks.first(),
    }
    .cloned();
    let Some((path, line)) = target else {
        return;
    };
    if let Err(e) = cx.editor.open(&path, Action::Replace) {
        cx.editor
            .set_error(format!("unable to open \"{}\": {e}", path.display()));
        return;
    }
    let (view, doc) = current!(cx.editor);
    push_jump(view, doc);
    let line = line.min(doc.text().len_lines().saturating_sub(1));
    let pos = doc.text().line_to_char(line);
    doc.set_selection(view.id, Selection::point(pos));
}

/// JetBrains "Next Bookmark": jump to the next line bookmark (wraps).
fn bookmark_next(cx: &mut Context) {
    bookmark_cycle(cx, true);
}

/// JetBrains "Previous Bookmark": jump to the previous line bookmark (wraps).
fn bookmark_prev(cx: &mut Context) {
    bookmark_cycle(cx, false);
}

/// Fuzzy menu of the project's harpoon marks; Enter opens, and the order is the
/// pin order (slot 1 at the top).
fn harpoon_menu(cx: &mut Context) {
    let marks = crate::harpoon::list();
    if marks.is_empty() {
        cx.editor
            .set_status("No harpoon marks yet — pin one with harpoon_add");
        return;
    }
    let cwd = zemacs_stdx::env::current_working_dir();
    // pair each mark with its 1-based slot so the picker shows the `SPC H N` mapping
    let items: Vec<(usize, PathBuf)> = marks
        .into_iter()
        .enumerate()
        .map(|(i, p)| (i + 1, p))
        .collect();
    let columns = [
        PickerColumn::new("#", |item: &(usize, PathBuf), _: &PathBuf| {
            item.0.to_string().into()
        }),
        PickerColumn::new("pinned file", |item: &(usize, PathBuf), cwd: &PathBuf| {
            item.1
                .strip_prefix(cwd)
                .unwrap_or(&item.1)
                .display()
                .to_string()
                .into()
        }),
    ];
    let picker = Picker::new(
        columns,
        1,
        items,
        cwd,
        |cx, item: &(usize, PathBuf), action| {
            if let Err(e) = cx.editor.open(&item.1, action) {
                cx.editor
                    .set_error(format!("unable to open \"{}\": {e}", item.1.display()));
            }
        },
    )
    .with_preview(|_editor, item| Some((item.1.as_path().into(), None)));
    cx.push_layer(Box::new(overlaid(picker)));
}

/// Remove the current file from the project's harpoon list.
fn harpoon_remove(cx: &mut Context) {
    let Some(path) = doc!(cx.editor).path().map(|p| p.to_path_buf()) else {
        return;
    };
    crate::harpoon::remove(&path);
    cx.editor.set_status("Unpinned from harpoon");
}

/// Pick a local git branch and check it out (magit `b`), reloading open buffers.
pub(crate) fn git_branch_picker(cx: &mut Context) {
    let dir = std::env::current_dir().unwrap_or_default();
    let branches: Vec<String> = std::process::Command::new("git")
        .arg("-C")
        .arg(&dir)
        .args(["for-each-ref", "--format=%(refname:short)", "refs/heads/"])
        .output()
        .ok()
        .filter(|o| o.status.success())
        .map(|o| {
            String::from_utf8_lossy(&o.stdout)
                .lines()
                .map(|s| s.trim().to_owned())
                .filter(|s| !s.is_empty())
                .collect()
        })
        .unwrap_or_default();
    if branches.is_empty() {
        cx.editor.set_status("No git branches");
        return;
    }
    let columns = [PickerColumn::new("branch", |b: &String, _: &()| {
        b.as_str().into()
    })];
    let picker = Picker::new(columns, 0, branches, (), |cx, branch: &String, _action| {
        let dir = std::env::current_dir().unwrap_or_default();
        match std::process::Command::new("git")
            .arg("-C")
            .arg(&dir)
            .args(["checkout", branch])
            .output()
        {
            Ok(o) if o.status.success() => {
                crate::commands::typed::reload_open_docs(cx);
                cx.editor.set_status(format!("Switched to branch {branch}"));
            }
            Ok(o) => cx.editor.set_error(
                String::from_utf8_lossy(&o.stderr)
                    .lines()
                    .next()
                    .unwrap_or("checkout failed")
                    .trim()
                    .to_owned(),
            ),
            Err(e) => cx.editor.set_error(format!("git: {e}")),
        }
    });
    cx.push_layer(Box::new(overlaid(picker)));
}

/// Reopen the most-recently-closed file (the IDE `Ctrl-Shift-T` gesture).
/// Repeated calls walk back through the session's close history.
fn reopen_last_closed(cx: &mut Context) {
    match crate::closed_files::pop() {
        Some(path) => {
            if let Err(e) = cx.editor.open(&path, Action::Replace) {
                cx.editor
                    .set_error(format!("unable to reopen \"{}\": {e}", path.display()));
            }
        }
        None => cx.editor.set_status("No recently closed file to reopen"),
    }
}

/// Fuzzy-pick a previously opened file, ranked by `z`-style frecency
/// (frequency × recency). Persisted across sessions in `<config>/recent_files`.
fn frecent_file_picker(cx: &mut Context) {
    match build_frecent_file_picker() {
        Some(picker) => cx.push_layer(picker),
        None => cx.editor.set_status("No recent files yet"),
    }
}

/// Build the recent-files picker (shared by the static command and `:oldfiles`). Returns `None`
/// when there are no recent files yet.
pub(crate) fn build_frecent_file_picker() -> Option<Box<dyn Component>> {
    let files = crate::recent_files::load_frecent();
    if files.is_empty() {
        return None;
    }
    let cwd = zemacs_stdx::env::current_working_dir();
    let columns = [PickerColumn::new("file", |p: &PathBuf, cwd: &PathBuf| {
        p.strip_prefix(cwd)
            .unwrap_or(p)
            .display()
            .to_string()
            .into()
    })];
    let picker = Picker::new(columns, 0, files, cwd, |cx, path: &PathBuf, action| {
        if let Err(e) = cx.editor.open(path, action) {
            cx.editor
                .set_error(format!("unable to open \"{}\": {e}", path.display()));
        }
    })
    .with_preview(|_editor, path| Some((path.as_path().into(), None)));
    Some(Box::new(overlaid(picker)))
}

fn changed_file_picker(cx: &mut Context) {
    pub struct FileChangeData {
        cwd: PathBuf,
        style_untracked: Style,
        style_modified: Style,
        style_conflict: Style,
        style_deleted: Style,
        style_renamed: Style,
    }

    let cwd = zemacs_stdx::env::current_working_dir();
    if !cwd.exists() {
        cx.editor
            .set_error("Current working directory does not exist");
        return;
    }

    let added = cx.editor.theme.get("diff.plus");
    let modified = cx.editor.theme.get("diff.delta");
    let conflict = cx.editor.theme.get("diff.delta.conflict");
    let deleted = cx.editor.theme.get("diff.minus");
    let renamed = cx.editor.theme.get("diff.delta.moved");

    let columns = [
        PickerColumn::new("change", |change: &FileChange, data: &FileChangeData| {
            match change {
                FileChange::Untracked { .. } => Span::styled("+ untracked", data.style_untracked),
                FileChange::Modified { .. } => Span::styled("~ modified", data.style_modified),
                FileChange::Conflict { .. } => Span::styled("x conflict", data.style_conflict),
                FileChange::Deleted { .. } => Span::styled("- deleted", data.style_deleted),
                FileChange::Renamed { .. } => Span::styled("> renamed", data.style_renamed),
            }
            .into()
        }),
        PickerColumn::new("path", |change: &FileChange, data: &FileChangeData| {
            let display_path = |path: &PathBuf| {
                path.strip_prefix(&data.cwd)
                    .unwrap_or(path)
                    .display()
                    .to_string()
            };
            match change {
                FileChange::Untracked { path } => display_path(path),
                FileChange::Modified { path } => display_path(path),
                FileChange::Conflict { path } => display_path(path),
                FileChange::Deleted { path } => display_path(path),
                FileChange::Renamed { from_path, to_path } => {
                    format!("{} -> {}", display_path(from_path), display_path(to_path))
                }
            }
            .into()
        }),
    ];

    let picker = Picker::new(
        columns,
        1, // path
        [],
        FileChangeData {
            cwd: cwd.clone(),
            style_untracked: added,
            style_modified: modified,
            style_conflict: conflict,
            style_deleted: deleted,
            style_renamed: renamed,
        },
        |cx, meta: &FileChange, action| {
            let path_to_open = meta.path();
            if let Err(e) = cx.editor.open(path_to_open, action) {
                let err = if let Some(err) = e.source() {
                    format!("{}", err)
                } else {
                    format!("unable to open \"{}\"", path_to_open.display())
                };
                cx.editor.set_error(err);
            }
        },
    )
    .with_preview(|_editor, meta| Some((meta.path().into(), None)));
    let injector = picker.injector();

    let trust_full = cx
        .editor
        .workspace_trust
        .query(
            &zemacs_loader::find_workspace_in(&cwd).0,
            zemacs_loader::workspace_trust::TrustQuery::Git,
        )
        .is_trusted();
    cx.editor
        .diff_providers
        .clone()
        .for_each_changed_file(cwd, trust_full, move |change| match change {
            Ok(change) => injector.push(change).is_ok(),
            Err(err) => {
                status::report_blocking(err);
                true
            }
        });
    cx.push_layer(Box::new(overlaid(picker)));
}

/// JetBrains "Search Everywhere": one entry point that chooses among the
/// pickers — Files, Symbols, Text (find in path), Actions, Open Buffers. Opens a
/// small chooser; each choice launches the matching picker (reusing the existing
/// commands, whose deferred `push_layer` callbacks are dispatched here).
fn search_everywhere(cx: &mut Context) {
    use crate::ui::context_menu::{ContextMenu, Entry};

    // Run a picker command from a menu-entry callback: build a Context, execute
    // the command, then dispatch the layer-push callbacks it queued.
    fn run(compositor: &mut Compositor, cx: &mut compositor::Context, cmd: fn(&mut Context)) {
        let cbs = {
            let mut c = Context {
                editor: cx.editor,
                register: None,
                count: None,
                callback: Vec::new(),
                on_next_key_callback: None,
                jobs: cx.jobs,
            };
            cmd(&mut c);
            std::mem::take(&mut c.callback)
        };
        for cb in cbs {
            cb(compositor, cx);
        }
    }

    let entries = vec![
        Entry::item("Files", |co, cx| run(co, cx, file_picker)),
        Entry::item("Symbols", |co, cx| run(co, cx, workspace_symbol_picker)),
        Entry::item("Text in Path", |co, cx| run(co, cx, global_search)),
        Entry::item("Actions", |co, cx| run(co, cx, command_palette)),
        Entry::item("Open Buffers", |co, cx| run(co, cx, buffer_picker)),
    ];
    cx.callback.push(Box::new(
        move |compositor: &mut Compositor, _cx: &mut compositor::Context| {
            let size = compositor.size();
            let col = size.width.saturating_sub(24) / 2;
            compositor.push(Box::new(ContextMenu::new(2, col, entries)));
        },
    ));
}

/// JetBrains "Recent Files" switcher (SPC b r): a two-pane popup with tool-window
/// shortcuts on the left and the recent-files list on the right.
fn recent_files_switcher(cx: &mut Context) {
    let all = crate::recent_files::load();
    let open: Vec<std::path::PathBuf> = cx
        .editor
        .documents()
        .filter_map(|d| d.path().map(|p| p.to_path_buf()))
        .collect();
    let root = zemacs_loader::find_workspace().0;
    cx.callback.push(Box::new(
        move |compositor: &mut Compositor, _cx: &mut compositor::Context| {
            compositor.push(Box::new(crate::ui::switcher::RecentFilesSwitcher::new(
                all, open, root,
            )));
        },
    ));
}

pub fn command_palette(cx: &mut Context) {
    let register = cx.register;
    let count = cx.count;

    cx.callback.push(Box::new(
        move |compositor: &mut Compositor, cx: &mut compositor::Context| {
            let keymap = compositor.find::<ui::EditorView>().unwrap().keymaps.map()
                [&cx.editor.mode]
                .reverse_map();

            let commands = MappableCommand::STATIC_COMMAND_LIST.iter().cloned().chain(
                typed::TYPABLE_COMMAND_LIST
                    .iter()
                    .map(|cmd| MappableCommand::Typable {
                        name: cmd.name.to_owned(),
                        args: String::new(),
                        doc: cmd.doc.to_owned(),
                    }),
            );

            let columns = [
                ui::PickerColumn::new("name", |item, _| match item {
                    MappableCommand::Typable { name, .. } => format!(":{name}").into(),
                    MappableCommand::Static { name, .. } => (*name).into(),
                    MappableCommand::Macro { .. } => {
                        unreachable!("macros aren't included in the command palette")
                    }
                }),
                ui::PickerColumn::new(
                    "bindings",
                    |item: &MappableCommand, keymap: &crate::keymap::ReverseKeymap| {
                        keymap
                            .get(item.name())
                            .map(|bindings| {
                                bindings.iter().fold(String::new(), |mut acc, bind| {
                                    if !acc.is_empty() {
                                        acc.push(' ');
                                    }
                                    for key in bind {
                                        acc.push_str(&key.key_sequence_format());
                                    }
                                    acc
                                })
                            })
                            .unwrap_or_default()
                            .into()
                    },
                ),
                ui::PickerColumn::new("doc", |item: &MappableCommand, _| item.doc().into()),
            ];

            let picker = Picker::new(columns, 0, commands, keymap, move |cx, command, _action| {
                let mut ctx = Context {
                    register,
                    count,
                    editor: cx.editor,
                    callback: Vec::new(),
                    on_next_key_callback: None,
                    jobs: cx.jobs,
                };
                let focus = view!(ctx.editor).id;

                command.execute(&mut ctx);

                if ctx.editor.tree.contains(focus) {
                    let config = ctx.editor.config();
                    let mode = ctx.editor.mode();
                    let view = view_mut!(ctx.editor, focus);
                    let doc = doc_mut!(ctx.editor, &view.doc);

                    view.ensure_cursor_in_view(doc, config.scrolloff);

                    if mode != Mode::Insert {
                        doc.append_changes_to_history(view);
                    }
                }
            });
            compositor.push(Box::new(overlaid(picker)));
        },
    ));
}

// ── Help system (C-h ...): real describe-* functions, Emacs-style ────────────
// Each renders a report into a scratch buffer (the zemacs `*Help*`), so nothing
// is a fake duplicate: describe-command shows docs, where-is shows bindings,
// describe-bindings lists the whole keymap, etc.

/// Format the key bindings a command has, from a reverse keymap.
fn help_fmt_bindings(km: &crate::keymap::ReverseKeymap, name: &str) -> String {
    km.get(name)
        .map(|binds| {
            binds
                .iter()
                .map(|b| {
                    b.iter()
                        .map(|k| k.key_sequence_format())
                        .collect::<String>()
                })
                .collect::<Vec<_>>()
                .join("   ")
        })
        .filter(|s| !s.is_empty())
        .unwrap_or_else(|| "(unbound)".to_string())
}

fn help_report_full(c: &MappableCommand, km: &crate::keymap::ReverseKeymap) -> String {
    let kind = if matches!(c, MappableCommand::Typable { .. }) {
        "typable (:) command"
    } else {
        "command"
    };
    format!(
        "{}  —  {kind}\n\nBound to: {}\n\n{}\n",
        c.name(),
        help_fmt_bindings(km, c.name()),
        c.doc()
    )
}

fn help_report_bindings(c: &MappableCommand, km: &crate::keymap::ReverseKeymap) -> String {
    format!(
        "{} is bound to:\n\n  {}\n",
        c.name(),
        help_fmt_bindings(km, c.name())
    )
}

/// Shared command picker used by describe-command / where-is / describe-key.
/// `bound_only` limits to commands that have a key binding; `primary` is the
/// searched column (0 = name, 1 = bindings); on select it renders `report` into
/// a scratch `*Help*` buffer instead of executing the command.
fn help_command_picker(
    cx: &mut Context,
    bound_only: bool,
    primary: usize,
    report: fn(&MappableCommand, &crate::keymap::ReverseKeymap) -> String,
) {
    cx.callback.push(Box::new(move |compositor, cx| {
        let rmap = compositor.find::<ui::EditorView>().unwrap().keymaps.map()[&cx.editor.mode]
            .reverse_map();
        let commands: Vec<MappableCommand> = MappableCommand::STATIC_COMMAND_LIST
            .iter()
            .cloned()
            .chain(
                typed::TYPABLE_COMMAND_LIST
                    .iter()
                    .map(|cmd| MappableCommand::Typable {
                        name: cmd.name.to_owned(),
                        args: String::new(),
                        doc: cmd.doc.to_owned(),
                    }),
            )
            .filter(|c| !bound_only || rmap.contains_key(c.name()))
            .collect();
        let columns = [
            ui::PickerColumn::new(
                "name",
                |item: &MappableCommand, _: &crate::keymap::ReverseKeymap| match item {
                    MappableCommand::Typable { name, .. } => format!(":{name}").into(),
                    _ => item.name().into(),
                },
            ),
            ui::PickerColumn::new(
                "bindings",
                |item: &MappableCommand, km: &crate::keymap::ReverseKeymap| {
                    help_fmt_bindings(km, item.name()).into()
                },
            ),
            ui::PickerColumn::new(
                "doc",
                |item: &MappableCommand, _: &crate::keymap::ReverseKeymap| item.doc().into(),
            ),
        ];
        let rmap_select = rmap.clone();
        let picker = Picker::new(
            columns,
            primary,
            commands,
            rmap,
            move |cx, command, _action| {
                let text = report(command, &rmap_select);
                show_text_in_scratch(cx.editor, &text);
            },
        );
        compositor.push(Box::new(overlaid(picker)));
    }));
}

/// C-h f / C-h x / C-h a: describe / apropos a command — its doc + bindings.
fn describe_command(cx: &mut Context) {
    help_command_picker(cx, false, 0, help_report_full);
}

/// C-h w: where-is — pick a command, show the keys bound to it.
fn where_is(cx: &mut Context) {
    help_command_picker(cx, false, 0, help_report_bindings);
}

/// C-h k: describe-key — search bindings by key, show the command + its doc.
fn describe_key(cx: &mut Context) {
    help_command_picker(cx, true, 1, help_report_full);
}

/// C-h b: describe-bindings — list every key binding of the current mode.
fn describe_bindings(cx: &mut Context) {
    cx.callback.push(Box::new(|compositor, cx| {
        let rmap = compositor.find::<ui::EditorView>().unwrap().keymaps.map()[&cx.editor.mode]
            .reverse_map();
        let mut rows: Vec<(String, String)> = rmap
            .iter()
            .flat_map(|(name, binds)| {
                let name = name.clone();
                binds.iter().map(move |b| {
                    (
                        b.iter()
                            .map(|k| k.key_sequence_format())
                            .collect::<String>(),
                        name.clone(),
                    )
                })
            })
            .collect();
        rows.sort();
        let mut out = format!("Key bindings — {:?} mode\n\n", cx.editor.mode);
        for (keys, name) in rows {
            out.push_str(&format!("{keys:<18} {name}\n"));
        }
        show_text_in_scratch(cx.editor, &out);
    }));
}

/// C-h C: describe-coding-system — the buffer's encoding and line ending.
fn describe_coding_system(cx: &mut Context) {
    let report = {
        let doc = doc!(cx.editor);
        format!(
            "Coding system — {}\n\nencoding: {}\nline ending: {:?}\n",
            doc.display_name(),
            doc.encoding().name(),
            doc.line_ending
        )
    };
    show_text_in_scratch(cx.editor, &report);
}

/// C-h L: describe-language-environment — language + locale.
fn describe_language_environment(cx: &mut Context) {
    let report = {
        let doc = doc!(cx.editor);
        format!(
            "Language environment\n\nlanguage: {}\nencoding: {}\nLANG: {}\nLC_ALL: {}\nLC_CTYPE: {}\n",
            doc.language_name().unwrap_or("(none)"),
            doc.encoding().name(),
            std::env::var("LANG").unwrap_or_default(),
            std::env::var("LC_ALL").unwrap_or_default(),
            std::env::var("LC_CTYPE").unwrap_or_default(),
        )
    };
    show_text_in_scratch(cx.editor, &report);
}

/// C-h s: describe-syntax — the buffer's language + tree-sitter status.
fn describe_syntax(cx: &mut Context) {
    let report = {
        let doc = doc!(cx.editor);
        format!(
            "Syntax\n\nlanguage: {}\ntree-sitter: {}\n",
            doc.language_name().unwrap_or("fundamental (none)"),
            if doc.syntax().is_some() {
                "active"
            } else {
                "not available for this buffer"
            }
        )
    };
    show_text_in_scratch(cx.editor, &report);
}

/// C-h l: view-lossage — the recently pressed keys.
fn view_lossage(cx: &mut Context) {
    cx.callback.push(Box::new(|compositor, cx| {
        let ev = compositor.find::<ui::EditorView>().unwrap();
        let keys: String = ev
            .recent_keys
            .iter()
            .map(|k| k.key_sequence_format())
            .collect::<Vec<_>>()
            .join(" ");
        show_text_in_scratch(cx.editor, &format!("Recent keys (lossage)\n\n{keys}\n"));
    }));
}

/// C-u C-x =: describe-char — the character after point in full: its glyph and
/// key description, decimal/octal/hex code, U+ codepoint, Unicode general category
/// and block, and its buffer position. Fuller than `what-cursor-position`; the
/// report string is built (and unit tested) in `zemacs_core::cursor_info`.
#[allow(deprecated)] // mirrors `what_cursor_position`'s column computation
fn describe_char(cx: &mut Context) {
    use zemacs_core::visual_coords_at_pos;
    let (view, doc) = current_ref!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let total = text.len_chars();
    let cursor = doc.selection(view.id).primary().cursor(slice);
    let point = cursor + 1;
    let column = visual_coords_at_pos(slice, cursor, doc.tab_width()).col;
    let char_at_point = (cursor < total).then(|| text.char(cursor));
    let report = zemacs_core::cursor_info::describe_char(char_at_point, point, total, column);
    show_text_in_scratch(cx.editor, &format!("{report}\n"));
}

/// C-h h: view-hello-file — a short multi-script sample so you can confirm your
/// fonts render the world's scripts. A bundled static string (zemacs has no
/// installed etc/HELLO file); the greetings and their scripts match GNU Emacs's.
const HELLO_FILE: &str = "\
This is a list of ways to say hello in various languages.  If your
font and terminal support the script, each greeting should render.

Arabic (العربية)\tالسّلام عليكم\nBengali (বাংলা)\tনমস্কার\nChinese (中文,普通话,汉语)\t你好\nEnglish (English)\tHello\nEsperanto\tSaluton\nFrench (Français)\tBonjour, Salut\nGeorgian (ქართული)\tგამარჯობა\nGerman (Deutsch)\tGuten Tag\nGreek (Ελληνικά)\tΓειά σας\nHebrew (עברית)\tשלום\nHindi (हिन्दी)\tनमस्ते, नमस्कार\nJapanese (日本語)\tこんにちは, ｺﾝﾆﾁﾊ\nKorean (한국어)\t안녕하세요, 안녕하십니까\nRussian (Русский)\tЗдравствуйте!\nSpanish (Español)\t¡Hola!\nThai (ภาษาไทย)\tสวัสดีครับ, สวัสดีค่ะ\nVietnamese (Tiếng Việt)\tChào bạn\n\nEmoji\t😀 👋 🌍 🎉 λ ∑ → ★\n";

fn view_hello_file(cx: &mut Context) {
    show_text_in_scratch(cx.editor, HELLO_FILE);
    cx.editor.set_status("HELLO — multi-script greeting sample");
}

/// Open a GNU documentation URL in the OS browser (the terminal analogue of the
/// Emacs `view-emacs-*` / `describe-gnu-project` commands, which pop the info /
/// browser). Reports what it opened, or the failure.
fn open_gnu_doc(cx: &mut Context, label: &str, url: &str) {
    match open_in_browser(url) {
        Ok(()) => cx.editor.set_status(format!("Opening {label}: {url}")),
        Err(e) => cx.editor.set_error(format!("failed to open browser: {e}")),
    }
}

