/// C-h e: view-echo-area-messages — show the last echo-area message. zemacs keeps
/// only the current status line, not a persistent *Messages* ring, so this is a
/// reduced view (there is a separate `view-lossage` for the recent key history).
fn view_echo_area_messages(cx: &mut Context) {
    let msg = cx
        .editor
        .get_status()
        .map(|(s, _)| s.to_string())
        .unwrap_or_default();
    let body = if msg.is_empty() {
        "*Messages*\n\n(no message in the echo area)\n\nzemacs shows only the current \
         echo-area message, not a persistent message log.\nUse view-lossage (C-h l) for the \
         recent key history."
            .to_string()
    } else {
        format!(
            "*Messages*\n\n{msg}\n\n(zemacs keeps only the current echo-area message, \
             not a persistent log.)"
        )
    };
    show_text_in_scratch(cx.editor, &body);
}

/// Render the current mode's whole keymap as sorted "chord  command" lines.
fn dump_mode_keymap(compositor: &mut Compositor, cx: &mut compositor::Context, header: &str) {
    let rmap =
        compositor.find::<ui::EditorView>().unwrap().keymaps.map()[&cx.editor.mode].reverse_map();
    let mut rows: Vec<(String, String)> = rmap
        .iter()
        .flat_map(|(name, binds)| {
            let name = name.clone();
            binds.iter().map(move |b| {
                (
                    b.iter()
                        .map(|k| k.key_sequence_format())
                        .collect::<String>(),
                    name.clone(),
                )
            })
        })
        .collect();
    rows.sort();
    let mut out = format!("{header}\n\n");
    for (keys, name) in rows {
        out.push_str(&format!("{keys:<18} {name}\n"));
    }
    show_text_in_scratch(cx.editor, &out);
}

/// describe-keymap — list every binding of a keymap. zemacs keymaps are per-mode
/// (Normal/Select/Insert), not named Emacs keymap variables, so this describes the
/// current mode's keymap in full.
fn describe_keymap(cx: &mut Context) {
    cx.callback.push(Box::new(|compositor, cx| {
        let header = format!("Keymap — {:?} mode", cx.editor.mode);
        dump_mode_keymap(compositor, cx, &header);
    }));
}

/// `C-x <help>`: describe-prefix-bindings — list the sub-bindings of a prefix. zemacs
/// does not track the pending prefix from within a command, so this lists the
/// current mode's full keymap (grouped by leading chord) for you to scan.
fn describe_prefix_bindings(cx: &mut Context) {
    cx.callback.push(Box::new(|compositor, cx| {
        let header = format!(
            "Prefix bindings — {:?} mode (full keymap; scan by leading key)",
            cx.editor.mode
        );
        dump_mode_keymap(compositor, cx, &header);
    }));
}

/// describe-categories — the character categories zemacs recognises. Emacs has a
/// per-buffer category table with dozens of syntax categories; zemacs classifies a
/// char into a small fixed set (see `zemacs_core::chars::categorize_char`), so this
/// is a reduced listing of that set.
fn describe_categories(cx: &mut Context) {
    let body = "Character categories (zemacs)\n\n\
        zemacs classifies each character into one of these categories\n\
        (zemacs_core::chars::CharCategory) rather than Emacs's full,\n\
        per-buffer syntax-category table:\n\n\
        \tWord\t\tletters, digits and _  (\\w)\n\
        \tPunctuation\tpunctuation, math, currency and modifier symbols\n\
        \tWhitespace\tspaces and other non-breaking blanks\n\
        \tEol\t\tline-ending characters\n\
        \tUnknown\t\tanything not in the above\n\n\
        The Unicode general-category of the character at point is shown by\n\
        describe-char (C-u C-x =).\n";
    show_text_in_scratch(cx.editor, body);
}

/// list-character-sets — the character "sets" zemacs can name. zemacs is a UTF-8
/// editor with no legacy charset registry, so instead of Emacs's charset list this
/// lists the Unicode blocks it knows, with their codepoint ranges.
fn list_character_sets(cx: &mut Context) {
    let mut out =
        String::from("Unicode blocks (zemacs is UTF-8; it has no legacy charset registry)\n\n");
    out.push_str(&format!("{:<12} {:<12} {}\n", "Start", "End", "Block"));
    for &(start, end, name) in zemacs_core::chars::unicode_blocks() {
        out.push_str(&format!("U+{start:04X}       U+{end:04X}       {name}\n"));
    }
    show_text_in_scratch(cx.editor, &out);
}

/// list-charset-chars — the characters of a "charset". zemacs lists the printable
/// characters of each named Unicode block it knows (a reduced analogue of Emacs's
/// per-charset listing).
fn list_charset_chars(cx: &mut Context) {
    let mut out = String::from("Characters by Unicode block (printable subset)\n\n");
    for &(start, end, name) in zemacs_core::chars::unicode_blocks() {
        // Cap each block so the buffer stays readable.
        let span = (end - start + 1).min(256);
        out.push_str(&format!("\n== {name} (U+{start:04X}..U+{end:04X}) ==\n"));
        let mut shown = 0;
        for cp in start..start + span {
            if let Some(ch) = char::from_u32(cp) {
                if ch.is_control() || !zemacs_core::chars::unicode_block(ch).eq(name) {
                    continue;
                }
                out.push_str(&format!("U+{cp:04X} {ch}   "));
                shown += 1;
                if shown % 8 == 0 {
                    out.push('\n');
                }
            }
        }
        if shown % 8 != 0 {
            out.push('\n');
        }
    }
    show_text_in_scratch(cx.editor, &out);
}

/// list-coding-systems — the coding systems zemacs supports. zemacs decodes via
/// encoding_rs (a wide set of encodings) and writes one of a fixed set of line
/// endings; Emacs's coding-system model (with EOL and newline conversions per
/// system) is richer, so this is a truthful listing of what zemacs actually offers.
fn list_coding_systems(cx: &mut Context) {
    let encodings = [
        "UTF-8",
        "UTF-16LE",
        "UTF-16BE",
        "windows-1252 (Latin-1 superset)",
        "ISO-8859-2..15",
        "windows-1250/1251/1253..1258",
        "Shift_JIS",
        "EUC-JP",
        "ISO-2022-JP",
        "GBK / GB18030",
        "Big5",
        "EUC-KR",
        "KOI8-R / KOI8-U",
        "IBM866",
        "macintosh",
    ];
    let mut out = String::from(
        "Coding systems (zemacs decodes via encoding_rs; default is UTF-8)\n\n\
         Encodings:\n",
    );
    for e in encodings {
        out.push_str(&format!("  {e}\n"));
    }
    out.push_str(
        "\nLine endings (end-of-line conversion):\n  \
         LF   (\\n, Unix)\n  CRLF (\\r\\n, DOS/Windows)\n  CR   (\\r, classic Mac)\n\n\
         Set the buffer's line ending with :set-line-ending; the encoding is detected \
         on load.\n",
    );
    show_text_in_scratch(cx.editor, &out);
}

fn last_picker(cx: &mut Context) {
    // TODO: last picker does not seem to work well with buffer_picker
    cx.callback.push(Box::new(|compositor, cx| {
        if let Some(picker) = compositor.last_picker.take() {
            compositor.push(picker);
        } else {
            cx.editor.set_error("no last picker")
        }
    }));
}

/// Fallback position to use for [`insert_with_indent`].
enum IndentFallbackPos {
    LineStart,
    LineEnd,
}

// `I` inserts at the first nonwhitespace character of each line with a selection.
// If the line is empty, automatically indent.
fn insert_at_line_start(cx: &mut Context) {
    insert_with_indent(cx, IndentFallbackPos::LineStart);
}

// `A` inserts at the end of each line with a selection.
// If the line is empty, automatically indent.
fn insert_at_line_end(cx: &mut Context) {
    insert_with_indent(cx, IndentFallbackPos::LineEnd);
}

// Enter insert mode and auto-indent the current line if it is empty.
// If the line is not empty, move the cursor to the specified fallback position.
fn insert_with_indent(cx: &mut Context, cursor_fallback: IndentFallbackPos) {
    let was_select_mode = cx.editor.mode == Mode::Select;
    enter_insert_mode(cx);

    let (view, doc) = current!(cx.editor);
    let loader = cx.editor.syn_loader.load();

    let text = doc.text().slice(..);
    let contents = doc.text();
    let selection = doc.selection(view.id);

    let syntax = doc.syntax();
    let tab_width = doc.tab_width();

    let mut ranges = SmallVec::with_capacity(selection.len());
    let mut offs = 0;

    let mut transaction = Transaction::change_by_selection(contents, selection, |range| {
        let cursor_line = range.cursor_line(text);
        let cursor_line_start = text.line_to_char(cursor_line);

        if line_end_char_index(&text, cursor_line) == cursor_line_start {
            // line is empty => auto indent
            let line_end_index = cursor_line_start;

            let indent = indent::indent_for_newline(
                &loader,
                syntax,
                &doc.config.load().indent_heuristic,
                &doc.indent_style,
                tab_width,
                text,
                cursor_line,
                line_end_index,
                cursor_line,
            );

            // calculate new selection ranges
            let pos = offs + cursor_line_start;
            let indent_width = indent.chars().count();
            ranges.push(Range::point(pos + indent_width));
            offs += indent_width;

            (line_end_index, line_end_index, Some(indent.into()))
        } else {
            // move cursor to the fallback position
            let pos = match cursor_fallback {
                IndentFallbackPos::LineStart => text
                    .line(cursor_line)
                    .first_non_whitespace_char()
                    .map(|ws_offset| ws_offset + cursor_line_start)
                    .unwrap_or(cursor_line_start),
                IndentFallbackPos::LineEnd => line_end_char_index(&text, cursor_line),
            };

            ranges.push(range.put_cursor(text, pos + offs, was_select_mode));

            (cursor_line_start, cursor_line_start, None)
        }
    });

    transaction = transaction.with_selection(Selection::new(ranges, selection.primary_index()));
    doc.apply(&transaction, view.id);
}

// Creates an LspCallback that waits for formatting changes to be computed. When they're done,
// it applies them, but only if the doc hasn't changed.
//
// TODO: provide some way to cancel this, probably as part of a more general job cancellation
// scheme
async fn make_format_callback(
    doc_id: DocumentId,
    doc_version: i32,
    view_id: ViewId,
    format: impl Future<Output = Result<Transaction, FormatterError>> + Send + 'static,
    write: Option<(Option<PathBuf>, bool)>,
) -> anyhow::Result<job::Callback> {
    let format = format.await;

    let call: job::Callback = Callback::Editor(Box::new(move |editor| {
        if !editor.documents.contains_key(&doc_id) || !editor.tree.contains(view_id) {
            return;
        }

        let scrolloff = editor.config().scrolloff;
        let doc = doc_mut!(editor, &doc_id);
        let view = view_mut!(editor, view_id);

        match format {
            Ok(format) => {
                if doc.version() == doc_version {
                    doc.apply(&format, view.id);
                    doc.append_changes_to_history(view);
                    doc.detect_indent_and_line_ending();
                    view.ensure_cursor_in_view(doc, scrolloff);
                } else {
                    log::info!("discarded formatting changes because the document changed");
                }
            }
            Err(err) => {
                if write.is_none() {
                    editor.set_error(err.to_string());
                    return;
                }
                log::info!("failed to format '{}': {err}", doc.display_name());
            }
        }

        if let Some((path, force)) = write {
            let id = doc.id();
            if let Err(err) = editor.save(id, path, force) {
                editor.set_error(format!("Error saving: {}", err));
            }
        }
    }));

    Ok(call)
}

#[derive(PartialEq, Eq)]
pub enum Open {
    Below,
    Above,
}

#[derive(PartialEq)]
pub enum CommentContinuation {
    Enabled,
    Disabled,
}

fn open(cx: &mut Context, open: Open, comment_continuation: CommentContinuation) {
    let count = cx.count();
    enter_insert_mode(cx);
    let config = cx.editor.config();
    let (view, doc) = current!(cx.editor);
    let loader = cx.editor.syn_loader.load();

    let text = doc.text().slice(..);
    let contents = doc.text();
    let selection = doc.selection(view.id);
    let mut offs = 0;

    let mut ranges = SmallVec::with_capacity(selection.len());

    let mut transaction = Transaction::change_by_selection(contents, selection, |range| {
        // the line number, where the cursor is currently
        let curr_line_num = text.char_to_line(match open {
            Open::Below => graphemes::prev_grapheme_boundary(text, range.to()),
            Open::Above => range.from(),
        });

        // the next line number, where the cursor will be, after finishing the transaction
        let next_new_line_num = match open {
            Open::Below => curr_line_num + 1,
            Open::Above => curr_line_num,
        };

        let above_next_new_line_num = next_new_line_num.saturating_sub(1);

        // Continue the comment leader using the comment tokens of the layer at the current line.
        let continue_comment_token =
            if comment_continuation == CommentContinuation::Enabled && config.continue_comments {
                text.line(curr_line_num)
                    .first_non_whitespace_char()
                    .map(|c| text.char_to_byte(text.line_to_char(curr_line_num) + c))
                    .and_then(|byte| doc.language_config_at(&loader, byte))
                    .and_then(|config| config.comment_tokens.as_ref())
                    .and_then(|tokens| comment::get_comment_token(text, tokens, curr_line_num))
            } else {
                None
            };

        // Index to insert newlines after, as well as the char width
        // to use to compensate for those inserted newlines.
        let (above_next_line_end_index, above_next_line_end_width) = if next_new_line_num == 0 {
            (0, 0)
        } else {
            (
                line_end_char_index(&text, above_next_new_line_num),
                doc.line_ending.len_chars(),
            )
        };

        let line = text.line(curr_line_num);
        let indent = match line.first_non_whitespace_char() {
            Some(pos) if continue_comment_token.is_some() => line.slice(..pos).to_string(),
            _ => indent::indent_for_newline(
                &loader,
                doc.syntax(),
                &config.indent_heuristic,
                &doc.indent_style,
                doc.tab_width(),
                text,
                above_next_new_line_num,
                above_next_line_end_index,
                curr_line_num,
            ),
        };

        let indent_len = indent.len();
        let mut text = String::with_capacity(1 + indent_len);

        if open == Open::Above && next_new_line_num == 0 {
            text.push_str(&indent);
            if let Some(token) = continue_comment_token {
                text.push_str(token);
                text.push(' ');
            }
            text.push_str(doc.line_ending.as_str());
        } else {
            text.push_str(doc.line_ending.as_str());
            text.push_str(&indent);

            if let Some(token) = continue_comment_token {
                text.push_str(token);
                text.push(' ');
            }
        }

        let text = text.repeat(count);

        // calculate new selection ranges
        let pos = offs + above_next_line_end_index + above_next_line_end_width;
        let comment_len = continue_comment_token
            .map(|token| token.len() + 1) // `+ 1` for the extra space added
            .unwrap_or_default();
        for i in 0..count {
            // pos                     -> beginning of reference line,
            // + (i * (line_ending_len + indent_len + comment_len)) -> beginning of i'th line from pos (possibly including comment token)
            // + indent_len + comment_len ->        -> indent for i'th line
            ranges.push(Range::point(
                pos + (i * (doc.line_ending.len_chars() + indent_len + comment_len))
                    + indent_len
                    + comment_len,
            ));
        }

        // update the offset for the next range
        offs += text.chars().count();

        (
            above_next_line_end_index,
            above_next_line_end_index,
            Some(text.into()),
        )
    });

    transaction = transaction.with_selection(Selection::new(ranges, selection.primary_index()));

    doc.apply(&transaction, view.id);
}

/// Build the expansion for postfix template `kw` on `expr` (JetBrains/rust-analyzer
/// postfix completion). Returns the replacement text and the char offset within it
/// for the cursor. `semi` appends the language's statement terminator. None = unknown.
fn postfix_template(kw: &str, expr: &str, semi: bool) -> Option<(String, usize)> {
    let s = if semi { ";" } else { "" };
    let block = |head: String| {
        let inner = format!("{head} {{\n\t");
        let full = format!("{inner}\n}}");
        (full, inner.chars().count())
    };
    let end = |t: String| {
        let n = t.chars().count();
        (t, n)
    };
    Some(match kw {
        "if" => block(format!("if {expr}")),
        "while" => block(format!("while {expr}")),
        "for" => block(format!("for it in {expr}")),
        "match" => block(format!("match {expr}")),
        "else" => block(format!("if !({expr})")),
        "let" => end(format!("let name = {expr}{s}")),
        "return" | "ret" => end(format!("return {expr}{s}")),
        "not" => end(format!("!{expr}")),
        "paren" | "par" => end(format!("({expr})")),
        "print" | "p" => end(format!("print({expr}){s}")),
        "dbg" => end(format!("dbg!({expr}){s}")),
        "some" => end(format!("Some({expr})")),
        "ok" => end(format!("Ok({expr})")),
        "await" => end(format!("{expr}.await")),
        _ => return None,
    })
}

/// Postfix completion: turn `expr.kw` before the cursor into the expansion (e.g.
/// `foo.if` → `if foo {…}`). Works in insert mode; bound under the C-c prefix.
fn postfix_expand(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let semi = lang_uses_semicolons(doc.language_name().unwrap_or(""));
    let text = doc.text();
    let slice = text.slice(..);
    let cursor = doc.selection(view.id).primary().cursor(slice);
    let line = slice.char_to_line(cursor);
    let line_start = slice.line_to_char(line);
    let before: String = slice.slice(line_start..cursor).into();
    let Some(dot) = before.rfind('.') else {
        cx.editor.set_error(
            "postfix: type `expr.kw` (if/for/while/match/let/return/not/paren/print/dbg)",
        );
        return;
    };
    let kw = before[dot + 1..].trim();
    let expr_part = &before[..dot];
    // Expression starts after the last separator before the `.`.
    let boundary = expr_part
        .rfind(|c: char| c.is_whitespace() || "([{;,=&|<>".contains(c))
        .map(|i| i + 1)
        .unwrap_or(0);
    let expr = expr_part[boundary..].trim();
    if expr.is_empty() {
        cx.editor.set_error("postfix: no expression before `.`");
        return;
    }
    let Some((repl, cur_off)) = postfix_template(kw, expr, semi) else {
        cx.editor
            .set_error(format!("postfix: unknown template `.{kw}`"));
        return;
    };
    let from = line_start + before[..boundary].chars().count();
    let tx = Transaction::change(text, std::iter::once((from, cursor, Some(repl.into()))));
    doc.apply(&tx, view.id);
    let new_pos = (from + cur_off).min(doc.text().len_chars());
    doc.set_selection(view.id, Selection::point(new_pos));
}

// o inserts a new line after each line with a selection
fn open_below(cx: &mut Context) {
    open(cx, Open::Below, CommentContinuation::Enabled)
}

// O inserts a new line before each line with a selection
fn open_above(cx: &mut Context) {
    open(cx, Open::Above, CommentContinuation::Enabled)
}

/// Whether a language terminates statements with `;` (so Complete Statement
/// should append one). Conservative allow-list keyed on the tree-sitter
/// language name; languages with implicit terminators (Go), significant
/// newlines (Python), or none (Lisp) are intentionally absent.
fn lang_uses_semicolons(lang: &str) -> bool {
    matches!(
        lang,
        "rust"
            | "c"
            | "cpp"
            | "cuda"
            | "c-sharp"
            | "csharp"
            | "java"
            | "javascript"
            | "jsx"
            | "typescript"
            | "tsx"
            | "php"
            | "scala"
            | "kotlin"
            | "dart"
            | "swift"
            | "objc"
            | "glsl"
            | "hlsl"
            | "css"
            | "scss"
            | "less"
            | "perl"
            | "pascal"
            | "d"
            | "zig"
    )
}

/// Analyze the current line for statement completion: the closers needed for any
/// `(`/`[` left open (in order), whether a `{` was left open, and the code
/// portion (comment stripped, trimmed). String/char literals and line comments
/// (`//`, `#`) are skipped so their brackets don't miscount.
fn bracket_analysis(line: &str) -> (String, bool, String) {
    let mut stack: Vec<char> = Vec::new();
    let mut it = line.char_indices().peekable();
    let mut in_str: Option<char> = None;
    let mut escaped = false;
    let mut code_end = line.len();
    while let Some((i, c)) = it.next() {
        if let Some(q) = in_str {
            if escaped {
                escaped = false;
            } else if c == '\\' {
                escaped = true;
            } else if c == q {
                in_str = None;
            }
            continue;
        }
        match c {
            '"' | '\'' | '`' => in_str = Some(c),
            '/' if matches!(it.peek(), Some((_, '/'))) => {
                code_end = i;
                break;
            }
            '#' => {
                code_end = i;
                break;
            }
            '(' | '[' | '{' => stack.push(c),
            ')' => {
                if stack.last() == Some(&'(') {
                    stack.pop();
                }
            }
            ']' => {
                if stack.last() == Some(&'[') {
                    stack.pop();
                }
            }
            '}' if stack.last() == Some(&'{') => {
                stack.pop();
            }
            _ => {}
        }
    }
    let mut closers = String::new();
    let mut has_open_brace = false;
    for &opener in stack.iter().rev() {
        match opener {
            '(' => closers.push(')'),
            '[' => closers.push(']'),
            '{' => has_open_brace = true,
            _ => {}
        }
    }
    (closers, has_open_brace, line[..code_end].trim().to_string())
}

/// Whether the line is a control-flow / definition header that should open a
/// `{ }` block (`if`/`else`/`for`/`while`/`fn`/`match`/`struct`/…), so Complete
/// Statement can insert the braces the way JetBrains does. Skips leading
/// visibility/async modifiers (`pub fn`, `public class`).
fn line_opens_block(code: &str) -> bool {
    // Strip a leading `}` so `} else if (…)` / `} catch (…)` are recognized.
    let code = code.trim().trim_start_matches('}').trim();
    if code.is_empty() || code.ends_with('{') || code.ends_with(';') {
        return false;
    }
    const MODS: &[&str] = &[
        "pub",
        "async",
        "unsafe",
        "const",
        "static",
        "extern",
        "default",
        "final",
        "public",
        "private",
        "protected",
        "virtual",
        "override",
        "abstract",
    ];
    const OPENERS: &[&str] = &[
        "if",
        "else",
        "for",
        "while",
        "do",
        "switch",
        "try",
        "catch",
        "finally",
        "fn",
        "func",
        "function",
        "class",
        "struct",
        "enum",
        "impl",
        "trait",
        "match",
        "loop",
        "mod",
        "namespace",
        "interface",
        "union",
    ];
    // First token, with any `(`/`{`/`<` stripped (`for(`, `pub(crate)`).
    let head = |w: &str| w.split(['(', '{', '<']).next().unwrap_or(w).to_string();
    let first = code.split_whitespace().next().map(head).unwrap_or_default();
    if OPENERS.contains(&first.as_str()) {
        return true;
    }
    if MODS.contains(&first.as_str()) {
        return code
            .split_whitespace()
            .any(|w| OPENERS.contains(&head(w).as_str()));
    }
    false
}

/// The plain-statement completion suffix: bracket closers plus a `;` terminator
/// when the language uses one and the line isn't already terminated / a comment.
fn statement_completion_suffix(line: &str, uses_semicolon: bool) -> String {
    let (mut suffix, has_open_brace, code) = bracket_analysis(line);
    if uses_semicolon && !has_open_brace {
        let already_terminated = matches!(
            code.chars().last(),
            None | Some(';') | Some('{') | Some('}') | Some(',') | Some(':')
        );
        if !already_terminated {
            suffix.push(';');
        }
    }
    suffix
}

/// JetBrains "Complete Current Statement" (C-c ;): finish the
/// statement the caret is on — close any brackets/parens left open on the line
/// and append the language's terminator (`;`) — then open a fresh indented line
/// below in insert mode, ready to continue. Operates on the primary selection.
fn complete_current_statement(cx: &mut Context) {
    let uses_semicolon = {
        let (_, doc) = current_ref!(cx.editor);
        doc.language_name()
            .map(lang_uses_semicolons)
            .unwrap_or(false)
    };

    let did_block = {
        let (view, doc) = current!(cx.editor);
        let text = doc.text();
        let slice = text.slice(..);
        let cursor = doc.selection(view.id).primary().cursor(slice);
        let line = slice.char_to_line(cursor);
        let line_start = slice.line_to_char(line);
        let line_end = line_end_char_index(&slice, line);
        let line_str: String = slice.slice(line_start..line_end).to_string();

        let (closers, has_open_brace, code) = bracket_analysis(&line_str);
        if uses_semicolon && !has_open_brace && line_opens_block(&code) {
            // Control-flow / definition header: complete the braces the way
            // JetBrains does — `header {` + an indented body line (caret here) +
            // a closing `}` — instead of just terminating.
            let indent: String = line_str.chars().take_while(|c| c.is_whitespace()).collect();
            let unit = doc.indent_style.as_str();
            let le = doc.line_ending.as_str();
            let body_indent = format!("{indent}{unit}");
            let insert = format!("{closers} {{{le}{body_indent}{le}{indent}}}");
            // Caret at the end of the (empty) indented body line.
            let caret = line_end
                + closers.chars().count()
                + 2 // " {"
                + le.chars().count()
                + body_indent.chars().count();
            let transaction = Transaction::change(
                text,
                std::iter::once((line_end, line_end, Some(insert.into()))),
            )
            .with_selection(Selection::point(caret));
            doc.apply(&transaction, view.id);
            true
        } else {
            let suffix = statement_completion_suffix(&line_str, uses_semicolon);
            if !suffix.is_empty() {
                let transaction = Transaction::change(
                    text,
                    std::iter::once((line_end, line_end, Some(suffix.into()))),
                );
                doc.apply(&transaction, view.id);
            }
            false
        }
    };

    if did_block {
        // Caret is already inside the new block; just start typing.
        enter_insert_mode(cx);
    } else {
        // Plain statement: open a fresh indented line below, like JetBrains
        // leaving the caret ready for the next statement.
        open(cx, Open::Below, CommentContinuation::Disabled);
    }
}

fn normal_mode(cx: &mut Context) {
    // Capture the text inserted this session (for i_CTRL-A and the vim `.`
    // register) before leaving insert.
    if cx.editor.mode == Mode::Insert {
        let inserted = {
            let (view, doc) = current!(cx.editor);
            let text = doc.text().slice(..);
            let end = doc.selection(view.id).primary().cursor(text);
            let start = INSERT_ANCHOR
                .load(std::sync::atomic::Ordering::Relaxed)
                .min(text.len_chars());
            (end > start).then(|| text.slice(start..end).chars().collect::<String>())
        };
        if let Some(s) = inserted {
            cx.editor.last_inserted_text = s;
        }
    }
    cx.editor.enter_normal_mode();
}

/// vim `i_CTRL-A`: insert the text of the most recently completed insert session.
fn insert_last_inserted_text(cx: &mut Context) {
    let text = cx.editor.last_inserted_text.clone();
    if text.is_empty() {
        return;
    }
    let mode = cx.editor.mode;
    let (view, doc) = current!(cx.editor);
    paste_impl(&[text], doc, view, Paste::Cursor, 1, mode);
}

/// vim `i_CTRL-@`: insert the last-inserted text and then leave insert mode.
fn insert_last_inserted_and_stop(cx: &mut Context) {
    insert_last_inserted_text(cx);
    normal_mode(cx);
}

// Store a jump on the jumplist.
fn push_jump(view: &mut View, doc: &mut Document) {
    doc.append_changes_to_history(view);
    // vim `` ` ``/`'` "previous context" mark: remember where the cursor was
    // before the jump so `` `` `` (exact) and `''` (line) return to it. Both
    // marks share the position; the two keys differ only in how goto resolves.
    let pos = doc
        .selection(view.id)
        .primary()
        .cursor(doc.text().slice(..));
    doc.set_mark('`', pos);
    doc.set_mark('\'', pos);
    let jump = (doc.id(), doc.selection(view.id).clone());
    view.push_jump(doc, jump);
}

/// Vim linewise motions (`gg`, `G`, `{n}G`, …) land on the first non-blank
/// character of the destination line, not column 0 (Helix's `goto_line`).
fn first_nonblank_of_line(text: RopeSlice, line: usize) -> usize {
    let start = text.line_to_char(line);
    text.line(line)
        .first_non_whitespace_char()
        .map_or(start, |offset| start + offset)
}

fn goto_line(cx: &mut Context) {
    goto_line_impl(cx, Movement::Move);
}

fn goto_line_impl(cx: &mut Context, movement: Movement) {
    if cx.count.is_some() {
        let (view, doc) = current!(cx.editor);
        push_jump(view, doc);

        goto_line_without_jumplist(cx.editor, cx.count, movement);
    }
}

fn goto_line_without_jumplist(
    editor: &mut Editor,
    count: Option<NonZeroUsize>,
    movement: Movement,
) {
    if let Some(count) = count {
        let (view, doc) = current!(editor);
        let text = doc.text().slice(..);
        let max_line = if text.line(text.len_lines() - 1).len_chars() == 0 {
            // If the last line is blank, don't jump to it.
            text.len_lines().saturating_sub(2)
        } else {
            text.len_lines() - 1
        };
        let line_idx = std::cmp::min(count.get() - 1, max_line);
        let pos = first_nonblank_of_line(text, line_idx);
        let selection = doc
            .selection(view.id)
            .clone()
            .transform(|range| range.put_cursor(text, pos, movement == Movement::Extend));

        doc.set_selection(view.id, selection);
    }
}

fn goto_last_line(cx: &mut Context) {
    goto_last_line_impl(cx, Movement::Move)
}

fn extend_to_last_line(cx: &mut Context) {
    goto_last_line_impl(cx, Movement::Extend)
}

fn goto_last_line_impl(cx: &mut Context, movement: Movement) {
    // vim `{count}G` jumps to that line (first non-blank); bare `G` to the last line.
    if cx.count.is_some() {
        let (view, doc) = current!(cx.editor);
        push_jump(view, doc);
        goto_line_without_jumplist(cx.editor, cx.count, movement);
        return;
    }
    let (view, doc) = current!(cx.editor);
    // When narrowed, `G` goes to the last line of the region (Emacs point-max line), per-view aware.
    let narrowed = doc.is_narrowed() || doc.view_narrow(view.id).is_some();
    let point_max = doc.view_point_max(view.id);
    let text = doc.text().slice(..);
    let last_line = if narrowed {
        text.char_to_line(point_max.min(text.len_chars()))
    } else {
        text.len_lines() - 1
    };
    let line_idx = if text.line(last_line).len_chars() == 0 && last_line > 0 {
        // If the last line is blank, don't jump to it.
        last_line.saturating_sub(1)
    } else {
        last_line
    };
    let pos = first_nonblank_of_line(text, line_idx);
    let selection = doc
        .selection(view.id)
        .clone()
        .transform(|range| range.put_cursor(text, pos, movement == Movement::Extend));

    push_jump(view, doc);
    doc.set_selection(view.id, selection);
}

fn goto_column(cx: &mut Context) {
    goto_column_impl(cx, Movement::Move);
}

fn extend_to_column(cx: &mut Context) {
    goto_column_impl(cx, Movement::Extend);
}

fn goto_column_impl(cx: &mut Context, movement: Movement) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);
    let selection = doc.selection(view.id).clone().transform(|range| {
        let line = range.cursor_line(text);
        let line_start = text.line_to_char(line);
        let line_end = line_end_char_index(&text, line);
        let pos = graphemes::nth_next_grapheme_boundary(text, line_start, count - 1).min(line_end);
        range.put_cursor(text, pos, movement == Movement::Extend)
    });
    push_jump(view, doc);
    doc.set_selection(view.id, selection);
}

fn goto_last_accessed_file(cx: &mut Context) {
    let view = view_mut!(cx.editor);
    if let Some(alt) = view.docs_access_history.pop() {
        cx.editor.switch(alt, Action::Replace);
    } else {
        cx.editor.set_error("no last accessed buffer")
    }
}

fn goto_last_modification(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let pos = doc.history.get_mut().last_edit_pos();
    let text = doc.text().slice(..);
    if let Some(pos) = pos {
        let selection = doc
            .selection(view.id)
            .clone()
            .transform(|range| range.put_cursor(text, pos, cx.editor.mode == Mode::Select));
        push_jump(view, doc);
        doc.set_selection(view.id, selection);
    }
}

fn goto_last_modified_file(cx: &mut Context) {
    let view = view!(cx.editor);
    let alternate_file = view
        .last_modified_docs
        .into_iter()
        .flatten()
        .find(|&id| id != view.doc);
    if let Some(alt) = alternate_file {
        cx.editor.switch(alt, Action::Replace);
    } else {
        cx.editor.set_error("no last modified buffer")
    }
}

fn select_mode(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);

    // Make sure end-of-document selections are also 1-width.
    // (With the exception of being in an empty document, of course.)
    let selection = doc.selection(view.id).clone().transform(|range| {
        if range.is_empty() && range.head == text.len_chars() {
            Range::new(
                graphemes::prev_grapheme_boundary(text, range.anchor),
                range.head,
            )
        } else {
            range
        }
    });
    doc.set_selection(view.id, selection);

    cx.editor.mode = Mode::Select;
}

fn exit_select_mode(cx: &mut Context) {
    if cx.editor.mode == Mode::Select {
        cx.editor.mode = Mode::Normal;
    }
}

/// Copy the diagnostic message(s) on the current line to the clipboard — handy
/// for pasting an error into a search or issue.
fn copy_diagnostic(cx: &mut Context) {
    let messages = {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text().slice(..);
        let line = text.char_to_line(doc.selection(view.id).primary().cursor(text));
        doc.diagnostics()
            .iter()
            .filter(|d| text.char_to_line(d.range.start) == line)
            .map(|d| d.message.clone())
            .collect::<Vec<_>>()
    };
    if messages.is_empty() {
        cx.editor.set_status("No diagnostic on this line");
        return;
    }
    let joined = messages.join("\n");
    let _ = cx.editor.registers.write('+', vec![joined.clone()]);
    let first = joined.lines().next().unwrap_or_default();
    cx.editor.set_status(format!("Copied diagnostic: {first}"));
}

fn goto_first_diag(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let selection = match doc.diagnostics().first() {
        Some(diag) => Selection::single(diag.range.start, diag.range.end),
        None => return,
    };
    push_jump(view, doc);
    doc.set_selection(view.id, selection);
    view.diagnostics_handler
        .immediately_show_diagnostic(doc, view.id);
}

fn goto_last_diag(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let selection = match doc.diagnostics().last() {
        Some(diag) => Selection::single(diag.range.start, diag.range.end),
        None => return,
    };
    push_jump(view, doc);
    doc.set_selection(view.id, selection);
    view.diagnostics_handler
        .immediately_show_diagnostic(doc, view.id);
}

fn goto_next_diag(cx: &mut Context) {
    let motion = move |editor: &mut Editor| {
        let (view, doc) = current!(editor);

        let cursor_pos = doc
            .selection(view.id)
            .primary()
            .cursor(doc.text().slice(..));

        let diag = doc
            .diagnostics()
            .iter()
            .find(|diag| diag.range.start > cursor_pos);

        let selection = match diag {
            Some(diag) => Selection::single(diag.range.start, diag.range.end),
            None => return,
        };
        push_jump(view, doc);
        doc.set_selection(view.id, selection);
        view.diagnostics_handler
            .immediately_show_diagnostic(doc, view.id);
    };

    cx.editor.apply_motion(motion);
}

fn goto_prev_diag(cx: &mut Context) {
    let motion = move |editor: &mut Editor| {
        let (view, doc) = current!(editor);

        let cursor_pos = doc
            .selection(view.id)
            .primary()
            .cursor(doc.text().slice(..));

        let diag = doc
            .diagnostics()
            .iter()
            .rev()
            .find(|diag| diag.range.start < cursor_pos);

        let selection = match diag {
            // NOTE: the selection is reversed because we're jumping to the
            // previous diagnostic.
            Some(diag) => Selection::single(diag.range.end, diag.range.start),
            None => return,
        };
        push_jump(view, doc);
        doc.set_selection(view.id, selection);
        view.diagnostics_handler
            .immediately_show_diagnostic(doc, view.id);
    };
    cx.editor.apply_motion(motion)
}

fn goto_first_change(cx: &mut Context) {
    goto_first_change_impl(cx, false);
}

fn goto_last_change(cx: &mut Context) {
    goto_first_change_impl(cx, true);
}

fn goto_first_change_impl(cx: &mut Context, reverse: bool) {
    let editor = &mut cx.editor;
    let (view, doc) = current!(editor);
    if let Some(handle) = doc.diff_handle() {
        let hunk = {
            let diff = handle.load();
            let idx = if reverse {
                diff.len().saturating_sub(1)
            } else {
                0
            };
            diff.nth_hunk(idx)
        };
        if hunk != Hunk::NONE {
            let range = hunk_range(hunk, doc.text().slice(..));
            push_jump(view, doc);
            doc.set_selection(view.id, Selection::single(range.anchor, range.head));
        }
    }
}

/// True if a line begins with a git merge-conflict marker.
fn is_conflict_marker(line: RopeSlice) -> bool {
    let prefix: String = line.chars().take(7).collect();
    matches!(
        prefix.as_str(),
        "<<<<<<<" | "=======" | ">>>>>>>" | "|||||||"
    )
}

/// Pure core of `goto_conflict_impl`: starting from `cur_line` (exclusive),
/// return the index of the nearest line that begins with a git merge-conflict
/// marker, searching forward or backward. Unit-tested.
fn find_conflict_line(slice: RopeSlice, cur_line: usize, forward: bool) -> Option<usize> {
    let total = slice.len_lines();
    if forward {
        (cur_line + 1..total).find(|&l| is_conflict_marker(slice.line(l)))
    } else {
        (0..cur_line)
            .rev()
            .find(|&l| is_conflict_marker(slice.line(l)))
    }
}

fn goto_conflict_impl(cx: &mut Context, forward: bool) {
    let scrolloff = cx.editor.config().scrolloff;
    let target = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        let cur_line = slice.char_to_line(doc.selection(view.id).primary().cursor(slice));
        find_conflict_line(slice, cur_line, forward).map(|l| slice.line_to_char(l))
    };
    match target {
        Some(pos) => {
            let (view, doc) = current!(cx.editor);
            push_jump(view, doc);
            doc.set_selection(view.id, Selection::point(pos));
            view.ensure_cursor_in_view(doc, scrolloff);
        }
        None => cx.editor.set_status("No merge-conflict markers"),
    }
}

fn line_starts_with(line: RopeSlice, marker: &str) -> bool {
    line.chars().take(marker.len()).collect::<String>() == marker
}

#[derive(Clone, Copy)]
enum ConflictSide {
    Ours,
    Theirs,
    #[allow(dead_code)] // keep-both resolution not yet wired to a command
    Both,
}

/// Resolve EVERY merge conflict in the buffer, keeping the given side(s).
fn resolve_all_conflicts(cx: &mut Context, side: ConflictSide) {
    let changes: Vec<(usize, usize, Option<Tendril>)> = {
        let (_, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        let total = slice.len_lines();
        let mut changes = Vec::new();
        let mut l = 0;
        while l < total {
            if !line_starts_with(slice.line(l), "<<<<<<<") {
                l += 1;
                continue;
            }
            let start = l;
            let (mut base, mut sep, mut end) = (None, None, None);
            let mut k = start + 1;
            while k < total {
                if base.is_none() && sep.is_none() && line_starts_with(slice.line(k), "|||||||") {
                    base = Some(k);
                } else if sep.is_none() && line_starts_with(slice.line(k), "=======") {
                    sep = Some(k);
                } else if line_starts_with(slice.line(k), ">>>>>>>") {
                    end = Some(k);
                    break;
                }
                k += 1;
            }
            if let (Some(sep), Some(end)) = (sep, end) {
                let ours_end = base.unwrap_or(sep);
                let ours: String = slice
                    .slice(slice.line_to_char(start + 1)..slice.line_to_char(ours_end))
                    .chars()
                    .collect();
                let theirs: String = slice
                    .slice(slice.line_to_char(sep + 1)..slice.line_to_char(end))
                    .chars()
                    .collect();
                let repl = match side {
                    ConflictSide::Ours => ours,
                    ConflictSide::Theirs => theirs,
                    ConflictSide::Both => format!("{ours}{theirs}"),
                };
                changes.push((
                    slice.line_to_char(start),
                    slice.line_to_char((end + 1).min(total)),
                    (!repl.is_empty()).then(|| repl.into()),
                ));
                l = end + 1;
            } else {
                l += 1;
            }
        }
        changes
    };
    if changes.is_empty() {
        cx.editor.set_status("No conflicts to resolve");
        return;
    }
    let n = changes.len();
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(doc.text(), changes.into_iter());
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
    cx.editor.set_status(format!("Resolved {n} conflicts"));
}

fn conflict_take_all_ours(cx: &mut Context) {
    resolve_all_conflicts(cx, ConflictSide::Ours);
}
fn conflict_take_all_theirs(cx: &mut Context) {
    resolve_all_conflicts(cx, ConflictSide::Theirs);
}

/// vim/git `]x`: jump to the next merge-conflict marker.
fn goto_next_conflict(cx: &mut Context) {
    goto_conflict_impl(cx, true);
}

/// vim/git `[x`: jump to the previous merge-conflict marker.
fn goto_prev_conflict(cx: &mut Context) {
    goto_conflict_impl(cx, false);
}

fn goto_next_change(cx: &mut Context) {
    goto_next_change_impl(cx, Direction::Forward)
}

fn goto_prev_change(cx: &mut Context) {
    goto_next_change_impl(cx, Direction::Backward)
}

fn goto_next_change_impl(cx: &mut Context, direction: Direction) {
    let count = cx.count() as u32 - 1;
    let motion = move |editor: &mut Editor| {
        let (view, doc) = current!(editor);
        let doc_text = doc.text().slice(..);
        let diff_handle = if let Some(diff_handle) = doc.diff_handle() {
            diff_handle
        } else {
            editor.set_status("Diff is not available in current buffer");
            return;
        };

        let selection = doc.selection(view.id).clone().transform(|range| {
            let cursor_line = range.cursor_line(doc_text) as u32;

            let diff = diff_handle.load();
            let hunk_idx = match direction {
                Direction::Forward => diff
                    .next_hunk(cursor_line)
                    .map(|idx| (idx + count).min(diff.len() - 1)),
                Direction::Backward => diff
                    .prev_hunk(cursor_line)
                    .map(|idx| idx.saturating_sub(count)),
            };
            let Some(hunk_idx) = hunk_idx else {
                return range;
            };
            let hunk = diff.nth_hunk(hunk_idx);
            let new_range = hunk_range(hunk, doc_text);
            if editor.mode == Mode::Select {
                let head = if new_range.head < range.anchor {
                    new_range.anchor
                } else {
                    new_range.head
                };

                Range::new(range.anchor, head)
            } else {
                new_range.with_direction(direction)
            }
        });

        push_jump(view, doc);
        doc.set_selection(view.id, selection)
    };
    cx.editor.apply_motion(motion);
}

/// Returns the [Range] for a [Hunk] in the given text.
/// Additions and modifications cover the added and modified ranges.
/// Deletions are represented as the point at the start of the deletion hunk.
fn hunk_range(hunk: Hunk, text: RopeSlice) -> Range {
    let anchor = text.line_to_char(hunk.after.start as usize);
    let head = if hunk.after.is_empty() {
        anchor + 1
    } else {
        text.line_to_char(hunk.after.end as usize)
    };

    Range::new(anchor, head)
}

pub mod insert {
    use crate::{events::PostInsertChar, key};

    use super::*;
    pub type Hook = fn(&Rope, &Selection, char) -> Option<Transaction>;

    /// Exclude the cursor in range.
    fn exclude_cursor(text: RopeSlice, range: Range, cursor: Range) -> Range {
        if range.to() == cursor.to() && text.len_chars() != cursor.to() {
            Range::new(
                range.from(),
                graphemes::prev_grapheme_boundary(text, cursor.to()),
            )
        } else {
            range
        }
    }

    use zemacs_core::auto_pairs;
    use zemacs_view::editor::SmartTabConfig;

    /// Emacs auto-fill break point. Given the line text up to the cursor and the
    /// fill column, return the char index (within `prefix`) of the whitespace to
    /// replace with a newline, or `None` to leave the line unbroken. Breaks at
    /// the last whitespace at/before the fill column; if the first word is itself
    /// longer than the column, breaks at the first whitespace past it instead.
    pub(crate) fn auto_fill_break(prefix: &str, fill: usize) -> Option<usize> {
        if prefix.chars().count() <= fill {
            return None;
        }
        let mut last_ws_before: Option<usize> = None;
        let mut first_ws_after: Option<usize> = None;
        for (i, ch) in prefix.chars().enumerate() {
            if (ch == ' ' || ch == '\t') && i > 0 {
                if i <= fill {
                    last_ws_before = Some(i);
                } else if first_ws_after.is_none() {
                    first_ws_after = Some(i);
                }
            }
        }
        last_ws_before.or(first_ws_after)
    }

    /// Emacs auto-fill (`SPC t F`): if the current line exceeds `text_width`,
    /// replace a whitespace with a newline so the line wraps. Single cursor only.
    fn auto_fill_after_insert(cx: &mut Context) {
        let fill = cx.editor.config().text_width;
        let (ws_at, view_id, doc_id) = {
            let (view, doc) = current_ref!(cx.editor);
            let slice = doc.text().slice(..);
            let sel = doc.selection(view.id);
            if sel.len() != 1 {
                return;
            }
            let cursor = sel.primary().cursor(slice);
            let line = slice.char_to_line(cursor);
            let line_start = slice.line_to_char(line);
            let prefix: String = slice.slice(line_start..cursor).chars().collect();
            match auto_fill_break(&prefix, fill) {
                Some(b) => (line_start + b, view.id, doc.id()),
                None => return,
            }
        };
        // Emacs `fill-prefix`: prepend it to the wrapped continuation line.
        let mut newline = String::from("\n");
        if let Some(prefix) = &cx.editor.fill_prefix {
            newline.push_str(prefix);
        }
        let doc = doc_mut!(cx.editor, &doc_id);
        let text = doc.text();
        let transaction = Transaction::change(
            text,
            std::iter::once((ws_at, ws_at + 1, Some(Tendril::from(newline.as_str())))),
        );
        doc.apply(&transaction, view_id);
    }

    pub fn insert_char(cx: &mut Context, c: char) {
        // Emacs picture-mode: overwrite the cell under point and advance in the
        // current drawing direction, padding past line/buffer ends with spaces.
        if cx.editor.picture_mode {
            return super::picture_self_insert(cx, c);
        }
        // vim Replace mode (`R`): overtype the character under the cursor rather
        // than inserting, unless the cursor sits at the end of the line (where
        // vim appends). Auto-pairs are bypassed while overtyping.
        if cx.editor.overwrite {
            return overtype_char(cx, c);
        }

        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text();
        let selection = doc.selection(view.id);

        let loader: &zemacs_core::syntax::Loader = &cx.editor.syn_loader.load();
        let auto_pairs = doc.auto_pairs(cx.editor, loader, view);

        let insert_char = |range: Range, ch: char| {
            let cursor = range.cursor(text.slice(..));
            let t = Tendril::from_iter([ch]);
            ((cursor, cursor, Some(t)), None)
        };

        let transaction = Transaction::change_by_and_with_selection(text, selection, |range| {
            auto_pairs
                .as_ref()
                .and_then(|ap| {
                    auto_pairs::hook_insert(text, range, c, ap)
                        .map(|(change, range)| (change, Some(range)))
                        .or_else(|| Some(insert_char(*range, c)))
                })
                .unwrap_or_else(|| insert_char(*range, c))
        });

        let doc = doc_mut!(cx.editor, &doc.id());
        doc.apply(&transaction, view.id);

        // Emacs auto-fill (SPC t F): wrap the line at whitespace past text_width.
        if cx.editor.auto_fill {
            auto_fill_after_insert(cx);
        }

        zemacs_event::dispatch(PostInsertChar { c, cx });
    }

    /// Overtype the grapheme under each cursor with `c` (vim Replace mode). At a
    /// line end the character is appended instead, matching vim.
    pub fn overtype_char(cx: &mut Context, c: char) {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text();
        let slice = text.slice(..);
        let selection = doc.selection(view.id);

        let transaction = Transaction::change_by_and_with_selection(text, selection, |range| {
            let cursor = range.cursor(slice);
            let line = slice.char_to_line(cursor);
            let line_end = line_end_char_index(&slice, line);
            let t = Tendril::from_iter([c]);
            // Replace the char under the cursor unless at end-of-line (append).
            let end = if cursor < line_end {
                graphemes::next_grapheme_boundary(slice, cursor)
            } else {
                cursor
            };
            // Advance the cursor past the overtyped character (vim moves right).
            ((cursor, end, Some(t)), Some(Range::point(cursor + 1)))
        });

        let doc = doc_mut!(cx.editor, &doc.id());
        doc.apply(&transaction, view.id);

        zemacs_event::dispatch(PostInsertChar { c, cx });
    }

    pub fn smart_tab(cx: &mut Context) {
        let (view, doc) = current_ref!(cx.editor);
        let view_id = view.id;

        if matches!(
            cx.editor.config().smart_tab,
            Some(SmartTabConfig { enable: true, .. })
        ) {
            let cursors_after_whitespace = doc.selection(view_id).ranges().iter().all(|range| {
                let cursor = range.cursor(doc.text().slice(..));
                let current_line_num = doc.text().char_to_line(cursor);
                let current_line_start = doc.text().line_to_char(current_line_num);
                let left = doc.text().slice(current_line_start..cursor);
                left.chars().all(|c| c.is_whitespace())
            });

            if !cursors_after_whitespace {
                if doc.active_snippet.is_some() {
                    goto_next_tabstop(cx);
                } else {
                    move_parent_node_end(cx);
                }
                return;
            }
        }

        insert_tab(cx);
    }

    pub fn insert_tab(cx: &mut Context) {
        insert_tab_impl(cx, 1)
    }

    fn insert_tab_impl(cx: &mut Context, count: usize) {
        let (view, doc) = current!(cx.editor);

        let transaction = Transaction::change(
            doc.text(),
            doc.selection(view.id).ranges().iter().map(|range| {
                let cursor = range.cursor(doc.text().slice(..));
                let indent = if let IndentStyle::Spaces(indent_width) = doc.indent_style {
                    let line = range.cursor_line(doc.text().slice(..));
                    let line_start = doc.text().line_to_char(line);
                    let offset = (cursor - line_start) % indent_width as usize;

                    Tendril::from(doc.indent_style.as_str().repeat(count)).split_off(offset)
                } else {
                    Tendril::from(doc.indent_style.as_str().repeat(count))
                };

                (cursor, cursor, Some(indent))
            }),
        );
        doc.apply(&transaction, view.id);
    }

    pub fn append_char_interactive(cx: &mut Context) {
        // Save the current mode, so we can restore it later.
        let mode = cx.editor.mode;
        append_mode(cx);
        insert_selection_interactive(cx, mode);
    }

    pub fn insert_char_interactive(cx: &mut Context) {
        let mode = cx.editor.mode;
        insert_mode(cx);
        insert_selection_interactive(cx, mode);
    }

    fn insert_selection_interactive(cx: &mut Context, old_mode: Mode) {
        let count = cx.count();

        // need to wait for next key
        cx.on_next_key(move |cx, event| {
            match event {
                KeyEvent {
                    code: KeyCode::Char(ch),
                    ..
                } => {
                    for _ in 0..count {
                        insert::insert_char(cx, ch)
                    }
                }
                key!(Enter) => {
                    if count != 1 {
                        cx.editor
                            .set_error("inserting multiple newlines not yet supported");
                        return;
                    }
                    insert_newline(cx)
                }
                key!(Tab) => insert_tab_impl(cx, count),
                _ => (),
            };
            // Restore the old mode.
            cx.editor.mode = old_mode;
        });
    }

    pub fn insert_newline(cx: &mut Context) {
        let config = cx.editor.config();
        let (view, doc) = current_ref!(cx.editor);
        let loader = cx.editor.syn_loader.load();
        let text = doc.text().slice(..);
        let line_ending = doc.line_ending.as_str();

        let contents = doc.text();
        let selection = doc.selection(view.id);
        let mut ranges = SmallVec::with_capacity(selection.len());

        // TODO: this is annoying, but we need to do it to properly calculate pos after edits
        let mut global_offs = 0;
        let mut new_text = String::new();

        let mut last_pos = 0;
        let mut transaction = Transaction::change_by_selection(contents, selection, |range| {
            // Tracks the number of trailing whitespace characters deleted by this selection.
            let mut chars_deleted = 0;
            let pos = range.cursor(text);

            let prev = if pos == 0 {
                ' '
            } else {
                contents.char(pos - 1)
            };
            let curr = contents.get_char(pos).unwrap_or(' ');

            let current_line = text.char_to_line(pos);
            let line_start = text.line_to_char(current_line);

            // Continue the comment leader using the comment tokens of the layer at the comment
            // leader (i.e. the first non-whitespace char on the line). Looking up at the cursor
            // would land inside an injected layer (e.g. `comment`, or markdown in a doc comment)
            // and miss the host language's tokens.
            let continue_comment_token = if config.continue_comments {
                text.line(current_line)
                    .first_non_whitespace_char()
                    .map(|c| text.char_to_byte(line_start + c))
                    .and_then(|byte| doc.language_config_at(&loader, byte))
                    .and_then(|config| config.comment_tokens.as_ref())
                    .and_then(|tokens| comment::get_comment_token(text, tokens, current_line))
            } else {
                None
            };

            let (from, to, local_offs) = if let Some(idx) =
                text.slice(line_start..pos).last_non_whitespace_char()
            {
                let first_trailing_whitespace_char = (line_start + idx + 1).clamp(last_pos, pos);
                last_pos = pos;
                let line = text.line(current_line);

                let indent = match line.first_non_whitespace_char() {
                    Some(pos) if continue_comment_token.is_some() => line.slice(..pos).to_string(),
                    _ => indent::indent_for_newline(
                        &loader,
                        doc.syntax(),
                        &config.indent_heuristic,
                        &doc.indent_style,
                        doc.tab_width(),
                        text,
                        current_line,
                        pos,
                        current_line,
                    ),
                };

                let loader: &zemacs_core::syntax::Loader = &cx.editor.syn_loader.load();
                // If we are between pairs (such as brackets), we want to
                // insert an additional line which is indented one level
                // more and place the cursor there
                let on_auto_pair = doc
                    .auto_pairs(cx.editor, loader, view)
                    .and_then(|pairs| pairs.get(prev))
                    .is_some_and(|pair| pair.open == prev && pair.close == curr);

                let local_offs = if let Some(token) = continue_comment_token {
                    new_text.reserve_exact(line_ending.len() + indent.len() + token.len() + 1);
                    new_text.push_str(line_ending);
                    new_text.push_str(&indent);
                    new_text.push_str(token);
                    new_text.push(' ');
                    new_text.chars().count()
                } else if on_auto_pair {
                    // line where the cursor will be
                    let inner_indent = indent.clone() + doc.indent_style.as_str();
                    new_text
                        .reserve_exact(line_ending.len() * 2 + indent.len() + inner_indent.len());
                    new_text.push_str(line_ending);
                    new_text.push_str(&inner_indent);

                    // line where the matching pair will be
                    let local_offs = new_text.chars().count();
                    new_text.push_str(line_ending);
                    new_text.push_str(&indent);

                    local_offs
                } else {
                    new_text.reserve_exact(line_ending.len() + indent.len());
                    new_text.push_str(line_ending);
                    new_text.push_str(&indent);

                    new_text.chars().count()
                };

                // Note that `first_trailing_whitespace_char` is at least `pos` so this unsigned
                // subtraction cannot underflow.
                chars_deleted = pos - first_trailing_whitespace_char;

                (
                    first_trailing_whitespace_char,
                    pos,
                    local_offs as isize - chars_deleted as isize,
                )
            } else {
                // If the current line is all whitespace, insert a line ending at the beginning of
                // the current line. This makes the current line empty and the new line contain the
                // indentation of the old line.
                new_text.push_str(line_ending);

                (line_start, line_start, new_text.chars().count() as isize)
            };

            let new_range = if range.cursor(text) > range.anchor {
                // when appending, extend the range by local_offs
                Range::new(
                    (range.anchor as isize + global_offs) as usize,
                    (range.head as isize + local_offs + global_offs) as usize,
                )
            } else {
                // when inserting, slide the range by local_offs
                Range::new(
                    (range.anchor as isize + local_offs + global_offs) as usize,
                    (range.head as isize + local_offs + global_offs) as usize,
                )
            };

            // TODO: range replace or extend
            // range.replace(|range| range.is_empty(), head); -> fn extend if cond true, new head pos
            // can be used with cx.mode to do replace or extend on most changes
            ranges.push(new_range);
            global_offs += new_text.chars().count() as isize - chars_deleted as isize;
            let tendril = Tendril::from(&new_text);
            new_text.clear();

            (from, to, Some(tendril))
        });

        transaction = transaction.with_selection(Selection::new(ranges, selection.primary_index()));

        let (view, doc) = current!(cx.editor);
        doc.apply(&transaction, view.id);
    }

    /// Core of `default-indent-new-line` (emacs M-j): break `line` at char offset
    /// `col`. Trailing whitespace immediately before the break and leading
    /// whitespace immediately after it are removed (emacs's two
    /// `delete-horizontal-space` calls in `comment-indent-new-line`), then a
    /// newline, the continuation `indent`, and — when the line is a comment
    /// (`token` is `Some`) — the comment prefix are inserted.
    ///
    /// Returns the char range within `line` to replace (`start..end`) and the
    /// text to put in its place; the caller offsets these by the line's start and
    /// places point at `line_start + start + insert.chars().count()`.
    pub(crate) fn default_indent_new_line_edit(
        line: &[char],
        col: usize,
        token: Option<&str>,
        indent: &str,
        line_ending: &str,
    ) -> (usize, usize, String) {
        let col = col.min(line.len());
        let mut start = col;
        while start > 0 && matches!(line[start - 1], ' ' | '\t') {
            start -= 1;
        }
        let mut end = col;
        while end < line.len() && matches!(line[end], ' ' | '\t') {
            end += 1;
        }
        let mut insert = String::with_capacity(line_ending.len() + indent.len() + 4);
        insert.push_str(line_ending);
        insert.push_str(indent);
        if let Some(token) = token {
            insert.push_str(token);
            insert.push(' ');
        }
        (start, end, insert)
    }

    /// `default-indent-new-line` (emacs M-j): break the line at point and indent,
    /// continuing the comment when point is inside one. In a comment this ports
    /// `comment-indent-new-line` (align the continuation under the current comment
    /// and reinsert the comment prefix); outside a comment it is
    /// `newline-and-indent` (drop surrounding whitespace, break, indent as for a
    /// fresh line). Reuses the same comment-token lookup and `indent_for_newline`
    /// helpers as `insert_newline`.
    pub fn default_indent_new_line(cx: &mut Context) {
        enter_insert_mode(cx);
        let config = cx.editor.config();
        let loader = cx.editor.syn_loader.load();
        let (view, doc) = current_ref!(cx.editor);
        let view_id = view.id;
        let text = doc.text().slice(..);
        let line_ending = doc.line_ending.as_str().to_string();

        let cursor = doc.selection(view_id).primary().cursor(text);
        let line_num = text.char_to_line(cursor);
        let line_start = text.line_to_char(line_num);
        let content_end = line_end_char_index(&text, line_num);
        let col = cursor.clamp(line_start, content_end) - line_start;

        // Comment token of this line (if it begins a comment) — the same lookup as
        // `insert_newline`'s continuation path, but unconditional: continuing the
        // comment is the whole point of this command, not a config toggle.
        let first_non_ws = text.line(line_num).first_non_whitespace_char();
        let token = first_non_ws
            .map(|c| text.char_to_byte(line_start + c))
            .and_then(|byte| doc.language_config_at(&loader, byte))
            .and_then(|cfg| cfg.comment_tokens.as_ref())
            .and_then(|tokens| comment::get_comment_token(text, tokens, line_num))
            .map(|t| t.to_string());

        // Continuation indent: align under the current comment (its leading
        // whitespace) when continuing one, else indent as for a fresh line.
        let indent = if token.is_some() {
            first_non_ws
                .map(|c| text.line(line_num).slice(..c).to_string())
                .unwrap_or_default()
        } else {
            indent::indent_for_newline(
                &loader,
                doc.syntax(),
                &config.indent_heuristic,
                &doc.indent_style,
                doc.tab_width(),
                text,
                line_num,
                cursor,
                line_num,
            )
        };

        let line_chars: Vec<char> = text
            .line(line_num)
            .slice(..content_end - line_start)
            .chars()
            .collect();
        let (del_start, del_end, insert) =
            default_indent_new_line_edit(&line_chars, col, token.as_deref(), &indent, &line_ending);

        let from = line_start + del_start;
        let to = line_start + del_end;
        let new_cursor = from + insert.chars().count();
        let transaction = Transaction::change(
            doc.text(),
            std::iter::once((from, to, Some(Tendril::from(insert.as_str())))),
        );

        let (view, doc) = current!(cx.editor);
        doc.apply(&transaction, view_id);
        doc.set_selection(view_id, Selection::point(new_cursor));
        doc.append_changes_to_history(view);
    }

    fn dedent(doc: &Document, range: &Range) -> Option<Deletion> {
        let text = doc.text().slice(..);
        let pos = range.cursor(text);
        let line_start_pos = text.line_to_char(range.cursor_line(text));

        // consider to delete by indent level if all characters before `pos` are indent units.
        let fragment = Cow::from(text.slice(line_start_pos..pos));

        if fragment.is_empty() || !fragment.chars().all(|ch| ch == ' ' || ch == '\t') {
            return None;
        }

        if text.get_char(pos.saturating_sub(1)) == Some('\t') {
            // fast path, delete one char
            return Some((graphemes::nth_prev_grapheme_boundary(text, pos, 1), pos));
        }

        let tab_width = doc.tab_width();
        let indent_width = doc.indent_width();

        let width: usize = fragment
            .chars()
            .map(|ch| {
                if ch == '\t' {
                    tab_width
                } else {
                    // it can be none if it still meet control characters other than '\t'
                    // here just set the width to 1 (or some value better?).
                    ch.width().unwrap_or(1)
                }
            })
            .sum();

        // round down to nearest unit
        let mut drop = width % indent_width;

        // if it's already at a unit, consume a whole unit
        if drop == 0 {
            drop = indent_width
        };

        let mut chars = fragment.chars().rev();
        let mut start = pos;

        for _ in 0..drop {
            // delete up to `drop` spaces
            match chars.next() {
                Some(' ') => start -= 1,
                _ => break,
            }
        }

        Some((start, pos)) // delete!
    }

    pub fn delete_char_backward(cx: &mut Context) {
        let count = cx.count();
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text().slice(..);

        let loader: &zemacs_core::syntax::Loader = &cx.editor.syn_loader.load();
        let auto_pairs = doc.auto_pairs(cx.editor, loader, view);

        let transaction = Transaction::delete_by_and_with_selection(
            doc.text(),
            doc.selection(view.id),
            |range| {
                let pos = range.cursor(text);

                log::debug!("cursor: {}, len: {}", pos, text.len_chars());

                if pos == 0 {
                    return ((pos, pos), None);
                }

                dedent(doc, range)
                    .map(|dedent| (dedent, None))
                    .or_else(|| {
                        // [TODO] should this be fixed to get the auto pairs for
                        // each selection after 46af40017c0704142516b5740cf1a000ba4fd7c1 ?
                        auto_pairs::hook_delete(doc.text(), range, auto_pairs?)
                            .map(|(delete, new_range)| (delete, Some(new_range)))
                    })
                    .unwrap_or_else(|| {
                        (
                            (graphemes::nth_prev_grapheme_boundary(text, pos, count), pos),
                            None,
                        )
                    })
            },
        );

        log::debug!("delete_char_backward transaction: {:?}", transaction);

        let doc = doc_mut!(cx.editor, &doc.id());
        doc.apply(&transaction, view.id);
    }

    pub fn delete_char_forward(cx: &mut Context) {
        let count = cx.count();
        delete_by_selection_insert_mode(
            cx,
            |text, range| {
                let pos = range.cursor(text);
                (pos, graphemes::nth_next_grapheme_boundary(text, pos, count))
            },
            Direction::Forward,
        )
    }

    pub fn delete_word_backward(cx: &mut Context) {
        let count = cx.count();
        delete_by_selection_insert_mode(
            cx,
            |text, range| {
                let anchor = movement::move_prev_word_start(text, *range, count).from();
                let next = Range::new(anchor, range.cursor(text));
                let range = exclude_cursor(text, next, *range);
                (range.from(), range.to())
            },
            Direction::Backward,
        );
    }

    pub fn delete_word_forward(cx: &mut Context) {
        let count = cx.count();
        delete_by_selection_insert_mode(
            cx,
            |text, range| {
                let head = movement::move_next_word_end(text, *range, count).to();
                (range.cursor(text), head)
            },
            Direction::Forward,
        );
    }
}

// Undo / Redo

fn undo(cx: &mut Context) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    for _ in 0..count {
        if !doc.undo(view) {
            cx.editor.set_status("Already at oldest change");
            break;
        }
    }
}

fn redo(cx: &mut Context) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    for _ in 0..count {
        if !doc.redo(view) {
            cx.editor.set_status("Already at newest change");
            break;
        }
    }
}

fn earlier(cx: &mut Context) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    for _ in 0..count {
        // rather than doing in batch we do this so get error halfway
        if !doc.earlier(view, UndoKind::Steps(1)) {
            cx.editor.set_status("Already at oldest change");
            break;
        }
    }
}

fn later(cx: &mut Context) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    for _ in 0..count {
        // rather than doing in batch we do this so get error halfway
        if !doc.later(view, UndoKind::Steps(1)) {
            cx.editor.set_status("Already at newest change");
            break;
        }
    }
}

fn commit_undo_checkpoint(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    doc.append_changes_to_history(view);
}

// Yank / Paste

fn yank(cx: &mut Context) {
    // `None` = the unnamed default; vim distribution then also fills `0`.
    yank_impl(cx.editor, cx.register);
    exit_select_mode(cx);
}

fn yank_to_clipboard(cx: &mut Context) {
    yank_impl(cx.editor, Some('+'));
    exit_select_mode(cx);
}

fn yank_to_primary_clipboard(cx: &mut Context) {
    yank_impl(cx.editor, Some('*'));
    exit_select_mode(cx);
}

fn yank_impl(editor: &mut Editor, register: Option<char>) {
    let default = editor.config().default_yank_register;
    let (view, doc) = current!(editor);
    let (from, to, values) = {
        let text = doc.text().slice(..);
        let primary = doc.selection(view.id).primary();
        let values: Vec<String> = doc
            .selection(view.id)
            .fragments(text)
            .map(Cow::into_owned)
            .collect();
        (primary.from(), primary.to(), values)
    };
    let selections = values.len();
    let reg_display = register.unwrap_or(default);
    // vim: yanking sets the `[`/`]` marks to the start/end of the yanked text.
    doc.set_mark('[', from);
    doc.set_mark(']', to.saturating_sub(1).max(from));

    crate::emacs_kill::record(values.join("\n"));
    // Route through the unnamed default when no register was selected, so vim's
    // yank register `0` and unnamed `"` are populated alongside the target.
    let target = register.filter(|&r| r != default);
    match editor.registers.write_yanked(target, values) {
        Ok(_) => editor.set_status(format!(
            "yanked {selections} selection{} to register {reg_display}",
            if selections == 1 { "" } else { "s" }
        )),
        Err(err) => editor.set_error(err.to_string()),
    }
}

fn yank_joined_impl(editor: &mut Editor, separator: &str, register: char) {
    let (view, doc) = current!(editor);
    let text = doc.text().slice(..);

    let selection = doc.selection(view.id);
    let selections = selection.len();
    let joined = selection
        .fragments(text)
        .fold(String::new(), |mut acc, fragment| {
            if !acc.is_empty() {
                acc.push_str(separator);
            }
            acc.push_str(&fragment);
            acc
        });

    match editor.registers.write(register, vec![joined]) {
        Ok(_) => editor.set_status(format!(
            "joined and yanked {selections} selection{} to register {register}",
            if selections == 1 { "" } else { "s" }
        )),
        Err(err) => editor.set_error(err.to_string()),
    }
}

fn yank_joined(cx: &mut Context) {
    let separator = doc!(cx.editor).line_ending.as_str();
    yank_joined_impl(
        cx.editor,
        separator,
        cx.register
            .unwrap_or(cx.editor.config().default_yank_register),
    );
    exit_select_mode(cx);
}

fn yank_joined_to_clipboard(cx: &mut Context) {
    let line_ending = doc!(cx.editor).line_ending;
    yank_joined_impl(cx.editor, line_ending.as_str(), '+');
    exit_select_mode(cx);
}

fn yank_joined_to_primary_clipboard(cx: &mut Context) {
    let line_ending = doc!(cx.editor).line_ending;
    yank_joined_impl(cx.editor, line_ending.as_str(), '*');
    exit_select_mode(cx);
}

pub(crate) fn yank_main_selection_to_register(editor: &mut Editor, register: char) {
    let (view, doc) = current!(editor);
    let text = doc.text().slice(..);

    let selection = doc.selection(view.id).primary().fragment(text).to_string();

    match editor.registers.write(register, vec![selection]) {
        Ok(_) => editor.set_status(format!("yanked primary selection to register {register}",)),
        Err(err) => editor.set_error(err.to_string()),
    }
}

fn yank_main_selection_to_clipboard(cx: &mut Context) {
    yank_main_selection_to_register(cx.editor, '+');
    exit_select_mode(cx);
}

fn yank_main_selection_to_primary_clipboard(cx: &mut Context) {
    yank_main_selection_to_register(cx.editor, '*');
    exit_select_mode(cx);
}

#[derive(Copy, Clone)]
pub(crate) enum Paste {
    Before,
    After,
    Cursor,
}

static LINE_ENDING_REGEX: Lazy<Regex> = Lazy::new(|| Regex::new(r"\r\n|\r|\n").unwrap());

fn paste_impl(
    values: &[String],
    doc: &mut Document,
    view: &mut View,
    action: Paste,
    count: usize,
    mode: Mode,
) {
    if values.is_empty() {
        return;
    }

    if mode == Mode::Insert {
        doc.append_changes_to_history(view);
    }

    // if any of values ends with a line ending, it's linewise paste
    let linewise = values
        .iter()
        .any(|value| get_line_ending_of_str(value).is_some());

    let map_value = |value| {
        let value = LINE_ENDING_REGEX.replace_all(value, doc.line_ending.as_str());
        let mut out = Tendril::from(value.as_ref());
        for _ in 1..count {
            out.push_str(&value);
        }
        out
    };

    let repeat = std::iter::repeat(
        // `values` is asserted to have at least one entry above.
        map_value(values.last().unwrap()),
    );

    let mut values = values.iter().map(|value| map_value(value)).chain(repeat);

    let text = doc.text();
    let selection = doc.selection(view.id);

    let mut offset = 0;
    let mut ranges = SmallVec::with_capacity(selection.len());

    let mut transaction = Transaction::change_by_selection(text, selection, |range| {
        let pos = match (action, linewise) {
            // paste linewise before
            (Paste::Before, true) => text.line_to_char(text.char_to_line(range.from())),
            // paste linewise after
            (Paste::After, true) => {
                let line = range.line_range(text.slice(..)).1;
                text.line_to_char((line + 1).min(text.len_lines()))
            }
            // paste insert
            (Paste::Before, false) => range.from(),
            // paste append
            (Paste::After, false) => range.to(),
            // paste at cursor
            (Paste::Cursor, _) => range.cursor(text.slice(..)),
        };

        let value = values.next();

        let value_len = value
            .as_ref()
            .map(|content| content.chars().count())
            .unwrap_or_default();
        let anchor = offset + pos;

        // vim-faithful cursor rest in normal mode: a bare cursor with no leftover
        // selection. Charwise paste rests on the last pasted char; linewise paste
        // rests on the first non-blank of the first pasted line.
        let new_range = if mode == Mode::Normal {
            if linewise {
                let nb = value
                    .as_ref()
                    .map(|v| v.chars().take_while(|&c| c == ' ' || c == '\t').count())
                    .unwrap_or(0)
                    .min(value_len.saturating_sub(1));
                Range::point(anchor + nb)
            } else {
                Range::point(anchor + value_len.saturating_sub(1))
            }
        } else {
            Range::new(anchor, anchor + value_len).with_direction(range.direction())
        };
        ranges.push(new_range);
        offset += value_len;

        (pos, pos, value)
    });

    if mode == Mode::Normal {
        transaction = transaction.with_selection(Selection::new(ranges, selection.primary_index()));
    }

    doc.apply(&transaction, view.id);
    doc.append_changes_to_history(view);
}

/// Emacs `yank` (C-y): insert the most-recent kill-ring entry at each cursor
/// and select it, so a following `yank-pop` can swap it for an older kill.
fn yank_from_kill_ring(cx: &mut Context) {
    let Some(text) = crate::emacs_kill::top() else {
        cx.editor.set_error("Kill ring is empty");
        return;
    };
    let count = cx.count();
    let mode = cx.editor.mode;
    let (view, doc) = current!(cx.editor);
    paste_impl(&[text], doc, view, Paste::Before, count, mode);
    let sel: Vec<(usize, usize)> = doc
        .selection(view.id)
        .iter()
        .map(|r| (r.anchor, r.head))
        .collect();
    crate::emacs_kill::begin_yank(sel);
}

/// Emacs `yank-pop` (M-y): replace the just-yanked text with the next-older
/// kill-ring entry, cycling. Only fires while the live selection still covers
/// the previous yank (our stand-in for emacs's last-command-was-yank check).
fn yank_pop(cx: &mut Context) {
    let cur: Vec<(usize, usize)> = {
        let (view, doc) = current!(cx.editor);
        doc.selection(view.id)
            .iter()
            .map(|r| (r.anchor, r.head))
            .collect()
    };
    let Some(entry) = crate::emacs_kill::next_entry(&cur) else {
        cx.editor
            .set_error("Previous command was not a yank — nothing to cycle");
        return;
    };
    let (view, doc) = current!(cx.editor);
    let value = Tendril::from(entry.as_str());
    let value_len = entry.chars().count();
    let selection = doc.selection(view.id).clone();
    let mut offset: isize = 0;
    let mut ranges = SmallVec::with_capacity(selection.len());
    let transaction = Transaction::change_by_selection(doc.text(), &selection, |range| {
        let (from, to) = (range.from(), range.to());
        let anchor = (from as isize + offset) as usize;
        ranges.push(Range::new(anchor, anchor + value_len).with_direction(range.direction()));
        offset += value_len as isize - (to as isize - from as isize);
        (from, to, Some(value.clone()))
    });
    doc.apply(&transaction, view.id);
    doc.set_selection(view.id, Selection::new(ranges, selection.primary_index()));
    doc.append_changes_to_history(view);
    let new_sel: Vec<(usize, usize)> = doc
        .selection(view.id)
        .iter()
        .map(|r| (r.anchor, r.head))
        .collect();
    crate::emacs_kill::set_yank_sel(new_sel);
}

pub(crate) fn paste_bracketed_value(cx: &mut Context, contents: String) {
    let count = cx.count();
    let paste = match cx.editor.mode {
        Mode::Insert | Mode::Select => Paste::Cursor,
        Mode::Normal => Paste::Before,
    };
    let (view, doc) = current!(cx.editor);
    paste_impl(&[contents], doc, view, paste, count, cx.editor.mode);
    exit_select_mode(cx);
}

fn paste_clipboard_after(cx: &mut Context) {
    paste(cx.editor, '+', Paste::After, cx.count());
    exit_select_mode(cx);
}

fn paste_clipboard_before(cx: &mut Context) {
    paste(cx.editor, '+', Paste::Before, cx.count());
    exit_select_mode(cx);
}

fn paste_primary_clipboard_after(cx: &mut Context) {
    paste(cx.editor, '*', Paste::After, cx.count());
    exit_select_mode(cx);
}

fn paste_primary_clipboard_before(cx: &mut Context) {
    paste(cx.editor, '*', Paste::Before, cx.count());
    exit_select_mode(cx);
}

fn replace_with_yanked(cx: &mut Context) {
    replace_selections_with_register(
        cx.editor,
        cx.register
            .unwrap_or(cx.editor.config().default_yank_register),
        cx.count(),
    );
    exit_select_mode(cx);
}

pub(crate) fn replace_selections_with_register(editor: &mut Editor, register: char, count: usize) {
    let Some(values) = editor
        .registers
        .read(register, editor)
        .filter(|values| values.len() > 0)
    else {
        return;
    };
    let scrolloff = editor.config().scrolloff;
    let (view, doc) = current_ref!(editor);

    let map_value = |value: &Cow<str>| {
        let value = LINE_ENDING_REGEX.replace_all(value, doc.line_ending.as_str());
        let mut out = Tendril::from(value.as_ref());
        for _ in 1..count {
            out.push_str(&value);
        }
        out
    };
    let mut values_rev = values.rev().peekable();
    // `values` is asserted to have at least one entry above.
    let last = values_rev.peek().unwrap();
    let repeat = std::iter::repeat(map_value(last));
    let mut values = values_rev
        .rev()
        .map(|value| map_value(&value))
        .chain(repeat);
    let selection = doc.selection(view.id);
    let transaction = Transaction::change_by_selection(doc.text(), selection, |range| {
        if !range.is_empty() {
            (range.from(), range.to(), Some(values.next().unwrap()))
        } else {
            (range.from(), range.to(), None)
        }
    });
    drop(values);

    let (view, doc) = current!(editor);
    doc.apply(&transaction, view.id);
    doc.append_changes_to_history(view);
    view.ensure_cursor_in_view(doc, scrolloff);
}

fn replace_selections_with_clipboard(cx: &mut Context) {
    replace_selections_with_register(cx.editor, '+', cx.count());
    exit_select_mode(cx);
}

fn replace_selections_with_primary_clipboard(cx: &mut Context) {
    replace_selections_with_register(cx.editor, '*', cx.count());
    exit_select_mode(cx);
}

pub(crate) fn paste(editor: &mut Editor, register: char, pos: Paste, count: usize) {
    let Some(values) = editor.registers.read(register, editor) else {
        return;
    };
    let values: Vec<_> = values.map(|value| value.to_string()).collect();

    let (view, doc) = current!(editor);
    paste_impl(&values, doc, view, pos, count, editor.mode);
}

fn paste_after(cx: &mut Context) {
    paste(
        cx.editor,
        cx.register
            .unwrap_or(cx.editor.config().default_yank_register),
        Paste::After,
        cx.count(),
    );
    exit_select_mode(cx);
}

/// Browse the written registers (named registers + yank ring) in a picker and
/// paste the chosen one after the cursor. Backs spacemacs `SPC r r/e/y`.
fn register_picker(cx: &mut Context) {
    struct RegMeta {
        name: char,
        preview: String,
    }

    let items: Vec<RegMeta> = cx
        .editor
        .registers
        .written()
        .into_iter()
        .filter_map(|name| {
            let preview = cx
                .editor
                .registers
                .read(name, cx.editor)?
                .map(|v| v.into_owned())
                .collect::<Vec<_>>()
                .join(" ⏎ ")
                .replace('\n', "⏎");
            (!preview.is_empty()).then_some(RegMeta { name, preview })
        })
        .collect();

    let columns = [
        ui::PickerColumn::new("reg", |m: &RegMeta, _: &()| m.name.to_string().into()),
        ui::PickerColumn::new("contents", |m: &RegMeta, _: &()| m.preview.as_str().into()),
    ];

    let picker = Picker::new(columns, 1, items, (), |cx, meta, _action| {
        paste(cx.editor, meta.name, Paste::After, 1);
    });
    cx.push_layer(Box::new(overlaid(picker)));
}

/// fzf.vim `:Marks` / spacemacs `SPC r m` (helm-mark-ring): fuzzy-pick a vim
/// named mark in the current buffer and jump to it. Marks are stored per-document
/// (`m{a-z}` sets them, plus the auto-marks `.`/`[`/`]`/`^`/`<`/`>`).
fn marks_picker(cx: &mut Context) {
    match build_marks_picker(cx.editor) {
        Some(picker) => cx.push_layer(picker),
        None => cx.editor.set_status("No marks set"),
    }
}

/// Build the marks picker (shared by the static command and `:marks`). `None` when no marks set.
pub(crate) fn build_marks_picker(editor: &mut Editor) -> Option<Box<dyn Component>> {
    struct MarkMeta {
        mark: char,
        doc_id: DocumentId,
        pos: usize,
        line: usize,
        text: String,
    }

    let (_, doc) = current_ref!(editor);
    let doc_id = doc.id();
    let text = doc.text().slice(..);
    let len = text.len_chars();

    let mut items: Vec<MarkMeta> = doc
        .marks_iter()
        .map(|(mark, pos)| {
            let pos = pos.min(len);
            let line = text.char_to_line(pos);
            let contents = text.line(line).to_string();
            MarkMeta {
                mark,
                doc_id,
                pos,
                line,
                text: contents.trim_end().to_string(),
            }
        })
        .collect();
    // letters first, then the structural/auto marks, for a stable, vim-like order
    items.sort_by_key(|m| (!m.mark.is_ascii_alphabetic(), m.mark));

    if items.is_empty() {
        return None;
    }

    let columns = [
        ui::PickerColumn::new("mark", |m: &MarkMeta, _: &()| m.mark.to_string().into()),
        ui::PickerColumn::new("line", |m: &MarkMeta, _: &()| {
            (m.line + 1).to_string().into()
        }),
        ui::PickerColumn::new("text", |m: &MarkMeta, _: &()| m.text.as_str().into()),
    ];

    let picker = Picker::new(columns, 2, items, (), |cx, meta, _action| {
        let (view, doc) = current!(cx.editor);
        push_jump(view, doc);
        let pos = meta.pos.min(doc.text().len_chars());
        doc.set_selection(view.id, Selection::point(pos));
    })
    .with_preview(|_editor, meta| Some((meta.doc_id.into(), Some((meta.line, meta.line)))));
    Some(Box::new(overlaid(picker)))
}

/// JetBrains "View Breakpoints" (SPC d B): a picker over every set breakpoint across all files
/// (file:line + verified/condition/log flags); selecting one jumps to it.
fn dap_breakpoints_picker(cx: &mut Context) {
    struct BpMeta {
        path: PathBuf,
        line: usize,
        verified: bool,
        condition: Option<String>,
        log_message: Option<String>,
    }

    let mut items: Vec<BpMeta> = cx
        .editor
        .breakpoints
        .iter()
        .flat_map(|(path, bps)| {
            bps.iter().map(move |bp| BpMeta {
                path: path.clone(),
                line: bp.line,
                verified: bp.verified,
                condition: bp.condition.clone(),
                log_message: bp.log_message.clone(),
            })
        })
        .collect();
    if items.is_empty() {
        cx.editor.set_status("No breakpoints set");
        return;
    }
    items.sort_by(|a, b| a.path.cmp(&b.path).then(a.line.cmp(&b.line)));

    let columns = [
        ui::PickerColumn::new("file", |m: &BpMeta, _: &()| {
            m.path.to_string_lossy().into_owned().into()
        }),
        ui::PickerColumn::new("line", |m: &BpMeta, _: &()| (m.line + 1).to_string().into()),
        ui::PickerColumn::new("flags", |m: &BpMeta, _: &()| {
            let mut s = String::new();
            if !m.verified {
                s.push('?');
            }
            if m.condition.is_some() {
                s.push('c');
            }
            if m.log_message.is_some() {
                s.push('l');
            }
            s.into()
        }),
        ui::PickerColumn::new("condition", |m: &BpMeta, _: &()| {
            m.condition
                .as_deref()
                .or(m.log_message.as_deref())
                .unwrap_or("")
                .into()
        }),
    ];

    let picker = Picker::new(columns, 0, items, (), |cx, meta, action| {
        if let Err(e) = cx.editor.open(&meta.path, action) {
            cx.editor
                .set_error(format!("Failed to open {}: {e}", meta.path.display()));
            return;
        }
        let (view, doc) = current!(cx.editor);
        push_jump(view, doc);
        let line = meta.line.min(doc.text().len_lines().saturating_sub(1));
        let pos = doc.text().line_to_char(line);
        doc.set_selection(view.id, Selection::point(pos));
    });
    cx.push_layer(Box::new(overlaid(picker)));
}

/// fzf.vim `:BLines`: fuzzy-search every line of the current buffer and jump to
/// the chosen one. (Project-wide line search is `SPC s s` / `global_search`.)
fn buffer_line_picker(cx: &mut Context) {
    struct LineMeta {
        doc_id: DocumentId,
        line: usize,
        pos: usize,
        text: String,
    }

    let (_, doc) = current_ref!(cx.editor);
    let doc_id = doc.id();
    let text = doc.text().slice(..);

    let items: Vec<LineMeta> = text
        .lines()
        .enumerate()
        .map(|(line, slice)| LineMeta {
            doc_id,
            line,
            pos: text.line_to_char(line),
            text: slice.to_string().trim_end().to_string(),
        })
        .collect();

    let columns = [
        ui::PickerColumn::new("line", |m: &LineMeta, _: &()| {
            (m.line + 1).to_string().into()
        }),
        ui::PickerColumn::new("text", |m: &LineMeta, _: &()| m.text.as_str().into()),
    ];

    let picker = Picker::new(columns, 1, items, (), |cx, meta, _action| {
        let (view, doc) = current!(cx.editor);
        push_jump(view, doc);
        let pos = meta.pos.min(doc.text().len_chars());
        doc.set_selection(view.id, Selection::point(pos));
        let config = cx.editor.config();
        let (view, doc) = current!(cx.editor);
        view.ensure_cursor_in_view_center(doc, config.scrolloff);
    })
    .with_preview(|_editor, meta| Some((meta.doc_id.into(), Some((meta.line, meta.line)))));
    cx.push_layer(Box::new(overlaid(picker)));
}

/// fzf.vim `:History:` : fuzzy-pick a past command line (`:` register history)
/// and execute it.
fn command_history_picker(cx: &mut Context) {
    match build_command_history_picker(cx.editor) {
        Some(picker) => cx.push_layer(picker),
        None => cx.editor.set_status("No command-line history"),
    }
}

/// Build the command-history picker (shared by the static command and `:history`). `None` if empty.
pub(crate) fn build_command_history_picker(editor: &mut Editor) -> Option<Box<dyn Component>> {
    let mut items: Vec<String> = editor
        .registers
        .read(':', editor)
        .map(|values| values.map(|v| v.into_owned()).collect())
        .unwrap_or_default();
    items.reverse(); // most-recent first

    if items.is_empty() {
        return None;
    }

    let columns = [ui::PickerColumn::new("command", |cmd: &String, _: &()| {
        cmd.as_str().into()
    })];

    let picker = Picker::new(columns, 0, items, (), |cx, cmd, _action| {
        crate::commands::typed::run_command_line(cx, cmd);
    });
    Some(Box::new(overlaid(picker)))
}

/// fzf.vim `:History/` : fuzzy-pick a past search pattern (`/` register history)
/// and re-run the search.
fn search_history_picker(cx: &mut Context) {
    let mut items: Vec<String> = cx
        .editor
        .registers
        .read('/', cx.editor)
        .map(|values| values.map(|v| v.into_owned()).collect())
        .unwrap_or_default();
    items.reverse(); // most-recent first

    if items.is_empty() {
        cx.editor.set_status("No search history");
        return;
    }

    let columns = [ui::PickerColumn::new("pattern", |p: &String, _: &()| {
        p.as_str().into()
    })];

    let picker = Picker::new(columns, 0, items, (), |cx, query, _action| {
        let _ = cx.editor.registers.write('/', vec![query.clone()]);
        cx.editor.registers.last_search_register = '/';
        let config = cx.editor.config();
        let case_insensitive = config.search.smart_case && !query.chars().any(char::is_uppercase);
        let wrap_around = config.search.wrap_around;
        let scrolloff = config.scrolloff;
        let is_crlf = doc!(cx.editor).line_ending == LineEnding::Crlf;
        if let Ok(regex) = rope::RegexBuilder::new()
            .syntax(
                rope::Config::new()
                    .case_insensitive(case_insensitive)
                    .multi_line(true)
                    .crlf(is_crlf),
            )
            .build(query)
        {
            search_impl(
                cx.editor,
                &regex,
                Movement::Move,
                Direction::Forward,
                scrolloff,
                wrap_around,
                true,
            );
        } else {
            cx.editor.set_error(format!("Invalid regex: {query}"));
        }
    });
    cx.push_layer(Box::new(overlaid(picker)));
}

/// fzf.vim `:BCommits` (current file) / `:Commits` (whole repo), and spacemacs
/// `SPC g f l` (commits log for current file): fuzzy-pick a commit from history.
/// Enter copies the commit hash to the clipboard (there is no commit-diff viewer yet).
fn git_log_picker(cx: &mut Context, current_file_only: bool) {
    let Some(path) = doc!(cx.editor).path().map(|p| p.to_path_buf()) else {
        cx.editor.set_error("Current buffer has no path");
        return;
    };
    let Some(repo_dir) = path.parent().map(|p| p.to_path_buf()) else {
        cx.editor.set_error("File has no parent directory");
        return;
    };

    let trust_full = cx
        .editor
        .workspace_trust
        .query(
            &zemacs_loader::find_workspace_in(&repo_dir).0,
            zemacs_loader::workspace_trust::TrustQuery::Git,
        )
        .is_trusted();

    let file_arg = current_file_only.then(|| path.clone());

    let columns = [
        ui::PickerColumn::new("hash", |c: &CommitInfo, _: &()| c.id.as_str().into()),
        ui::PickerColumn::new("summary", |c: &CommitInfo, _: &()| {
            c.summary.as_str().into()
        }),
        ui::PickerColumn::new("author", |c: &CommitInfo, _: &()| c.author.as_str().into()),
    ];

    let picker = Picker::new(columns, 1, [], (), |cx, commit, _action| {
        let _ = cx.editor.registers.write('+', vec![commit.id.clone()]);
        cx.editor
            .set_status(format!("Copied commit {} to clipboard", commit.id));
    });
    let injector = picker.injector();

    // Walk history on a background thread, streaming commits into the picker.
    cx.editor.diff_providers.clone().for_each_commit(
        repo_dir,
        file_arg,
        trust_full,
        256,
        move |commit| match commit {
            Ok(commit) => injector.push(commit).is_ok(),
            Err(err) => {
                status::report_blocking(err);
                true
            }
        },
    );
    cx.push_layer(Box::new(overlaid(picker)));
}

/// fzf.vim `:BCommits` / spacemacs `SPC g f l`: commit log for the current file.
fn git_file_log_picker(cx: &mut Context) {
    git_log_picker(cx, true);
}

/// fzf.vim `:Commits`: commit log for the whole repository.
fn git_repo_log_picker(cx: &mut Context) {
    git_log_picker(cx, false);
}

/// spacemacs `SPC i u` (helm-unicode): fuzzy-pick a character from the digraph
/// table by its mnemonic / glyph and insert it at the cursor.
fn unicode_picker(cx: &mut Context) {
    struct CharMeta {
        ch: char,
        mnemonic: String,
    }

    let items: Vec<CharMeta> = DIGRAPHS
        .iter()
        .map(|&(a, b, ch)| CharMeta {
            ch,
            mnemonic: format!("{a}{b}"),
        })
        .collect();

    let columns = [
        ui::PickerColumn::new("char", |m: &CharMeta, _: &()| m.ch.to_string().into()),
        ui::PickerColumn::new("mnemonic", |m: &CharMeta, _: &()| {
            m.mnemonic.as_str().into()
        }),
        ui::PickerColumn::new("code", |m: &CharMeta, _: &()| {
            format!("U+{:04X}", m.ch as u32).into()
        }),
    ];

    let picker = Picker::new(columns, 1, items, (), |cx, meta, _action| {
        let mut ctx = Context {
            register: None,
            count: None,
            editor: cx.editor,
            callback: Vec::new(),
            on_next_key_callback: None,
            jobs: cx.jobs,
        };
        insert::insert_char(&mut ctx, meta.ch);
    });
    cx.push_layer(Box::new(overlaid(picker)));
}

/// Fuzzy theme picker with live preview, like vim/fzf.vim `:Colors`. Bound to `SPC T c`.
/// Moving the highlight previews the theme live; Enter commits, Esc reverts.
fn theme_picker(cx: &mut Context) {
    let current = cx.editor.theme.name().to_string();
    let themes = crate::commands::typed::all_theme_names();
    let initial = themes.iter().position(|n| n == &current).unwrap_or(0) as u32;

    let columns = [ui::PickerColumn::new("theme", |name: &String, _: &()| {
        name.as_str().into()
    })];

    let picker = Picker::new(
        columns,
        0,
        themes,
        (),
        |cx, name: &String, _action| match cx.editor.theme_loader.load(name) {
            Ok(theme) => {
                if let Err(err) = cx.editor.set_theme(theme) {
                    cx.editor
                        .set_error(format!("failed to set theme '{name}': {err}"));
                }
            }
            Err(err) => cx
                .editor
                .set_error(format!("failed to load theme '{name}': {err}")),
        },
    )
    .with_initial_cursor(initial)
    // Show the current buffer in the preview pane so you see real code re-themed
    // live as you move through the list (and the picker no longer hides everything).
    .with_preview(|editor, _name: &String| {
        let doc_id = editor.tree.try_get(editor.tree.focus)?.doc;
        Some((doc_id.into(), None))
    })
    .with_on_highlight(|cx, name: Option<&String>| {
        if let Some(name) = name {
            if let Ok(theme) = cx.editor.theme_loader.load(name) {
                let _ = cx.editor.set_theme_preview(theme);
            }
        }
    })
    .with_on_abort(|cx| {
        let _ = cx.editor.unset_theme_preview();
    });

    cx.push_layer(Box::new(overlaid(picker)));
}

fn paste_before(cx: &mut Context) {
    paste(
        cx.editor,
        cx.register
            .unwrap_or(cx.editor.config().default_yank_register),
        Paste::Before,
        cx.count(),
    );
    exit_select_mode(cx);
}

fn get_lines(doc: &Document, view_id: ViewId) -> Vec<usize> {
    let mut lines = Vec::new();

    // Get all line numbers
    for range in doc.selection(view_id) {
        let (start, end) = range.line_range(doc.text().slice(..));

        for line in start..=end {
            lines.push(line)
        }
    }
    lines.sort_unstable(); // sorting by usize so _unstable is preferred
    lines.dedup();
    lines
}

fn indent(cx: &mut Context) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    let lines = get_lines(doc, view.id);

    // Indent by one level
    let indent = Tendril::from(doc.indent_style.as_str().repeat(count));

    let transaction = Transaction::change(
        doc.text(),
        lines.into_iter().filter_map(|line| {
            let is_blank = doc.text().line(line).chunks().all(|s| s.trim().is_empty());
            if is_blank {
                return None;
            }
            let pos = doc.text().line_to_char(line);

            let indent = if let IndentStyle::Spaces(indent_width) = doc.indent_style {
                let line = doc.text().line(line);
                let offset = line.first_non_whitespace_char().unwrap_or(0) % indent_width as usize;
                indent.clone().split_off(offset)
            } else {
                indent.clone()
            };

            Some((pos, pos, Some(indent)))
        }),
    );
    doc.apply(&transaction, view.id);
    exit_select_mode(cx);
}

fn unindent(cx: &mut Context) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    let lines = get_lines(doc, view.id);
    let mut changes = Vec::with_capacity(lines.len());
    let tab_width = doc.tab_width();
    let indent_width = count * doc.indent_width();

    for line_idx in lines {
        let line = doc.text().line(line_idx);
        let mut width = 0;
        let mut pos = 0;

        for ch in line.chars() {
            match ch {
                ' ' => width += 1,
                '\t' => width = (width / tab_width + 1) * tab_width,
                _ => break,
            }

            pos += 1;

            if width >= indent_width {
                break;
            }
        }

        // now delete from start to first non-blank
        if pos > 0 {
            let start = doc.text().line_to_char(line_idx);
            changes.push((start, start + pos, None))
        }
    }

    let transaction = Transaction::change(doc.text(), changes.into_iter());

    doc.apply(&transaction, view.id);
    exit_select_mode(cx);
}

fn format_selections(cx: &mut Context) {
    use zemacs_lsp::{lsp, util::range_to_lsp_range};

    let (view, doc) = current!(cx.editor);
    let view_id = view.id;

    // via lsp if available
    // TODO: else via tree-sitter indentation calculations

    if doc.selection(view_id).len() != 1 {
        cx.editor
            .set_error("format_selections only supports a single selection for now");
        return;
    }

    // TODO extra LanguageServerFeature::FormatSelections?
    // maybe such that LanguageServerFeature::Format contains it as well
    let Some(language_server) = doc
        .language_servers_with_feature(LanguageServerFeature::Format)
        .find(|ls| {
            matches!(
                ls.capabilities().document_range_formatting_provider,
                Some(lsp::OneOf::Left(true) | lsp::OneOf::Right(_))
            )
        })
    else {
        cx.editor
            .set_error("No configured language server supports range formatting");
        return;
    };

    let offset_encoding = language_server.offset_encoding();
    let ranges: Vec<lsp::Range> = doc
        .selection(view_id)
        .iter()
        .map(|range| range_to_lsp_range(doc.text(), *range, offset_encoding))
        .collect();

    // TODO: handle fails
    // TODO: concurrent map over all ranges

    let range = ranges[0];

    let future = language_server
        .text_document_range_formatting(
            doc.identifier(),
            range,
            lsp::FormattingOptions {
                tab_size: doc.tab_width() as u32,
                insert_spaces: matches!(doc.indent_style, IndentStyle::Spaces(_)),
                ..Default::default()
            },
            None,
        )
        .unwrap();

    let text = doc.text().clone();
    let doc_id = doc.id();
    let doc_version = doc.version();

    tokio::spawn(async move {
        match future.await {
            Ok(Some(res)) => {
                let transaction =
                    zemacs_lsp::util::generate_transaction_from_edits(&text, res, offset_encoding);
                job::dispatch(move |editor, _compositor| {
                    let Some(doc) = editor.document_mut(doc_id) else {
                        return;
                    };
                    // Updating a desynced document causes problems with applying the transaction
                    if doc.version() != doc_version {
                        return;
                    }
                    doc.apply(&transaction, view_id);
                })
                .await
            }
            Err(err) => log::error!("format sections failed: {err}"),
            Ok(None) => (),
        }
    });
}

fn join_selections_impl(cx: &mut Context, select_space: bool) {
    use movement::skip_while;
    let loader = cx.editor.syn_loader.load();
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);

    let mut changes = Vec::new();

    for selection in doc.selection(view.id) {
        let (start, mut end) = selection.line_range(slice);
        if start == end {
            end = (end + 1).min(text.len_lines() - 1);
        }
        let lines = start..end;

        changes.reserve(lines.len());

        // Strip the comment leader of joined lines using the comment tokens of the layer at this selection.
        let byte = slice.char_to_byte(slice.line_to_char(start));
        let comment_tokens = doc
            .language_config_at(&loader, byte)
            .and_then(|config| config.comment_tokens.as_deref())
            .unwrap_or(&[]);
        // Sort by length to handle Rust's /// vs //
        let mut comment_tokens: Vec<&str> = comment_tokens.iter().map(|x| x.as_str()).collect();
        comment_tokens.sort_unstable_by_key(|x| std::cmp::Reverse(x.len()));

        let first_line_idx = slice.line_to_char(start);
        let first_line_idx = skip_while(slice, first_line_idx, |ch| matches!(ch, ' ' | '\t'))
            .unwrap_or(first_line_idx);
        let first_line = slice.slice(first_line_idx..);
        let mut current_comment_token = comment_tokens
            .iter()
            .find(|token| first_line.starts_with(token));

        for line in lines {
            let start = line_end_char_index(&slice, line);
            let mut end = text.line_to_char(line + 1);
            end = skip_while(slice, end, |ch| matches!(ch, ' ' | '\t')).unwrap_or(end);
            let slice_from_end = slice.slice(end..);
            if let Some(token) = comment_tokens
                .iter()
                .find(|token| slice_from_end.starts_with(token))
            {
                if Some(token) == current_comment_token {
                    end += token.chars().count();
                    end = skip_while(slice, end, |ch| matches!(ch, ' ' | '\t')).unwrap_or(end);
                } else {
                    // update current token, but don't delete this one.
                    current_comment_token = Some(token);
                }
            }

            let separator = if end == line_end_char_index(&slice, line + 1) {
                // the joining line contains only space-characters => don't include a whitespace when joining
                None
            } else {
                Some(Tendril::from(" "))
            };
            changes.push((start, end, separator));
        }
    }

    // nothing to do, bail out early to avoid crashes later
    if changes.is_empty() {
        return;
    }

    changes.sort_unstable_by_key(|(from, _to, _text)| *from);
    changes.dedup();

    // select inserted spaces
    let transaction = if select_space {
        let mut offset: usize = 0;
        let ranges: SmallVec<_> = changes
            .iter()
            .filter_map(|change| {
                if change.2.is_some() {
                    let range = Range::point(change.0 - offset);
                    offset += change.1 - change.0 - 1; // -1 adjusts for the replacement of the range by a space
                    Some(range)
                } else {
                    offset += change.1 - change.0;
                    None
                }
            })
            .collect();
        let t = Transaction::change(text, changes.into_iter());
        if ranges.is_empty() {
            t
        } else {
            let selection = Selection::new(ranges, 0);
            t.with_selection(selection)
        }
    } else {
        Transaction::change(text, changes.into_iter())
    };

    doc.apply(&transaction, view.id);
}

fn keep_or_remove_selections_impl(cx: &mut Context, remove: bool) {
    // keep or remove selections matching regex
    let reg = cx.register.unwrap_or('/');
    ui::regex_prompt(
        cx,
        if remove { "remove:" } else { "keep:" }.into(),
        Some(reg),
        ui::completers::none,
        move |cx, regex, event| {
            let (view, doc) = current!(cx.editor);
            if !matches!(event, PromptEvent::Update | PromptEvent::Validate) {
                return;
            }
            let text = doc.text().slice(..);

            if let Some(selection) =
                selection::keep_or_remove_matches(text, doc.selection(view.id), &regex, remove)
            {
                doc.set_selection(view.id, selection);
            } else if event == PromptEvent::Validate {
                cx.editor.set_error("no selections remaining");
            }
        },
    )
}

fn join_selections(cx: &mut Context) {
    join_selections_impl(cx, false)
}

fn join_selections_space(cx: &mut Context) {
    join_selections_impl(cx, true)
}

/// vim `~`: toggle the case of `count` characters starting under the cursor
/// (bounded to the current line), then advance the cursor past the toggled run.
fn switch_case_forward(cx: &mut Context) {
    let count = cx.count();
    {
        let (view, doc) = current!(cx.editor);
        let text = doc.text().slice(..);
        let extended = doc.selection(view.id).clone().transform(|range| {
            let cursor = range.cursor(text);
            let line = text.char_to_line(cursor);
            let line_end = line_end_char_index(&text, line);
            let to = graphemes::nth_next_grapheme_boundary(text, cursor, count).min(line_end);
            Range::new(cursor, to.max(cursor))
        });
        doc.set_selection(view.id, extended);
    }
    switch_case(cx);
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);
    let advanced = doc.selection(view.id).clone().transform(|range| {
        let line = text.char_to_line(range.from());
        let line_start = text.line_to_char(line);
        let line_end = line_end_char_index(&text, line);
        let cursor = if range.to() < line_end {
            range.to()
        } else {
            graphemes::prev_grapheme_boundary(text, line_end).max(line_start)
        };
        Range::point(cursor)
    });
    doc.set_selection(view.id, advanced);
}

/// vim `x`: delete `count` characters starting under the cursor, bounded to the
/// current line (never deletes the trailing newline).
fn delete_chars_forward_vim(cx: &mut Context) {
    let count = cx.count();
    {
        let (view, doc) = current!(cx.editor);
        let text = doc.text().slice(..);
        let extended = doc.selection(view.id).clone().transform(|range| {
            let cursor = range.cursor(text);
            let line = text.char_to_line(cursor);
            let line_end = line_end_char_index(&text, line);
            let to = graphemes::nth_next_grapheme_boundary(text, cursor, count).min(line_end);
            Range::new(cursor, to.max(cursor))
        });
        doc.set_selection(view.id, extended);
    }
    delete_selection(cx);
}

/// vim `X`: delete `count` characters before the cursor, bounded to the start of
/// the current line (a no-op at column 0 — never joins with the previous line).
fn delete_chars_backward_vim(cx: &mut Context) {
    let count = cx.count();
    {
        let (view, doc) = current!(cx.editor);
        let text = doc.text().slice(..);
        let extended = doc.selection(view.id).clone().transform(|range| {
            let cursor = range.cursor(text);
            let line = text.char_to_line(cursor);
            let line_start = text.line_to_char(line);
            let from = graphemes::nth_prev_grapheme_boundary(text, cursor, count).max(line_start);
            Range::new(from, cursor)
        });
        doc.set_selection(view.id, extended);
    }
    delete_selection(cx);
}

/// Shared implementation of vim `J` (with a separating space) and `gJ` (raw).
/// Joins `count` lines (minimum two) below each cursor and leaves the cursor on
/// the join, matching vim.
fn join_lines_below_vim(cx: &mut Context, space: bool) {
    use movement::skip_while;
    let count = cx.count();
    // Number of line breaks to remove: bare `J`/`2J` join two lines (one break),
    // `3J` joins three (two breaks), etc.
    let joins = count.saturating_sub(1).max(1);

    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let last_line = slice.len_lines().saturating_sub(1);

    let mut changes: Vec<(usize, usize, Option<Tendril>)> = Vec::new();
    for range in doc.selection(view.id).iter() {
        let base = range.cursor_line(slice);
        for k in 0..joins {
            let line = base + k;
            if line >= last_line {
                break;
            }
            let start = line_end_char_index(&slice, line);
            let mut end = slice.line_to_char(line + 1);
            let separator = if space {
                // vim `J` strips the joined line's leading whitespace and inserts a
                // single space, except when the joined line is blank.
                end = skip_while(slice, end, |ch| matches!(ch, ' ' | '\t')).unwrap_or(end);
                if end == line_end_char_index(&slice, line + 1) {
                    None
                } else {
                    Some(Tendril::from(" "))
                }
            } else {
                // vim `gJ` removes only the newline, preserving all whitespace.
                None
            };
            changes.push((start, end, separator));
        }
    }

    if changes.is_empty() {
        return;
    }
    changes.sort_unstable_by_key(|(from, _, _)| *from);
    changes.dedup();

    // Leave a bare cursor at each join point.
    let mut offset = 0usize;
    let ranges: SmallVec<[Range; 1]> = changes
        .iter()
        .map(|(from, to, sep)| {
            let sep_len = sep.as_ref().map(|t| t.chars().count()).unwrap_or(0);
            let r = Range::point(from.saturating_sub(offset));
            offset += (to - from).saturating_sub(sep_len);
            r
        })
        .collect();

    let transaction =
        Transaction::change(text, changes.into_iter()).with_selection(Selection::new(ranges, 0));
    doc.apply(&transaction, view.id);
}

fn join_lines_vim(cx: &mut Context) {
    join_lines_below_vim(cx, true)
}

fn join_lines_vim_nospace(cx: &mut Context) {
    join_lines_below_vim(cx, false)
}

fn keep_selections(cx: &mut Context) {
    keep_or_remove_selections_impl(cx, false)
}

fn remove_selections(cx: &mut Context) {
    keep_or_remove_selections_impl(cx, true)
}

fn keep_primary_selection(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    // TODO: handle count

    let range = doc.selection(view.id).primary();
    doc.set_selection(view.id, Selection::single(range.anchor, range.head));
}

fn remove_primary_selection(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    // TODO: handle count

    let selection = doc.selection(view.id);
    if selection.len() == 1 {
        cx.editor.set_error("no selections remaining");
        return;
    }
    let index = selection.primary_index();
    let selection = selection.clone().remove(index);

    doc.set_selection(view.id, selection);
}

pub fn completion(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let range = doc.selection(view.id).primary();
    let text = doc.text().slice(..);
    let cursor = range.cursor(text);

    cx.editor
        .handlers
        .trigger_completions(cursor, doc.id(), view.id);
}

// comments
type CommentTransactionFn = fn(
    line_token: Option<&str>,
    block_tokens: Option<&[BlockCommentToken]>,
    doc: &Rope,
    selection: &Selection,
) -> Transaction;

fn toggle_comments_impl(cx: &mut Context, comment_transaction: CommentTransactionFn) {
    apply_comment_transaction(cx.editor, comment_transaction);
    exit_select_mode(cx);
}

/// Resolve the comment tokens for the cursor's enclosing language layer, build the transaction
/// via `comment_transaction`, and apply it to the current selection. Operates on `&mut Editor`
/// alone so it can run from a prompt callback (where no full `Context` is available).
fn apply_comment_transaction(editor: &mut Editor, comment_transaction: CommentTransactionFn) {
    let loader: &zemacs_core::syntax::Loader = &editor.syn_loader.load();
    let (view, doc) = current!(editor);
    let cursor = doc
        .selection(view.id)
        .primary()
        .cursor(doc.text().slice(..));
    let byte_pos = doc.text().char_to_byte(cursor);
    // Resolve the comment tokens from the enclosing injection layer that owns the comment,
    // not the innermost layer at the cursor. Prefer the innermost layer that defines
    // *line* comment tokens, falling back to the innermost layer with block tokens.
    let mut line_layer = None;
    let mut block_layer = None;
    if let Some(syntax) = doc.syntax() {
        for layer in syntax.layers_for_byte_range(byte_pos as u32, byte_pos as u32) {
            let language = syntax.layer(layer).language;
            let config = loader.language(language).config();
            if config.comment_tokens.is_some() {
                line_layer = Some(language);
            }
            if config.block_comment_tokens.is_some() {
                block_layer = Some(language);
            }
        }
    }
    let lang_config = line_layer
        .or(block_layer)
        .map(|language| &**loader.language(language).config())
        .or_else(|| doc.language_config());

    // Pick the token the cursor's line is already commented with (longest match, so `///` wins over `//`).
    // If the line isn't commented yet, fall back to the primary token for adding a comment.
    let cursor_line = doc.text().char_to_line(cursor);
    let line_token: Option<&str> = lang_config
        .and_then(|lc| lc.comment_tokens.as_ref())
        .and_then(|tokens| {
            comment::get_comment_token(doc.text().slice(..), tokens, cursor_line)
                .or_else(|| tokens.first().map(|token| token.as_str()))
        });
    let block_tokens: Option<&[BlockCommentToken]> = lang_config
        .and_then(|lc| lc.block_comment_tokens.as_ref())
        .map(|tc| &tc[..]);

    let transaction =
        comment_transaction(line_token, block_tokens, doc.text(), doc.selection(view.id));

    doc.apply(&transaction, view.id);
}

/// commenting behavior:
/// 1. only line comment tokens -> line comment
/// 2. each line block commented -> uncomment all lines
/// 3. whole selection block commented -> uncomment selection
/// 4. all lines not commented and block tokens -> comment uncommented lines
/// 5. no comment tokens and not block commented -> line comment
fn toggle_comments(cx: &mut Context) {
    toggle_comments_impl(cx, |line_token, block_tokens, doc, selection| {
        let text = doc.slice(..);

        // only have line comment tokens
        if line_token.is_some() && block_tokens.is_none() {
            return comment::toggle_line_comments(doc, selection, line_token);
        }

        let split_lines = comment::split_lines_of_selection(text, selection);

        let default_block_tokens = &[BlockCommentToken::default()];
        let block_comment_tokens = block_tokens.unwrap_or(default_block_tokens);

        let (line_commented, line_comment_changes) =
            comment::find_block_comments(block_comment_tokens, text, &split_lines);

        // block commented by line would also be block commented so check this first
        if line_commented {
            return comment::create_block_comment_transaction(
                doc,
                &split_lines,
                line_commented,
                line_comment_changes,
            )
            .0;
        }

        let (block_commented, comment_changes) =
            comment::find_block_comments(block_comment_tokens, text, selection);

        // check if selection has block comments
        if block_commented {
            return comment::create_block_comment_transaction(
                doc,
                selection,
                block_commented,
                comment_changes,
            )
            .0;
        }

        // not commented and only have block comment tokens
        if line_token.is_none() && block_tokens.is_some() {
            return comment::create_block_comment_transaction(
                doc,
                &split_lines,
                line_commented,
                line_comment_changes,
            )
            .0;
        }

        // not block commented at all and don't have any tokens
        comment::toggle_line_comments(doc, selection, line_token)
    })
}

/// Comment the range of lines between the cursor's line and `target_line` (0-based, clamped to the
/// buffer). When `invert`, each line is toggled independently (Spacemacs
/// `evilnc-invert-comment-line-by-line`); otherwise the whole range shares one decision
/// (`evilnc-comment-or-uncomment-to-the-line`).
fn comment_line_range(editor: &mut Editor, target_line: usize, invert: bool) {
    {
        let (view, doc) = current!(editor);
        let text = doc.text();
        let slice = text.slice(..);
        let cursor = doc.selection(view.id).primary().cursor(slice);
        let cur_line = text.char_to_line(cursor);
        let last = text.len_lines().saturating_sub(1);
        let target = target_line.min(last);
        let (lo, hi) = if cur_line <= target {
            (cur_line, target)
        } else {
            (target, cur_line)
        };
        let start = text.line_to_char(lo);
        let end = (text.line_to_char(hi) + text.line(hi).len_chars()).min(text.len_chars());
        doc.set_selection(view.id, Selection::single(start, end));
    }
    if invert {
        apply_comment_transaction(editor, |line_token, _block_tokens, doc, selection| {
            comment::invert_line_comments(doc, selection, line_token)
        });
    } else {
        apply_comment_transaction(editor, |line_token, _block_tokens, doc, selection| {
            comment::toggle_line_comments(doc, selection, line_token)
        });
    }
}

/// Prompt for a 1-based target line (or take a count prefix) and comment the range from the
/// cursor's line to it; `invert` toggles each line independently.
fn comment_to_line_prompt(cx: &mut Context, invert: bool) {
    let cur_line = {
        let (view, doc) = current!(cx.editor);
        let slice = doc.text().slice(..);
        doc.text()
            .char_to_line(doc.selection(view.id).primary().cursor(slice))
            + 1
    };
    if let Some(count) = cx.count {
        comment_line_range(cx.editor, count.get().saturating_sub(1), invert);
        return;
    }
    let label = if invert {
        format!("Invert comment to line (cursor at {cur_line}): ")
    } else {
        format!("Comment to line (cursor at {cur_line}): ")
    };
    let prompt = crate::ui::prompt::Prompt::new(
        label.into(),
        None,
        ui::completers::none,
        move |cx: &mut crate::compositor::Context, input: &str, event: PromptEvent| {
            if event != PromptEvent::Validate {
                return;
            }
            match input.trim().parse::<usize>() {
                Ok(n) if n >= 1 => comment_line_range(cx.editor, n - 1, invert),
                _ => cx
                    .editor
                    .set_error("comment to line: enter a 1-based line number"),
            }
        },
    );
    cx.push_layer(Box::new(prompt));
}

/// SPC c t : line-comment the range from the cursor to a prompted line (uniform).
fn comment_to_line(cx: &mut Context) {
    comment_to_line_prompt(cx, false);
}

/// SPC c T : invert (per-line toggle) comments over the range from the cursor to a prompted line.
fn invert_comment_to_line(cx: &mut Context) {
    comment_to_line_prompt(cx, true);
}

fn toggle_line_comments(cx: &mut Context) {
    toggle_comments_impl(cx, |line_token, block_tokens, doc, selection| {
        if line_token.is_none() && block_tokens.is_some() {
            let default_block_tokens = &[BlockCommentToken::default()];
            let block_comment_tokens = block_tokens.unwrap_or(default_block_tokens);
            comment::toggle_block_comments(
                doc,
                &comment::split_lines_of_selection(doc.slice(..), selection),
                block_comment_tokens,
            )
        } else {
            comment::toggle_line_comments(doc, selection, line_token)
        }
    });
}

fn toggle_block_comments(cx: &mut Context) {
    toggle_comments_impl(cx, |line_token, block_tokens, doc, selection| {
        if line_token.is_some() && block_tokens.is_none() {
            comment::toggle_line_comments(doc, selection, line_token)
        } else {
            let default_block_tokens = &[BlockCommentToken::default()];
            let block_comment_tokens = block_tokens.unwrap_or(default_block_tokens);
            comment::toggle_block_comments(doc, selection, block_comment_tokens)
        }
    });
}

/// Byte offset within `line` where a line comment begins, scanning left to right
/// while skipping `"`- and `'`-delimited string literals (honouring `\` escapes)
/// so a comment leader inside a string is not mistaken for a comment. Returns
/// `None` when the line carries no comment. `tokens` are the language's
/// line-comment leaders; the first that matches at a position wins.
fn comment_start_in_line(line: &str, tokens: &[&str]) -> Option<usize> {
    let mut chars = line.char_indices();
    let mut in_str: Option<char> = None;
    while let Some((i, c)) = chars.next() {
        match in_str {
            Some(quote) => {
                if c == '\\' {
                    chars.next(); // skip the escaped character
                } else if c == quote {
                    in_str = None;
                }
            }
            None => {
                if c == '"' || c == '\'' {
                    in_str = Some(c);
                } else if tokens
                    .iter()
                    .any(|t| !t.is_empty() && line[i..].starts_with(t))
                {
                    return Some(i);
                }
            }
        }
    }
    None
}

/// Char range of the comment on `line` (including the whitespace immediately
/// before the comment leader, matching Emacs' `skip-syntax-backward " "`), or
/// `None` when the line has no comment. Prefers a tree-sitter `comment` node;
/// falls back to a string-aware scan for the language's line-comment token.
fn line_comment_span(
    doc: &Document,
    loader: &zemacs_core::syntax::Loader,
    line: usize,
) -> Option<(usize, usize)> {
    let slice = doc.text().slice(..);
    if line >= slice.len_lines() {
        return None;
    }
    let line_start = slice.line_to_char(line);
    let line_end = line_end_char_index(&slice, line);
    if line_end <= line_start {
        return None;
    }

    // 1) tree-sitter comment node overlapping this line.
    let mut comment_from: Option<usize> = None;
    if let Some(syntax) = doc.syntax() {
        let mut ch = line_start;
        while ch < line_end {
            let byte = slice.char_to_byte(ch) as u32;
            if let Some(node) = syntax.descendant_for_byte_range(byte, byte) {
                if node.kind().contains("comment") {
                    let start = slice.byte_to_char(node.byte_range().start as usize);
                    comment_from = Some(start.max(line_start));
                    break;
                }
            }
            ch += 1;
        }
    }

    // 2) fallback: scan for the language's line-comment token outside strings.
    if comment_from.is_none() {
        let byte = slice.char_to_byte(line_start);
        let tokens = doc
            .language_config_at(loader, byte)
            .and_then(|c| c.comment_tokens.as_deref())
            .unwrap_or(&[]);
        if !tokens.is_empty() {
            let toks: Vec<&str> = tokens.iter().map(String::as_str).collect();
            let content = slice.slice(line_start..line_end).to_string();
            if let Some(off) = comment_start_in_line(&content, &toks) {
                let col = content[..off].chars().count();
                comment_from = Some(line_start + col);
            }
        }
    }

    let mut from = comment_from?;
    // Absorb the whitespace immediately preceding the comment leader.
    while from > line_start && matches!(slice.char(from - 1), ' ' | '\t') {
        from -= 1;
    }
    Some((from, line_end))
}

/// Emacs `comment-kill` (`M-x comment-kill`): kill the comment on the current
/// line, saving it to the kill ring. With a count, kill comments on that many
/// lines starting with the current one (Emacs' prefix-ARG behaviour).
fn comment_kill(cx: &mut Context) {
    let count = cx.count();
    let loader = cx.editor.syn_loader.load();
    let (spans, killed) = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        let cursor = doc.selection(view.id).primary().cursor(slice);
        let start_line = slice.char_to_line(cursor);
        let last_line = (start_line + count - 1).min(slice.len_lines().saturating_sub(1));
        let mut spans: Vec<(usize, usize)> = Vec::new();
        for line in start_line..=last_line {
            if let Some((from, to)) = line_comment_span(doc, &loader, line) {
                if to > from {
                    spans.push((from, to));
                }
            }
        }
        let killed = spans
            .iter()
            .map(|&(f, t)| slice.slice(f..t).to_string())
            .collect::<Vec<_>>()
            .join("\n");
        (spans, killed)
    };
    if spans.is_empty() {
        cx.editor.set_status("no comment on this line");
        return;
    }
    crate::emacs_kill::record(killed);
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(doc.text(), spans.into_iter().map(|(f, t)| (f, t, None)));
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
}

/// Tab-expanded indentation column of a line plus the char offset of its first
/// non-whitespace char (emacs `current-indentation` + `skip-chars-forward
/// " \t"`). If the line is blank, the returned offset equals `line_end`.
fn code_indent_leading(
    text: RopeSlice,
    line_start: usize,
    line_end: usize,
    tab_width: usize,
) -> (usize, usize) {
    let mut col = 0usize;
    let mut idx = line_start;
    while idx < line_end {
        match text.char(idx) {
            ' ' => col += 1,
            '\t' => col += tab_width - (col % tab_width),
            _ => break,
        }
        idx += 1;
    }
    (col, idx)
}

/// Build whitespace reaching column `col`, honoring the buffer's indent style
/// (emacs `indent-to`): tabs (then a spaces remainder) when `indent-tabs-mode`,
/// otherwise all spaces.
fn code_indent_string(col: usize, style: IndentStyle, tab_width: usize) -> String {
    match style {
        IndentStyle::Tabs if tab_width > 0 => {
            let tabs = col / tab_width;
            let spaces = col % tab_width;
            let mut s = String::with_capacity(tabs + spaces);
            s.push_str(&"\t".repeat(tabs));
            s.push_str(&" ".repeat(spaces));
            s
        }
        _ => " ".repeat(col),
    }
}

/// The first line-start at/after `top` that a region-of-lines command touches:
/// a `top` mid-line skips that partial first line (emacs `(or (bolp)
/// (forward-line 1))`).
fn code_region_first_line_start(text: RopeSlice, top: usize) -> usize {
    let top = top.min(text.len_chars());
    let line = text.char_to_line(top);
    let bol = text.line_to_char(line);
    if top == bol {
        top
    } else {
        let next = line + 1;
        if next < text.len_lines() {
            text.line_to_char(next)
        } else {
            text.len_chars()
        }
    }
}

/// Emacs `indent-code-rigidly` (`= r`): shift every line whose start lies in the
/// region sideways by `arg` columns, leaving lines that *begin* inside a string
/// untouched (its distinction from plain `indent-rigidly`). The in-string test
/// reuses the tree-sitter node at the line start, exactly as `line_comment_span`
/// classifies comment nodes. Blank lines lose their leading whitespace and are
/// not re-indented, matching the `(or (eolp) (indent-to …))` guard in indent.el.
fn indent_code_rigidly(cx: &mut Context) {
    let arg = cx.count() as isize; // columns to shift right (prefix arg)
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);
    let tab_width = doc.tab_width();
    let style = doc.indent_style;
    let sel = doc.selection(view.id).primary();
    let (top, end) = (sel.from(), sel.to());
    let start = code_region_first_line_start(text, top);
    if start >= end {
        return;
    }
    let start_line = text.char_to_line(start);
    // `end` may fall mid-line; a line is processed when its start is < end.
    let last_line = text.char_to_line(end.saturating_sub(1));

    let mut changes: Vec<(usize, usize, Option<Tendril>)> = Vec::new();
    for line in start_line..=last_line.min(text.len_lines().saturating_sub(1)) {
        let line_start = text.line_to_char(line);
        if line_start >= end {
            break;
        }
        // Skip lines that begin inside a string literal (tree-sitter node kind).
        if let Some(syntax) = doc.syntax() {
            let byte = text.char_to_byte(line_start) as u32;
            if let Some(node) = syntax.descendant_for_byte_range(byte, byte) {
                if node.kind().contains("string") {
                    continue;
                }
            }
        }
        let line_end = line_end_char_index(&text, line);
        let (col, first_non_ws) = code_indent_leading(text, line_start, line_end, tab_width);
        // Blank line: strip leading whitespace, do not re-indent.
        let new_indent = if first_non_ws >= line_end {
            String::new()
        } else {
            code_indent_string((col as isize + arg).max(0) as usize, style, tab_width)
        };
        let old_text = text.slice(line_start..first_non_ws).to_string();
        if old_text == new_indent {
            continue;
        }
        let replacement = (!new_indent.is_empty()).then(|| Tendril::from(new_indent));
        changes.push((line_start, first_non_ws, replacement));
    }

    if changes.is_empty() {
        return;
    }
    let tx = Transaction::change(doc.text(), changes.into_iter());
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
}

/// The char range emacs `c-hungry-delete` removes at `idx`. When `forward`, it
/// skips whitespace toward the end of `chars`; otherwise toward the start.
/// Faithful to cc-cmds.el: `c-skip-ws-{forward,backward}` then, if that moved,
/// `delete-region` over the skipped run — otherwise `c-{delete,backspace}-function`
/// removes a single character. Whitespace is the syntax-whitespace class, which
/// includes newlines; `char::is_whitespace` is the matching predicate. Returns
/// `None` only at the buffer edge, where there is nothing to delete.
///
/// The command below scans the rope directly with the same `is_whitespace`
/// predicate rather than materializing a char vector; this pure form mirrors it
/// for unit testing (the same split the `horizontal_space_run` pair uses).
#[cfg(test)]
fn hungry_delete_range(chars: &[char], idx: usize, forward: bool) -> Option<(usize, usize)> {
    let idx = idx.min(chars.len());
    if forward {
        let mut end = idx;
        while end < chars.len() && chars[end].is_whitespace() {
            end += 1;
        }
        if end != idx {
            Some((idx, end))
        } else if idx < chars.len() {
            Some((idx, idx + 1))
        } else {
            None
        }
    } else {
        let mut start = idx;
        while start > 0 && chars[start - 1].is_whitespace() {
            start -= 1;
        }
        if start != idx {
            Some((start, idx))
        } else if idx > 0 {
            Some((idx - 1, idx))
        } else {
            None
        }
    }
}

/// emacs `c-hungry-delete-forward`: delete all whitespace after point up to the
/// next non-whitespace character, or a single character if none follows.
fn c_hungry_delete_forward(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let slice = doc.text().slice(..);
    let cursor = doc.selection(view.id).primary().cursor(slice);
    let len = slice.len_chars();
    let mut end = cursor;
    while end < len && slice.char(end).is_whitespace() {
        end += 1;
    }
    let (from, to) = if end != cursor {
        (cursor, end)
    } else if cursor < len {
        (cursor, cursor + 1)
    } else {
        return;
    };
    let transaction = Transaction::change(doc.text(), std::iter::once((from, to, None)));
    doc.apply(&transaction, view.id);
    doc.set_selection(view.id, Selection::point(from));
    doc.append_changes_to_history(view);
}

/// emacs `c-hungry-delete-backwards`: delete all whitespace before point back to
/// the previous non-whitespace character, or a single character if none precedes.
fn c_hungry_delete_backwards(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let slice = doc.text().slice(..);
    let cursor = doc.selection(view.id).primary().cursor(slice);
    let mut start = cursor;
    while start > 0 && slice.char(start - 1).is_whitespace() {
        start -= 1;
    }
    let (from, to) = if start != cursor {
        (start, cursor)
    } else if cursor > 0 {
        (cursor - 1, cursor)
    } else {
        return;
    };
    let transaction = Transaction::change(doc.text(), std::iter::once((from, to, None)));
    doc.apply(&transaction, view.id);
    doc.set_selection(view.id, Selection::point(from));
    doc.append_changes_to_history(view);
}

// ---------------------------------------------------------------------------
// C-mode (cc-mode) motion / indent / fill commands. Pure preprocessor-
// conditional matching, comment fill, backslash alignment and statement motion
// live in `zemacs_core::cmode`; these wrappers apply them to the buffer, plus
// tree-sitter defun motion and reindentation.
// ---------------------------------------------------------------------------

/// The tree-sitter "function" text object around the primary selection, as
/// `(view_id, from, to)`, or `None` when there is no parsed function at point.
fn c_function_object(cx: &mut Context) -> Option<(ViewId, usize, usize)> {
    let count = cx.count();
    let loader = cx.editor.syn_loader.load();
    let (view, doc) = current_ref!(cx.editor);
    let slice = doc.text().slice(..);
    let range = doc.selection(view.id).primary();
    doc.syntax().and_then(|syntax| {
        let obj = textobject::textobject_treesitter(
            slice,
            range,
            textobject::TextObject::Around,
            "function",
            syntax,
            &loader,
            count,
        );
        (obj.from() != obj.to()).then_some((view.id, obj.from(), obj.to()))
    })
}

/// Emacs `c-beginning-of-defun`: move point to the start of the function at
/// point, using the tree-sitter `function` text object.
fn c_beginning_of_defun(cx: &mut Context) {
    match c_function_object(cx) {
        Some((vid, from, _to)) => {
            let (_view, doc) = current!(cx.editor);
            let len = doc.text().len_chars();
            doc.set_selection(vid, Selection::point(from.min(len)));
        }
        None => cx
            .editor
            .set_status("c-beginning-of-defun: no function at point (needs a parsed syntax tree)"),
    }
}

/// Emacs `c-end-of-defun`: move point to the end of the function at point.
fn c_end_of_defun(cx: &mut Context) {
    match c_function_object(cx) {
        Some((vid, _from, to)) => {
            let (_view, doc) = current!(cx.editor);
            let len = doc.text().len_chars();
            doc.set_selection(vid, Selection::point(to.min(len)));
        }
        None => cx
            .editor
            .set_status("c-end-of-defun: no function at point (needs a parsed syntax tree)"),
    }
}

/// Emacs `c-mark-function`: select the whole function around point.
fn c_mark_function(cx: &mut Context) {
    match c_function_object(cx) {
        Some((vid, from, to)) => {
            let (_view, doc) = current!(cx.editor);
            let len = doc.text().len_chars();
            doc.set_selection(vid, Selection::single(to.min(len), from.min(len)));
        }
        None => cx
            .editor
            .set_status("c-mark-function: no function at point (needs a parsed syntax tree)"),
    }
}

/// Emacs `c-beginning-of-statement`: move to the start of the C statement at
/// point (brace/`;`-delimited; see `zemacs_core::cmode::beginning_of_statement`).
fn c_beginning_of_statement(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let cursor = doc.selection(view.id).primary().cursor(slice);
    let s = text.to_string();
    let pos = zemacs_core::cmode::beginning_of_statement(&s, cursor);
    doc.set_selection(view.id, Selection::point(pos.min(text.len_chars())));
}

/// Emacs `c-end-of-statement`: move just past the end of the C statement at
/// point.
fn c_end_of_statement(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let cursor = doc.selection(view.id).primary().cursor(slice);
    let s = text.to_string();
    let pos = zemacs_core::cmode::end_of_statement(&s, cursor);
    doc.set_selection(view.id, Selection::point(pos.min(text.len_chars())));
}

/// Move point to the line chosen by a `zemacs_core::cmode` conditional motion,
/// then to the first non-whitespace character of that line (or report `what`).
fn c_conditional_motion(cx: &mut Context, f: impl Fn(&[&str], usize) -> Option<usize>, what: &str) {
    let target = {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text();
        let slice = text.slice(..);
        let cursor = doc.selection(view.id).primary().cursor(slice);
        let cur_line = slice.char_to_line(cursor);
        let content = text.to_string();
        let lines: Vec<&str> = content.lines().collect();
        f(&lines, cur_line)
    };
    match target {
        Some(line) => {
            let (view, doc) = current!(cx.editor);
            let text = doc.text();
            let line = line.min(text.len_lines().saturating_sub(1));
            let start = text.line_to_char(line);
            let first = text
                .line(line)
                .first_non_whitespace_char()
                .map(|c| start + c)
                .unwrap_or(start);
            doc.set_selection(view.id, Selection::point(first.min(text.len_chars())));
        }
        None => cx.editor.set_status(format!("No {what}")),
    }
}

/// Emacs `c-forward-conditional` (C-c C-n): move forward across the following
/// preprocessor conditional.
fn c_forward_conditional(cx: &mut Context) {
    c_conditional_motion(
        cx,
        zemacs_core::cmode::forward_conditional,
        "following conditional",
    );
}

/// Emacs `c-backward-conditional` (C-c C-p): move backward across the preceding
/// preprocessor conditional.
fn c_backward_conditional(cx: &mut Context) {
    c_conditional_motion(
        cx,
        zemacs_core::cmode::backward_conditional,
        "preceding conditional",
    );
}

/// Emacs `c-up-conditional` (C-c C-u): move up out of the containing
/// preprocessor conditional. Honours a numeric prefix for the number of levels.
fn c_up_conditional(cx: &mut Context) {
    let count = cx.count();
    c_conditional_motion(
        cx,
        move |lines, cur| zemacs_core::cmode::up_conditional(lines, cur, count),
        "containing conditional",
    );
}

/// Re-indent the buffer lines in `[start_line, end_line]` to their tree-sitter
/// indentation, rewriting each line's leading whitespace. Returns the number of
/// lines changed. A no-op when there is no syntax tree / indent query.
fn c_reindent_lines(cx: &mut Context, start_line: usize, end_line: usize) -> usize {
    let config = cx.editor.config();
    let loader = cx.editor.syn_loader.load();
    let (view, doc) = current!(cx.editor);
    if doc.syntax().is_none() {
        return 0;
    }
    let text = doc.text().clone();
    let slice = text.slice(..);
    let tab_width = doc.tab_width();
    let end_line = end_line.min(text.len_lines().saturating_sub(1));
    let mut changes: Vec<(usize, usize, Option<Tendril>)> = Vec::new();
    for line in start_line..=end_line {
        let line_start = text.line_to_char(line);
        let first = slice.line(line).first_non_whitespace_char();
        // Skip blank lines (nothing to align).
        let Some(first) = first else { continue };
        let line_before = line.saturating_sub(1);
        let before_end = line_end_char_index(&slice, line_before);
        let indent = zemacs_core::indent::indent_for_newline(
            &loader,
            doc.syntax(),
            &config.indent_heuristic,
            &doc.indent_style,
            tab_width,
            slice,
            line_before,
            before_end,
            line,
        );
        let old = slice.slice(line_start..line_start + first).to_string();
        if old != indent {
            changes.push((
                line_start,
                line_start + first,
                Some(Tendril::from(indent.as_str())),
            ));
        }
    }
    let n = changes.len();
    if n > 0 {
        let tx = Transaction::change(doc.text(), changes.into_iter());
        doc.apply(&tx, view.id);
        doc.append_changes_to_history(view);
    }
    n
}

/// Emacs `c-indent-line-or-region`: re-indent the current line, or every line
/// touched by the selection when it spans more than one line.
fn c_indent_line_or_region(cx: &mut Context) {
    let (start_line, end_line) = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        doc.selection(view.id).primary().line_range(slice)
    };
    c_reindent_lines(cx, start_line, end_line);
}

/// Emacs `c-indent-defun`: re-indent every line of the function at point.
fn c_indent_defun(cx: &mut Context) {
    let range = c_function_object(cx).map(|(_v, from, to)| {
        let (_view, doc) = current_ref!(cx.editor);
        let text = doc.text();
        (
            text.char_to_line(from),
            text.char_to_line(to.saturating_sub(1).max(from)),
        )
    });
    match range {
        Some((start, end)) => {
            c_reindent_lines(cx, start, end);
        }
        None => cx
            .editor
            .set_status("c-indent-defun: no function at point (needs a parsed syntax tree)"),
    }
}

/// Emacs `c-ts-mode-indent-defun`: re-indent the whole function at point using
/// the tree-sitter indent query (the `c-ts-mode` equivalent of
/// [`c_indent_defun`]).
fn c_ts_mode_indent_defun(cx: &mut Context) {
    c_indent_defun(cx);
}

/// Emacs `c-indent-exp`: re-indent the balanced brace expression starting at
/// point (the lines from the opening `{` through its matching `}`).
fn c_indent_exp(cx: &mut Context) {
    let range = {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text();
        let slice = text.slice(..);
        let cursor = doc.selection(view.id).primary().cursor(slice);
        // Find the next opening brace at/after point, then its match.
        let s = text.to_string();
        let chars: Vec<char> = s.chars().collect();
        let mut open = cursor;
        while open < chars.len() && chars[open] != '{' {
            open += 1;
        }
        if open >= chars.len() {
            None
        } else {
            let mut depth = 0i32;
            let mut close = open;
            for (i, c) in chars.iter().enumerate().skip(open) {
                match c {
                    '{' => depth += 1,
                    '}' => {
                        depth -= 1;
                        if depth == 0 {
                            close = i;
                            break;
                        }
                    }
                    _ => {}
                }
            }
            Some((text.char_to_line(open), text.char_to_line(close)))
        }
    };
    match range {
        Some((start, end)) => {
            c_reindent_lines(cx, start, end);
        }
        None => cx
            .editor
            .set_status("c-indent-exp: no brace expression at point"),
    }
}

/// The contiguous run of comment lines around `line` sharing its comment style
/// (`//` line comments, or block-comment body lines beginning with `*`).
/// Returns the inclusive `(start_line, end_line)` range, or `None` when `line`
/// is not a fillable comment line.
fn c_comment_block_range(text: &Rope, line: usize) -> Option<(usize, usize)> {
    let is_fillable = |l: usize| -> bool {
        let s = text.line(l).to_string();
        let t = s.trim_start();
        t.starts_with("//") || t.starts_with('*')
    };
    if !is_fillable(line) {
        return None;
    }
    let mut start = line;
    while start > 0 && is_fillable(start - 1) {
        start -= 1;
    }
    let mut end = line;
    while end + 1 < text.len_lines() && is_fillable(end + 1) {
        end += 1;
    }
    Some((start, end))
}

/// Emacs `c-fill-paragraph` (M-q): fill the comment block around point,
/// rewrapping its text to `text-width` and reusing the block's `//` or `*`
/// prefix. Only fills comment blocks; outside a comment it does nothing.
fn c_fill_paragraph(cx: &mut Context) {
    let width = {
        let w = cx.editor.config().text_width;
        if w == 0 {
            70
        } else {
            w
        }
    };
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let cursor = doc.selection(view.id).primary().cursor(slice);
    let cur_line = slice.char_to_line(cursor);
    let Some((start, end)) = c_comment_block_range(text, cur_line) else {
        cx.editor.set_status("c-fill-paragraph: not in a comment");
        return;
    };
    let region_start = text.line_to_char(start);
    let region_end = text.line_to_char((end + 1).min(text.len_lines()));
    let region = text.slice(region_start..region_end).to_string();
    let had_trailing_nl = region.ends_with('\n');
    let lines: Vec<&str> = region.lines().collect();
    let out = zemacs_core::cmode::fill_c_comment(&lines, width);
    let le = doc.line_ending.as_str();
    let mut replacement = out.join(le);
    if had_trailing_nl {
        replacement.push_str(le);
    }
    if replacement == region {
        return;
    }
    let tx = Transaction::change(
        text,
        std::iter::once((region_start, region_end, Some(replacement.into()))),
    );
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
}

/// Emacs `c-backslash-region`: align the trailing `\` line continuations in the
/// selected lines to a common column. With a numeric prefix (count > 1) the
/// backslashes are removed instead.
fn c_backslash_region(cx: &mut Context) {
    let remove = cx.count() > 1;
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let (start_line, end_line) = doc.selection(view.id).primary().line_range(slice);
    let region_start = text.line_to_char(start_line);
    let region_end = text.line_to_char((end_line + 1).min(text.len_lines()));
    let region = text.slice(region_start..region_end).to_string();
    let had_trailing_nl = region.ends_with('\n');
    let lines: Vec<&str> = region.lines().collect();
    let out = if remove {
        zemacs_core::cmode::remove_backslashes(&lines)
    } else {
        let col = zemacs_core::cmode::backslash_column(&lines);
        zemacs_core::cmode::align_backslashes(&lines, col)
    };
    let le = doc.line_ending.as_str();
    let mut replacement = out.join(le);
    if had_trailing_nl {
        replacement.push_str(le);
    }
    if replacement == region {
        return;
    }
    let tx = Transaction::change(
        text,
        std::iter::once((region_start, region_end, Some(replacement.into()))),
    );
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
}

/// Emacs `c-context-line-break`: break the line at point. Inside a `//` or `*`
/// comment it continues the comment prefix; inside a multi-line macro it appends
/// a `\` continuation to the current line before the break; otherwise it is a
/// plain newline that keeps the current indentation.
fn c_context_line_break(cx: &mut Context) {
    enter_insert_mode(cx);
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let cursor = doc.selection(view.id).primary().cursor(slice);
    let line = slice.char_to_line(cursor);
    let line_start = text.line_to_char(line);
    let line_str = text.line(line).to_string();
    let le = doc.line_ending.as_str().to_string();

    let content = text.to_string();
    let all_lines: Vec<&str> = content.lines().collect();
    let in_macro = zemacs_core::cmode::in_cpp_macro(&all_lines, line);

    // Comment continuation prefix, if any.
    let comment_prefix = zemacs_core::cmode::comment_continuation_prefix(&line_str);

    let mut insert = String::new();
    if in_macro {
        // Pad to a single space and append the backslash continuation before
        // breaking, matching cc-mode's macro line-break.
        insert.push_str(" \\");
    }
    insert.push_str(&le);
    if let Some(prefix) = comment_prefix {
        insert.push_str(&prefix);
    } else {
        // Keep the current line's indentation.
        let indent_end = text.line(line).first_non_whitespace_char().unwrap_or(0);
        insert.push_str(&text.slice(line_start..line_start + indent_end).to_string());
    }
    let new_cursor = cursor + insert.chars().count();
    let tx = Transaction::change(text, std::iter::once((cursor, cursor, Some(insert.into()))));
    doc.apply(&tx, view.id);
    doc.set_selection(
        view.id,
        Selection::point(new_cursor.min(doc.text().len_chars())),
    );
    doc.append_changes_to_history(view);
}

/// Toggle flags for the C-mode electric/auto-newline/hungry states. zemacs has
/// no live cc-mode electric machinery, so these track the flag and report it
/// (partial), mirroring `nroff-electric-mode`.
static C_AUTO_NEWLINE: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(false);
/// Tracks the C-mode hungry-delete state toggle (flag only).
static C_HUNGRY_STATE: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(false);
/// Tracks the C-mode electric state toggle (flag only).
static C_ELECTRIC_STATE: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(true);

/// Emacs `c-toggle-auto-newline` (partial): toggle the auto-newline flag. There
/// is no live electric insertion, so this only records and reports the state.
fn c_toggle_auto_newline(cx: &mut Context) {
    use std::sync::atomic::Ordering;
    let on = !C_AUTO_NEWLINE.fetch_xor(true, Ordering::Relaxed);
    cx.editor.set_status(format!(
        "c-toggle-auto-newline: {} (flag only)",
        if on { "on" } else { "off" }
    ));
}

/// Emacs `c-toggle-hungry-state` (partial): toggle the hungry-delete flag. The
/// `c-hungry-delete-*` commands work explicitly regardless of this flag.
fn c_toggle_hungry_state(cx: &mut Context) {
    use std::sync::atomic::Ordering;
    let on = !C_HUNGRY_STATE.fetch_xor(true, Ordering::Relaxed);
    cx.editor.set_status(format!(
        "c-toggle-hungry-state: {} (flag only)",
        if on { "on" } else { "off" }
    ));
}

/// Emacs `c-toggle-electric-state` (partial): toggle the electric flag.
fn c_toggle_electric_state(cx: &mut Context) {
    use std::sync::atomic::Ordering;
    let on = !C_ELECTRIC_STATE.fetch_xor(true, Ordering::Relaxed);
    cx.editor.set_status(format!(
        "c-toggle-electric-state: {} (flag only)",
        if on { "on" } else { "off" }
    ));
}

/// Emacs `c-show-syntactic-information` (C-c C-s): report the tree-sitter node
/// kind at point and the enclosing node stack, in lieu of cc-mode's syntactic
/// analysis symbols.
fn c_show_syntactic_information(cx: &mut Context) {
    let (view, doc) = current_ref!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let cursor = doc.selection(view.id).primary().cursor(slice);
    let scopes = zemacs_core::indent::get_scopes(doc.syntax(), slice, cursor);
    if scopes.is_empty() {
        cx.editor
            .set_status("c-show-syntactic-information: no syntax tree at point");
        return;
    }
    let innermost = scopes.last().copied().unwrap_or("?");
    cx.editor
        .set_status(format!("syntactic: {innermost}  [{}]", scopes.join(" > ")));
}

/// Emacs `c-macro-expand` (partial): expand the preprocessor over the selected
/// region by shelling out to `cpp`, showing the result in a scratch buffer.
/// Requires a `cpp` on PATH; there is no in-process preprocessor.
fn c_macro_expand(cx: &mut Context) {
    let region = {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text();
        let slice = text.slice(..);
        let sel = doc.selection(view.id).primary();
        let (from, to) = (sel.from(), sel.to());
        if from == to {
            text.to_string()
        } else {
            slice.slice(from..to).to_string()
        }
    };
    let mut child = match std::process::Command::new("cpp")
        .arg("-P")
        .stdin(std::process::Stdio::piped())
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::null())
        .spawn()
    {
        Ok(c) => c,
        Err(_) => {
            cx.editor
                .set_error("c-macro-expand: `cpp` not found on PATH");
            return;
        }
    };
    if let Some(mut stdin) = child.stdin.take() {
        use std::io::Write;
        let _ = stdin.write_all(region.as_bytes());
    }
    match child.wait_with_output() {
        Ok(out) if out.status.success() => {
            let content = String::from_utf8_lossy(&out.stdout).into_owned();
            show_text_in_scratch(cx.editor, &content);
            cx.editor.set_status("c-macro-expand: expanded via cpp");
        }
        _ => cx.editor.set_error("c-macro-expand: cpp failed"),
    }
}

/// Emacs `c-set-style` (partial): zemacs has no cc-mode style engine, so this
/// reports the current tree-sitter indentation style/width instead of selecting
/// a named cc-mode style.
fn c_set_style(cx: &mut Context) {
    let (_view, doc) = current_ref!(cx.editor);
    let style = doc.indent_style.as_str();
    let width = doc.indent_width();
    let kind = if style == "\t" { "tabs" } else { "spaces" };
    cx.editor.set_status(format!(
        "c-set-style: indent = {kind}, width {width} (no cc-mode style engine)"
    ));
}

fn rotate_selections(cx: &mut Context, direction: Direction) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    let mut selection = doc.selection(view.id).clone();
    let index = selection.primary_index();
    let len = selection.len();
    selection.set_primary_index(match direction {
        Direction::Forward => (index + count) % len,
        Direction::Backward => (index + (len.saturating_sub(count) % len)) % len,
    });
    doc.set_selection(view.id, selection);
}
fn rotate_selections_forward(cx: &mut Context) {
    rotate_selections(cx, Direction::Forward)
}
fn rotate_selections_backward(cx: &mut Context) {
    rotate_selections(cx, Direction::Backward)
}

fn rotate_selections_first(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let mut selection = doc.selection(view.id).clone();
    selection.set_primary_index(0);
    doc.set_selection(view.id, selection);
}

fn rotate_selections_last(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let mut selection = doc.selection(view.id).clone();
    let len = selection.len();
    selection.set_primary_index(len - 1);
    doc.set_selection(view.id, selection);
}

#[derive(Debug)]
enum ReorderStrategy {
    RotateForward,
    RotateBackward,
    Reverse,
}

fn reorder_selection_contents(cx: &mut Context, strategy: ReorderStrategy) {
    let count = cx.count;
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);

    let selection = doc.selection(view.id);

    let mut ranges: Vec<_> = selection
        .slices(text)
        .map(|fragment| fragment.chunks().collect())
        .collect();

    let rotate_by = count.map_or(1, |count| count.get().min(ranges.len()));

    let primary_index = match strategy {
        ReorderStrategy::RotateForward => {
            ranges.rotate_right(rotate_by);
            // Like `usize::wrapping_add`, but provide a custom range from `0` to `ranges.len()`
            (selection.primary_index() + ranges.len() + rotate_by) % ranges.len()
        }
        ReorderStrategy::RotateBackward => {
            ranges.rotate_left(rotate_by);
            // Like `usize::wrapping_sub`, but provide a custom range from `0` to `ranges.len()`
            (selection.primary_index() + ranges.len() - rotate_by) % ranges.len()
        }
        ReorderStrategy::Reverse => {
            if rotate_by.is_multiple_of(2) {
                // nothing changed, if we reverse something an even
                // amount of times, the output will be the same
                return;
            }
            ranges.reverse();
            // -1 to turn 1-based len into 0-based index
            (ranges.len() - 1) - selection.primary_index()
        }
    };

    let transaction = Transaction::change(
        doc.text(),
        selection
            .ranges()
            .iter()
            .zip(ranges)
            .map(|(range, fragment)| (range.from(), range.to(), Some(fragment))),
    );

    doc.set_selection(
        view.id,
        Selection::new(selection.ranges().into(), primary_index),
    );
    doc.apply(&transaction, view.id);
}

fn rotate_selection_contents_forward(cx: &mut Context) {
    reorder_selection_contents(cx, ReorderStrategy::RotateForward)
}
fn rotate_selection_contents_backward(cx: &mut Context) {
    reorder_selection_contents(cx, ReorderStrategy::RotateBackward)
}
fn reverse_selection_contents(cx: &mut Context) {
    reorder_selection_contents(cx, ReorderStrategy::Reverse)
}

// tree sitter node selection

fn expand_selection(cx: &mut Context) {
    let motion = |editor: &mut Editor| {
        let (view, doc) = current!(editor);

        if let Some(syntax) = doc.syntax() {
            let text = doc.text().slice(..);

            let current_selection = doc.selection(view.id);
            let selection = object::expand_selection(syntax, text, current_selection.clone());

            // check if selection is different from the last one
            if *current_selection != selection {
                // save current selection so it can be restored using shrink_selection
                view.object_selections.push(current_selection.clone());

                doc.set_selection(view.id, selection);
            }
        }
    };
    cx.editor.apply_motion(motion);
}

fn shrink_selection(cx: &mut Context) {
    let motion = |editor: &mut Editor| {
        let (view, doc) = current!(editor);
        let current_selection = doc.selection(view.id);
        // try to restore previous selection
        if let Some(prev_selection) = view.object_selections.pop() {
            if current_selection.contains(&prev_selection) {
                doc.set_selection(view.id, prev_selection);
                return;
            } else {
                // clear existing selection as they can't be shrunk to anyway
                view.object_selections.clear();
            }
        }
        // if not previous selection, shrink to first child
        if let Some(syntax) = doc.syntax() {
            let text = doc.text().slice(..);
            let selection = object::shrink_selection(syntax, text, current_selection.clone());
            doc.set_selection(view.id, selection);
        }
    };
    cx.editor.apply_motion(motion);
}

/// Returns true if `outer` fully contains `inner` and is strictly larger than
/// it (i.e. they are not equal). Direction is ignored; only the covered span
/// (`from()`..`to()`) matters.
fn wildfire_range_strictly_contains(outer: Range, inner: Range) -> bool {
    outer.from() <= inner.from()
        && outer.to() >= inner.to()
        && (outer.from() < inner.from() || outer.to() > inner.to())
}

/// Compute the wildfire target for a single range.
///
/// * With `count > 1` we jump directly to the Nth closest enclosing pair's
///   inside (like the count-aware text-object commands).
/// * With `count == 1` (a plain `<Enter>`) we must grow *strictly*: because
///   `find_nth_closest_pairs_pos` on a range that is already a pair's inside
///   can return that very same pair, we retry with an increasing `skip`
///   (Nth-closest) until the result strictly contains the current range. If no
///   larger enclosing object exists, the range is returned unchanged.
fn wildfire_grow_range(
    syntax: Option<&Syntax>,
    slice: RopeSlice,
    range: Range,
    count: usize,
) -> Range {
    use textobject::{textobject_pair_surround_closest, TextObject};

    if count > 1 {
        return textobject_pair_surround_closest(syntax, slice, range, TextObject::Inside, count);
    }

    // Grow strictly: try successively larger enclosing pairs.
    let mut last: Option<Range> = None;
    let mut skip = 1usize;
    // Bound the search so a pathological document can never spin forever.
    while skip <= 64 {
        let candidate =
            textobject_pair_surround_closest(syntax, slice, range, TextObject::Inside, skip);
        if wildfire_range_strictly_contains(candidate, range) {
            return candidate;
        }
        // `textobject_pair_surround_closest` returns the input range unchanged
        // when no pair is found, so once the candidate stops changing there is
        // no larger object to grow into.
        if last == Some(candidate) {
            break;
        }
        last = Some(candidate);
        skip += 1;
    }
    range
}

/// Wildfire: select / expand to the closest enclosing text object.
///
/// Each plain `<Enter>` grows the selection to the inside of the next-larger
/// enclosing pair (quote/paren/bracket/brace/tag). `N<Enter>` jumps straight to
/// the Nth closest. The previous selection is pushed onto the per-view
/// `object_selections` stack so `wildfire_shrink` (`<BS>`) can restore it.
fn wildfire(cx: &mut Context) {
    let count = cx.count();
    let motion = move |editor: &mut Editor| {
        let (view, doc) = current!(editor);
        let text = doc.text().slice(..);
        let current_selection = doc.selection(view.id).clone();
        let new_selection = current_selection
            .clone()
            .transform(|range| wildfire_grow_range(doc.syntax(), text, range, count));

        // Only record / apply when something actually changed, so that a
        // no-op `<Enter>` (no larger object) doesn't pollute the shrink stack.
        if new_selection != current_selection {
            view.object_selections.push(current_selection);
            doc.set_selection(view.id, new_selection);
        }
    };
    cx.editor.apply_motion(motion);
}

/// Wildfire: shrink to the previously selected (smaller) text object.
///
/// Pops the per-view `object_selections` stack (shared with `expand_selection`
/// / `shrink_selection`) and restores the previous selection. No-op when the
/// stack is empty.
fn wildfire_shrink(cx: &mut Context) {
    let motion = |editor: &mut Editor| {
        let (view, doc) = current!(editor);
        let current_selection = doc.selection(view.id);
        if let Some(prev_selection) = view.object_selections.pop() {
            if current_selection.contains(&prev_selection) {
                doc.set_selection(view.id, prev_selection);
            } else {
                // The stack no longer matches the current selection; drop it so
                // a later expand starts fresh.
                view.object_selections.clear();
            }
        }
    };
    cx.editor.apply_motion(motion);
}

fn select_sibling_impl<F>(cx: &mut Context, sibling_fn: F)
where
    F: Fn(&zemacs_core::Syntax, RopeSlice, Selection) -> Selection + 'static,
{
    let motion = move |editor: &mut Editor| {
        let (view, doc) = current!(editor);

        if let Some(syntax) = doc.syntax() {
            let text = doc.text().slice(..);
            let current_selection = doc.selection(view.id);
            let selection = sibling_fn(syntax, text, current_selection.clone());
            doc.set_selection(view.id, selection);
        }
    };
    cx.editor.apply_motion(motion);
}

fn select_next_sibling(cx: &mut Context) {
    select_sibling_impl(cx, object::select_next_sibling)
}

fn select_prev_sibling(cx: &mut Context) {
    select_sibling_impl(cx, object::select_prev_sibling)
}

/// Surround each selection with parentheses (paredit-style `wrap`). An empty
/// selection produces `()` with the cursor between the parens.
fn wrap_sexp(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let selection = doc.selection(view.id);
    let transaction = Transaction::change_by_selection(text, selection, |range| {
        let from = range.from();
        let to = range.to();
        let wrapped = format!("({})", slice.slice(from..to));
        (from, to, Some(wrapped.into()))
    });
    doc.apply(&transaction, view.id);
}

fn move_node_bound_impl(cx: &mut Context, dir: Direction, movement: Movement) {
    let motion = move |editor: &mut Editor| {
        let (view, doc) = current!(editor);

        if let Some(syntax) = doc.syntax() {
            let text = doc.text().slice(..);
            let current_selection = doc.selection(view.id);

            let selection = movement::move_parent_node_end(
                syntax,
                text,
                current_selection.clone(),
                dir,
                movement,
            );

            doc.set_selection(view.id, selection);
        }
    };

    cx.editor.apply_motion(motion);
}

pub fn move_parent_node_end(cx: &mut Context) {
    move_node_bound_impl(cx, Direction::Forward, Movement::Move)
}

pub fn move_parent_node_start(cx: &mut Context) {
    move_node_bound_impl(cx, Direction::Backward, Movement::Move)
}

pub fn extend_parent_node_end(cx: &mut Context) {
    move_node_bound_impl(cx, Direction::Forward, Movement::Extend)
}

pub fn extend_parent_node_start(cx: &mut Context) {
    move_node_bound_impl(cx, Direction::Backward, Movement::Extend)
}

fn select_all_impl<F>(editor: &mut Editor, select_fn: F)
where
    F: Fn(&Syntax, RopeSlice, Selection) -> Selection,
{
    let (view, doc) = current!(editor);

    if let Some(syntax) = doc.syntax() {
        let text = doc.text().slice(..);
        let current_selection = doc.selection(view.id);
        let selection = select_fn(syntax, text, current_selection.clone());
        doc.set_selection(view.id, selection);
    }
}

fn select_all_siblings(cx: &mut Context) {
    let motion = |editor: &mut Editor| {
        select_all_impl(editor, object::select_all_siblings);
    };

    cx.editor.apply_motion(motion);
}

fn select_all_children(cx: &mut Context) {
    let motion = |editor: &mut Editor| {
        select_all_impl(editor, object::select_all_children);
    };

    cx.editor.apply_motion(motion);
}

// vim `%`: with no count, match the bracket under the cursor; with a count,
// `{count}%` jumps to {count} percent through the file, on the first non-blank.
fn match_brackets_or_goto_percent(cx: &mut Context) {
    let Some(count) = cx.count else {
        match_brackets(cx);
        return;
    };
    let is_select = cx.editor.mode == Mode::Select;
    {
        let (view, doc) = current!(cx.editor);
        push_jump(view, doc);
        let text = doc.text().slice(..);
        // Effective line count excludes a phantom trailing empty line so the
        // percentage matches vim's "number-of-lines".
        let lines = if text.line(text.len_lines() - 1).len_chars() == 0 {
            text.len_lines().saturating_sub(1)
        } else {
            text.len_lines()
        };
        // vim formula: ({count} * number-of-lines + 99) / 100
        let line = (count.get().saturating_mul(lines).saturating_add(99) / 100)
            .saturating_sub(1)
            .min(lines.saturating_sub(1));
        let pos = text.line_to_char(line);
        let selection = doc
            .selection(view.id)
            .clone()
            .transform(|range| range.put_cursor(text, pos, is_select));
        doc.set_selection(view.id, selection);
    }
    goto_first_nonwhitespace(cx);
}

fn match_brackets(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let is_select = cx.editor.mode == Mode::Select;
    let text = doc.text();
    let text_slice = text.slice(..);

    let selection = doc.selection(view.id).clone().transform(|range| {
        let pos = range.cursor(text_slice);
        if let Some(matched_pos) = doc.syntax().map_or_else(
            || match_brackets::find_matching_bracket_plaintext(text.slice(..), pos),
            |syntax| match_brackets::find_matching_bracket_fuzzy(syntax, text.slice(..), pos),
        ) {
            range.put_cursor(text_slice, matched_pos, is_select)
        } else {
            range
        }
    });

    doc.set_selection(view.id, selection);
}

//

fn jump_forward(cx: &mut Context) {
    cx.editor.jump_forward(cx.editor.tree.focus, cx.count());
}

fn jump_backward(cx: &mut Context) {
    cx.editor.jump_backward(cx.editor.tree.focus, cx.count());
}

fn save_selection(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    push_jump(view, doc);
    cx.editor.set_status("Selection saved to jumplist");
}

fn rotate_view(cx: &mut Context) {
    cx.editor.focus_next()
}

fn rotate_view_reverse(cx: &mut Context) {
    cx.editor.focus_prev()
}

/// Scroll the *other* window without leaving the current one — Emacs
/// `scroll-other-window` (C-M-v, `Forward`) and `scroll-other-window-down`
/// (C-M-S-v, `Backward`). Scrolls by a near-full screen (window height minus two
/// context lines), matching Emacs.
fn scroll_other_window_impl(cx: &mut Context, direction: Direction) {
    if cx.editor.tree.views().count() < 2 {
        cx.editor.set_status("no other window to scroll");
        return;
    }
    let orig = cx.editor.tree.focus;
    let other = cx.editor.tree.next();
    if other == orig {
        cx.editor.set_status("no other window to scroll");
        return;
    }
    // Retarget `current!` to the other view directly (a lightweight ViewId swap,
    // avoiding the side effects of `Editor::focus` — mode reset, history commit,
    // focus-lost dispatch), scroll its viewport, then restore focus. `scroll`
    // with `sync_cursor = false` moves only the view offset, not the cursor.
    cx.editor.tree.focus = other;
    let offset = {
        let (view, _doc) = current_ref!(cx.editor);
        view.inner_height().saturating_sub(2).max(1)
    };
    scroll(cx, offset, direction, false);
    cx.editor.tree.focus = orig;
}

fn scroll_other_window(cx: &mut Context) {
    scroll_other_window_impl(cx, Direction::Forward);
}

fn scroll_other_window_down(cx: &mut Context) {
    scroll_other_window_impl(cx, Direction::Backward);
}

/// Recenter point in the *other* window without leaving the current one — Emacs
/// `recenter-other-window` (C-M-S-l). Faithful to lisp/window.el, which runs
/// `recenter-top-bottom` in `other-window-for-scrolling`; zemacs's C-l recenter
/// is `align_view` `Center`, so this centers the other view on its cursor. Uses
/// the same lightweight `tree.focus` retarget as `scroll_other_window` (avoiding
/// the side effects of `Editor::focus`) and restores focus afterward.
fn recenter_other_window(cx: &mut Context) {
    if cx.editor.tree.views().count() < 2 {
        cx.editor.set_status("no other window to recenter");
        return;
    }
    let orig = cx.editor.tree.focus;
    let other = cx.editor.tree.next();
    if other == orig {
        cx.editor.set_status("no other window to recenter");
        return;
    }
    cx.editor.tree.focus = other;
    {
        let (view, doc) = current!(cx.editor);
        align_view(doc, view, Align::Center);
    }
    cx.editor.tree.focus = orig;
}

fn jump_view_right(cx: &mut Context) {
    cx.editor.focus_direction(tree::Direction::Right)
}

fn jump_view_left(cx: &mut Context) {
    cx.editor.focus_direction(tree::Direction::Left)
}

fn jump_view_up(cx: &mut Context) {
    cx.editor.focus_direction(tree::Direction::Up)
}

fn jump_view_down(cx: &mut Context) {
    cx.editor.focus_direction(tree::Direction::Down)
}

fn swap_view_right(cx: &mut Context) {
    cx.editor.swap_split_in_direction(tree::Direction::Right)
}

fn swap_view_left(cx: &mut Context) {
    cx.editor.swap_split_in_direction(tree::Direction::Left)
}

fn swap_view_up(cx: &mut Context) {
    cx.editor.swap_split_in_direction(tree::Direction::Up)
}

fn swap_view_down(cx: &mut Context) {
    cx.editor.swap_split_in_direction(tree::Direction::Down)
}

fn transpose_view(cx: &mut Context) {
    cx.editor.transpose_view()
}

/// JetBrains "Move to Opposite Tab Group": move the current editor into the adjacent split group,
/// swapping with whatever split is in the first available direction (right/left/down/up).
fn move_to_opposite_group(cx: &mut Context) {
    for dir in [
        tree::Direction::Right,
        tree::Direction::Left,
        tree::Direction::Down,
        tree::Direction::Up,
    ] {
        if cx.editor.tree.swap_split_in_direction(dir).is_some() {
            return;
        }
    }
    cx.editor.set_status("No opposite split group to move to");
}

/// Open a new split in the given direction specified by the action.
///
/// Maintain the current view (both the cursor's position and view in document).
fn split(editor: &mut Editor, action: Action) {
    let (view, doc) = current!(editor);
    let id = doc.id();
    let selection = doc.selection(view.id).clone();
    let offset = doc.view_offset(view.id);

    editor.switch(id, action);

    // match the selection in the previous view
    let (view, doc) = current!(editor);
    doc.set_selection(view.id, selection);
    // match the view scroll offset (switch doesn't handle this fully
    // since the selection is only matched after the split)
    doc.set_view_offset(view.id, offset);
}

fn hsplit(cx: &mut Context) {
    split(cx.editor, Action::HorizontalSplit);
}

fn hsplit_new(cx: &mut Context) {
    cx.editor.new_file(Action::HorizontalSplit);
}

fn vsplit(cx: &mut Context) {
    split(cx.editor, Action::VerticalSplit);
}

fn vsplit_new(cx: &mut Context) {
    cx.editor.new_file(Action::VerticalSplit);
}

/// SPC b N i : clone the current buffer into a new split. zemacs views share their underlying
/// Document — text and edits propagate between them — so a second view of the same buffer is
/// functionally an Emacs indirect buffer of the same base. Spacemacs `make-indirect-buffer`.
fn clone_indirect_buffer(cx: &mut Context) {
    split(cx.editor, Action::VerticalSplit);
    cx.editor
        .set_status("indirect clone: new view sharing this buffer");
}

fn wclose(cx: &mut Context) {
    winner_record(cx);
    if cx.editor.tree.views().count() == 1 {
        if let Err(err) = typed::buffers_remaining_impl(cx.editor) {
            cx.editor.set_error(err.to_string());
            return;
        }
    }
    let view_id = view!(cx.editor).id;
    // close current split
    cx.editor.close(view_id);
}

fn wonly(cx: &mut Context) {
    winner_record(cx);
    let views = cx
        .editor
        .tree
        .views()
        .map(|(v, focus)| (v.id, focus))
        .collect::<Vec<_>>();
    for (view_id, focus) in views {
        if !focus {
            cx.editor.close(view_id);
        }
    }
}

// --- winner-mode: undo/redo of window-layout changes (Spacemacs SPC w u / w . u / w . U) ---
struct WinnerHistory {
    stack: Vec<(Vec<std::path::PathBuf>, usize)>,
    pos: usize,
}
static WINNER: std::sync::Mutex<WinnerHistory> = std::sync::Mutex::new(WinnerHistory {
    stack: Vec::new(),
    pos: 0,
});

/// Snapshot the current window layout onto the winner history (truncating any redo tail).
/// Called before window-mutating commands so their previous layout can be restored.
fn winner_record(cx: &mut Context) {
    let cur = layout_capture(cx);
    let mut w = WINNER.lock().unwrap();
    // Skip if identical to the current tip (avoid duplicate snapshots).
    if w.stack.get(w.pos).map(|c| c == &cur).unwrap_or(false) {
        return;
    }
    let pos = w.pos;
    if !w.stack.is_empty() {
        w.stack.truncate(pos + 1);
    }
    w.stack.push(cur);
    w.pos = w.stack.len() - 1;
}

/// SPC w u : undo the last window-layout change (winner-undo).
fn winner_undo(cx: &mut Context) {
    let cur = layout_capture(cx);
    let target = {
        let mut w = WINNER.lock().unwrap();
        // Ensure the current layout is the tip so redo can return to it.
        if w.stack.get(w.pos).map(|c| c != &cur).unwrap_or(true) {
            let pos = w.pos;
            if !w.stack.is_empty() {
                w.stack.truncate(pos + 1);
            }
            w.stack.push(cur);
            w.pos = w.stack.len() - 1;
        }
        if w.pos > 0 {
            w.pos -= 1;
            Some(w.stack[w.pos].clone())
        } else {
            None
        }
    };
    match target {
        Some((files, focused)) => {
            layout_restore(cx, &files, focused);
            cx.editor
                .set_status("winner-undo: restored previous window layout");
        }
        None => cx
            .editor
            .set_status("winner-undo: no earlier window layout"),
    }
}

/// SPC w U : redo a window-layout change undone by winner-undo (winner-redo).
fn winner_redo(cx: &mut Context) {
    let target = {
        let mut w = WINNER.lock().unwrap();
        if w.pos + 1 < w.stack.len() {
            w.pos += 1;
            Some(w.stack[w.pos].clone())
        } else {
            None
        }
    };
    match target {
        Some((files, focused)) => {
            layout_restore(cx, &files, focused);
            cx.editor
                .set_status("winner-redo: restored next window layout");
        }
        None => cx.editor.set_status("winner-redo: no later window layout"),
    }
}

/// vim `=` expression register: prompt on the command line for an expression,
/// evaluate it with the embedded viml interpreter, and hand the result string to
/// `on_result`. Backs both `` "= `` (normal-mode register select) and
/// `i_CTRL-R =` (insert-mode register paste).
fn eval_expression_register(
    cx: &mut Context,
    on_result: impl Fn(&mut crate::compositor::Context, String) + 'static,
) {
    ui::prompt(
        cx,
        "=".into(),
        None,
        |_, _| Vec::new(),
        move |cx, input, event| {
            if event != PromptEvent::Validate || input.is_empty() {
                return;
            }
            match crate::commands::scripting::eval_viml(cx, input) {
                Ok(result) => on_result(cx, result),
                Err(e) => cx.editor.set_error(e),
            }
        },
    );
}

fn select_register(cx: &mut Context) {
    cx.editor.autoinfo = Some(Info::from_registers(
        "Select register",
        &cx.editor.registers,
    ));
    cx.on_next_key(move |cx, event| {
        cx.editor.autoinfo = None;
        if let Some(ch) = event.char() {
            if ch == '=' {
                // Evaluate now and stash the result in `=` so the pending
                // operator (e.g. `p`) reads it, matching vim.
                eval_expression_register(cx, |cx, result| {
                    let _ = cx.editor.registers.write('=', vec![result]);
                    cx.editor.selected_register = Some('=');
                });
                return;
            }
            cx.editor.selected_register = Some(ch);
        }
    })
}

fn insert_register(cx: &mut Context) {
    // TODO: count is reset to 1 before next key so we move it into the closure here.
    // Would be nice to carry over.
    let count = cx.count();
    cx.editor.autoinfo = Some(Info::from_registers(
        "Insert register",
        &cx.editor.registers,
    ));
    cx.on_next_key(move |cx, event| {
        cx.editor.autoinfo = None;
        if let Some(ch) = event.char() {
            if ch == '=' {
                // vim `i_CTRL-R =`: prompt, evaluate, insert the result at the cursor.
                eval_expression_register(cx, move |cx, result| {
                    let mode = cx.editor.mode;
                    let (view, doc) = current!(cx.editor);
                    paste_impl(&[result], doc, view, Paste::Cursor, count, mode);
                });
                return;
            }
            cx.register = Some(ch);
            paste(
                cx.editor,
                cx.register
                    .unwrap_or(cx.editor.config().default_yank_register),
                Paste::Cursor,
                count,
            );
        }
    })
}

/// Emacs `view-register` (C-x r v): prompt for a register and show its contents
/// on the status line as a one-line preview.
fn view_register(cx: &mut Context) {
    cx.editor.autoinfo = Some(Info::from_registers("View register", &cx.editor.registers));
    cx.on_next_key(move |cx, event| {
        cx.editor.autoinfo = None;
        let Some(ch) = event.char() else {
            return;
        };
        let contents: Option<Vec<String>> = cx
            .editor
            .registers
            .read(ch, cx.editor)
            .map(|vals| vals.map(|v| v.to_string()).collect());
        match contents {
            Some(v) if !v.is_empty() => {
                let joined = v.join(" ⏎ ");
                let n = joined.chars().count();
                let preview: String = joined.chars().take(140).collect();
                let ell = if n > 140 { "…" } else { "" };
                cx.editor
                    .set_status(format!("Register {ch}: {preview}{ell}"));
            }
            _ => cx.editor.set_status(format!("Register {ch} is empty")),
        }
    });
}

/// The primary selection's text (empty when the selection is a caret).
fn primary_selection_text(cx: &Context) -> String {
    let (view, doc) = current_ref!(cx.editor);
    let sel = doc.selection(view.id).primary();
    doc.text().slice(sel.from()..sel.to()).to_string()
}

/// Emacs `copy-to-register` (`C-x r s r`): store the region in register `r`,
/// replacing its contents. Prompts for the register character.
fn copy_to_register(cx: &mut Context) {
    let text = primary_selection_text(cx);
    if text.is_empty() {
        cx.editor.set_status("copy-to-register: empty region");
        return;
    }
    cx.editor.autoinfo = Some(Info::from_registers(
        "Copy to register",
        &cx.editor.registers,
    ));
    cx.on_next_key(move |cx, event| {
        cx.editor.autoinfo = None;
        let Some(reg) = event.char() else {
            return;
        };
        if let Err(e) = cx.editor.registers.write(reg, vec![text.clone()]) {
            cx.editor.set_error(e.to_string());
        } else {
            cx.editor
                .set_status(format!("copied region to register {reg}"));
        }
    });
}

/// Combine the region with register `r`'s existing text (Emacs
/// `append-to-register` / `prepend-to-register`). `append` puts the region
/// after the current contents; otherwise before.
fn region_to_register(cx: &mut Context, append: bool) {
    let text = primary_selection_text(cx);
    if text.is_empty() {
        cx.editor.set_status("register: empty region");
        return;
    }
    let label = if append {
        "Append to register"
    } else {
        "Prepend to register"
    };
    cx.editor.autoinfo = Some(Info::from_registers(label, &cx.editor.registers));
    cx.on_next_key(move |cx, event| {
        cx.editor.autoinfo = None;
        let Some(reg) = event.char() else {
            return;
        };
        let existing: String = cx
            .editor
            .registers
            .read(reg, cx.editor)
            .map(|vals| vals.collect::<Vec<_>>().join("\n"))
            .unwrap_or_default();
        let combined = if append {
            format!("{existing}{text}")
        } else {
            format!("{text}{existing}")
        };
        if let Err(e) = cx.editor.registers.write(reg, vec![combined]) {
            cx.editor.set_error(e.to_string());
        } else {
            cx.editor.set_status(format!(
                "{} register {reg}",
                if append {
                    "appended to"
                } else {
                    "prepended to"
                }
            ));
        }
    });
}

/// Emacs `append-to-register` (`C-x r a r`).
fn append_to_register(cx: &mut Context) {
    region_to_register(cx, true);
}

/// Emacs `prepend-to-register` (`C-x r p r`).
fn prepend_to_register(cx: &mut Context) {
    region_to_register(cx, false);
}

fn copy_between_registers(cx: &mut Context) {
    cx.editor.autoinfo = Some(Info::from_registers(
        "Copy from register",
        &cx.editor.registers,
    ));
    cx.on_next_key(move |cx, event| {
        cx.editor.autoinfo = None;

        let Some(source) = event.char() else {
            return;
        };

        let Some(values) = cx.editor.registers.read(source, cx.editor) else {
            cx.editor.set_error(format!("register {source} is empty"));
            return;
        };
        let values: Vec<_> = values.map(|value| value.to_string()).collect();

        cx.editor.autoinfo = Some(Info::from_registers(
            "Copy into register",
            &cx.editor.registers,
        ));
        cx.on_next_key(move |cx, event| {
            cx.editor.autoinfo = None;

            let Some(dest) = event.char() else {
                return;
            };

            let n_values = values.len();
            match cx.editor.registers.write(dest, values) {
                Ok(_) => cx.editor.set_status(format!(
                    "yanked {n_values} value{} from register {source} to {dest}",
                    if n_values == 1 { "" } else { "s" }
                )),
                Err(err) => cx.editor.set_error(err.to_string()),
            }
        });
    });
}

fn align_view_top(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    align_view(doc, view, Align::Top);
}

fn align_view_center(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    align_view(doc, view, Align::Center);
}

fn align_view_bottom(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    align_view(doc, view, Align::Bottom);
}

fn align_view_middle(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let inner_width = view.inner_width(doc);
    let text_fmt = doc.text_format(inner_width, None, Some(view.id));
    // there is no horizontal position when softwrap is enabled
    if text_fmt.soft_wrap {
        return;
    }
    let doc_text = doc.text().slice(..);
    let pos = doc.selection(view.id).primary().cursor(doc_text);
    let pos = visual_offset_from_block(
        doc_text,
        doc.view_offset(view.id).anchor,
        pos,
        &text_fmt,
        &view.text_annotations(doc, None),
    )
    .0;

    let mut offset = doc.view_offset(view.id);
    offset.horizontal_offset = pos
        .col
        .saturating_sub((view.inner_area(doc).width as usize) / 2);
    doc.set_view_offset(view.id, offset);
}

// --- horizontal scroll (vim z h / z l / z H / z L) ---------------------------
fn scroll_column_impl(cx: &mut Context, cols: usize, right: bool) {
    let (view, doc) = current!(cx.editor);
    let mut offset = doc.view_offset(view.id);
    offset.horizontal_offset = if right {
        offset.horizontal_offset.saturating_add(cols)
    } else {
        offset.horizontal_offset.saturating_sub(cols)
    };
    doc.set_view_offset(view.id, offset);
}

fn scroll_column_right(cx: &mut Context) {
    let n = cx.count();
    scroll_column_impl(cx, n, true);
}

fn scroll_column_left(cx: &mut Context) {
    let n = cx.count();
    scroll_column_impl(cx, n, false);
}

fn scroll_half_column_right(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let half = (view.inner_area(doc).width as usize / 2).max(1);
    scroll_column_impl(cx, half, true);
}

fn scroll_half_column_left(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let half = (view.inner_area(doc).width as usize / 2).max(1);
    scroll_column_impl(cx, half, false);
}

// --- window width resize (vim CTRL-W < / CTRL-W > / CTRL-W |) -----------------
fn resize_view_wider(cx: &mut Context) {
    let delta = cx.count() as i16;
    let view = cx.editor.tree.focus;
    cx.editor.tree.resize_horizontal(view, delta);
}

fn resize_view_narrower(cx: &mut Context) {
    let delta = cx.count() as i16;
    let view = cx.editor.tree.focus;
    cx.editor.tree.resize_horizontal(view, -delta);
}

fn resize_view_taller(cx: &mut Context) {
    let delta = cx.count() as i16;
    let view = cx.editor.tree.focus;
    cx.editor.tree.resize_vertical(view, delta);
}

fn resize_view_shorter(cx: &mut Context) {
    let delta = cx.count() as i16;
    let view = cx.editor.tree.focus;
    cx.editor.tree.resize_vertical(view, -delta);
}

fn resize_view_equalize(cx: &mut Context) {
    cx.editor.tree.equalize();
}

/// Resize the focused window to the golden ratio (~62% of the frame), the
/// primary effect of Spacemacs golden-ratio mode (SPC t g / SPC w . g). Uses
/// only the public resize APIs — no core layout surgery.
fn golden_ratio_resize(cx: &mut Context) {
    const PHI: f32 = 0.618;
    cx.editor.tree.equalize();
    let total = cx.editor.tree.area();
    let focus = cx.editor.tree.focus;
    let cur = cx.editor.tree.get(focus).area;
    let dw = (total.width as f32 * PHI) as i16 - cur.width as i16;
    let dh = (total.height as f32 * PHI) as i16 - cur.height as i16;
    if dw > 0 {
        cx.editor.tree.resize_horizontal(focus, dw);
    }
    if dh > 0 {
        cx.editor.tree.resize_vertical(focus, dh);
    }
}

// --- digraphs (vim i_CTRL-K {char1}{char2}) ----------------------------------
// A practical subset of vim's RFC-1345 digraph table: accented Latin letters,
// common punctuation/symbols, currency, fractions, Greek, and arrows. Typed as
// two characters after CTRL-K.
#[rustfmt::skip]
const DIGRAPHS: &[(char, char, char)] = &[
    // grave / acute / circumflex / tilde / diaeresis / ring — lowercase
    ('a','!','à'),('a','\'','á'),('a','>','â'),('a','?','ã'),('a',':','ä'),('a','a','å'),('a','e','æ'),
    ('e','!','è'),('e','\'','é'),('e','>','ê'),('e',':','ë'),
    ('i','!','ì'),('i','\'','í'),('i','>','î'),('i',':','ï'),
    ('o','!','ò'),('o','\'','ó'),('o','>','ô'),('o','?','õ'),('o',':','ö'),('o','/','ø'),
    ('u','!','ù'),('u','\'','ú'),('u','>','û'),('u',':','ü'),
    ('n','?','ñ'),('c',',','ç'),('y','\'','ý'),('y',':','ÿ'),('s','s','ß'),
    // uppercase
    ('A','!','À'),('A','\'','Á'),('A','>','Â'),('A','?','Ã'),('A',':','Ä'),('A','A','Å'),('A','E','Æ'),
    ('E','!','È'),('E','\'','É'),('E','>','Ê'),('E',':','Ë'),
    ('I','!','Ì'),('I','\'','Í'),('I','>','Î'),('I',':','Ï'),
    ('O','!','Ò'),('O','\'','Ó'),('O','>','Ô'),('O','?','Õ'),('O',':','Ö'),('O','/','Ø'),
    ('U','!','Ù'),('U','\'','Ú'),('U','>','Û'),('U',':','Ü'),
    ('N','?','Ñ'),('C',',','Ç'),('Y','\'','Ý'),
    // punctuation / symbols
    ('C','o','©'),('R','g','®'),('T','M','™'),('D','G','°'),('+','-','±'),('M','y','µ'),
    ('S','E','§'),('P','I','¶'),('P','d','£'),('Y','e','¥'),('C','t','¢'),('E','u','€'),
    ('*','X','×'),('-',':','÷'),('1','4','¼'),('1','2','½'),('3','4','¾'),
    ('<','<','«'),('>','>','»'),('?','I','¿'),('!','I','¡'),('o','o','°'),
    ('\'','6','‘'),('\'','9','’'),('"','6','“'),('"','9','”'),('-','N','–'),('-','M','—'),
    ('R','T','√'),('0','0','∞'),('!','=','≠'),('=','<','≤'),('=','>','≥'),
    // arrows
    ('-','>','→'),('<','-','←'),('-','!','↑'),('-','v','↓'),('=','>','⇒'),
    // greek (lower)
    ('a','*','α'),('b','*','β'),('g','*','γ'),('d','*','δ'),('e','*','ε'),('z','*','ζ'),
    ('y','*','η'),('h','*','θ'),('i','*','ι'),('k','*','κ'),('l','*','λ'),('m','*','μ'),
    ('n','*','ν'),('c','*','ξ'),('p','*','π'),('r','*','ρ'),('s','*','σ'),('t','*','τ'),
    ('u','*','υ'),('f','*','φ'),('x','*','χ'),('q','*','ψ'),('w','*','ω'),
    // greek (upper)
    ('D','*','Δ'),('H','*','Θ'),('L','*','Λ'),('C','*','Ξ'),('P','*','Π'),('S','*','Σ'),
    ('F','*','Φ'),('Q','*','Ψ'),('W','*','Ω'),('G','*','Γ'),
];

fn digraph_lookup(a: char, b: char) -> Option<char> {
    DIGRAPHS
        .iter()
        .find(|(x, y, _)| (*x == a && *y == b) || (*x == b && *y == a))
        .map(|(_, _, c)| *c)
}

// vim i_CTRL-E / i_CTRL-Y: insert the character that is directly below / above
// the cursor (same column on the adjacent line).
fn copy_char_from_adjacent_line(cx: &mut Context, below: bool) {
    let ch = {
        let (view, doc) = current!(cx.editor);
        let text = doc.text();
        let pos = doc.selection(view.id).primary().cursor(text.slice(..));
        let line = text.char_to_line(pos);
        let col = pos - text.line_to_char(line);
        let target = if below {
            line + 1
        } else if line == 0 {
            return;
        } else {
            line - 1
        };
        if target >= text.len_lines() {
            return;
        }
        let tstart = text.line_to_char(target);
        let tline = text.line(target);
        let mut len = tline.len_chars();
        if len > 0 && tline.get_char(len - 1) == Some('\n') {
            len -= 1;
        }
        if col >= len {
            return;
        }
        text.char(tstart + col)
    };
    insert::insert_char(cx, ch);
}

// --- spell checking (vim z= / zg / zw / [s / ]s) -----------------------------
/// Alphabetic-run word ranges across the whole buffer.
fn spell_word_ranges(text: RopeSlice) -> Vec<(usize, usize)> {
    let len = text.len_chars();
    let mut ranges = Vec::new();
    let mut i = 0;
    while i < len {
        if text.char(i).is_alphabetic() {
            let start = i;
            while i < len && text.char(i).is_alphabetic() {
                i += 1;
            }
            ranges.push((start, i));
        } else {
            i += 1;
        }
    }
    ranges
}

/// The word range + text under the cursor (ranges are sorted by position).
fn spell_word_at(text: RopeSlice, pos: usize) -> Option<(usize, usize, String)> {
    for (s, e) in spell_word_ranges(text) {
        if pos >= s && pos < e {
            return Some((s, e, text.slice(s..e).chars().collect()));
        }
        if s > pos {
            break;
        }
    }
    None
}

fn goto_spell_error(cx: &mut Context, forward: bool) {
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);
    let pos = doc.selection(view.id).primary().cursor(text);
    let ranges = spell_word_ranges(text);
    let misspelled: Vec<(usize, usize)> = ranges
        .into_iter()
        .filter(|&(s, e)| {
            crate::spell::is_misspelled(&text.slice(s..e).chars().collect::<String>())
        })
        .collect();
    if misspelled.is_empty() {
        cx.editor.set_status("No misspelled words");
        return;
    }
    let target = if forward {
        misspelled
            .iter()
            .find(|&&(s, _)| s > pos)
            .or_else(|| misspelled.first())
    } else {
        misspelled
            .iter()
            .rev()
            .find(|&&(s, _)| s < pos)
            .or_else(|| misspelled.last())
    };
    if let Some(&(s, _)) = target {
        push_jump(view, doc);
        doc.set_selection(view.id, Selection::point(s));
    }
}

fn goto_next_spell_error(cx: &mut Context) {
    goto_spell_error(cx, true);
}
fn goto_prev_spell_error(cx: &mut Context) {
    goto_spell_error(cx, false);
}

fn spell_word_under_cursor(cx: &mut Context) -> Option<(usize, usize, String)> {
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);
    let pos = doc.selection(view.id).primary().cursor(text);
    spell_word_at(text, pos)
}

fn spell_add_good(cx: &mut Context) {
    if let Some((_, _, w)) = spell_word_under_cursor(cx) {
        crate::spell::add_good(&w);
        cx.editor
            .set_status(format!("Added '{w}' to spellfile (good)"));
    }
}
fn spell_add_bad(cx: &mut Context) {
    if let Some((_, _, w)) = spell_word_under_cursor(cx) {
        crate::spell::add_bad(&w);
        cx.editor.set_status(format!("Marked '{w}' as misspelled"));
    }
}
fn spell_undo(cx: &mut Context) {
    if let Some((_, _, w)) = spell_word_under_cursor(cx) {
        crate::spell::remove_user(&w);
        cx.editor
            .set_status(format!("Removed '{w}' from spellfile"));
    }
}

/// vim `z=`: show numbered suggestions for the word under the cursor; the next
/// digit key replaces the word with that suggestion.
fn spell_suggest(cx: &mut Context) {
    let Some((start, end, word)) = spell_word_under_cursor(cx) else {
        return;
    };
    let suggestions: Vec<String> = crate::spell::suggest(&word).into_iter().take(9).collect();
    if suggestions.is_empty() {
        cx.editor.set_status(format!("No suggestions for '{word}'"));
        return;
    }
    let rows: Vec<(String, String)> = suggestions
        .iter()
        .enumerate()
        .map(|(i, s)| (format!("{}", i + 1), s.clone()))
        .collect();
    cx.editor.autoinfo = Some(Info::new(format!("Change \"{word}\" to"), &rows));
    cx.on_next_key(move |cx, ev| {
        cx.editor.autoinfo = None;
        let Some(d) = ev.char().and_then(|c| c.to_digit(10)) else {
            return;
        };
        let idx = d as usize;
        if idx == 0 || idx > suggestions.len() {
            return;
        }
        let repl = suggestions[idx - 1].clone();
        let (view, doc) = current!(cx.editor);
        let tx = Transaction::change(
            doc.text(),
            [(start, end, Some(repl.as_str().into()))].into_iter(),
        );
        doc.apply(&tx, view.id);
    });
}

/// Emacs `flyspell-auto-correct-word` (C-.): replace the misspelled word at
/// point with the top spelling suggestion, without prompting.
fn flyspell_auto_correct_word(cx: &mut Context) {
    let Some((start, end, word)) = spell_word_under_cursor(cx) else {
        cx.editor.set_status("No word at point");
        return;
    };
    if !crate::spell::is_misspelled(&word) {
        cx.editor.set_status(format!("\"{word}\" is correct"));
        return;
    }
    let Some(repl) = crate::spell::suggest(&word).into_iter().next() else {
        cx.editor.set_status(format!("No suggestions for '{word}'"));
        return;
    };
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(
        doc.text(),
        [(start, end, Some(repl.as_str().into()))].into_iter(),
    );
    doc.apply(&tx, view.id);
    cx.editor.set_status(format!("corrected to \"{repl}\""));
}

/// Emacs `view-buffer`: make the current buffer read-only for viewing.
fn view_buffer(cx: &mut Context) {
    let (_, doc) = current!(cx.editor);
    doc.readonly = true;
    cx.editor.set_status("View mode: buffer is read-only");
}

/// Emacs `view-file` (C-x C-r): open a file read-only for viewing. Prompts for
/// the path.
fn view_file(cx: &mut Context) {
    ui::prompt(
        cx,
        "View file: ".into(),
        None,
        |_editor, _input| Vec::new(),
        move |cx, input, event| {
            if event != PromptEvent::Validate || input.trim().is_empty() {
                return;
            }
            let path = zemacs_stdx::path::expand_tilde(std::path::Path::new(input.trim()));
            match cx.editor.open(&path, Action::Replace) {
                Ok(_) => {
                    let (_, doc) = current!(cx.editor);
                    doc.readonly = true;
                    cx.editor.set_status("View mode: read-only");
                }
                Err(e) => cx.editor.set_error(format!("view-file: {e}")),
            }
        },
    );
}

// ---------------------------------------------------------------------------
// Emacs `ispell`: drive an external speller (aspell / hunspell / ispell) in
// `-a` pipe mode. The `-a` output protocol is parsed by the pure, tested
// zemacs_core::ispell; these commands spawn the program and apply corrections.
// ---------------------------------------------------------------------------

/// The dictionary set by `ispell-change-dictionary` (e.g. "en_GB"), or None.
fn ispell_dictionary() -> &'static std::sync::RwLock<Option<String>> {
    static D: std::sync::OnceLock<std::sync::RwLock<Option<String>>> = std::sync::OnceLock::new();
    D.get_or_init(|| std::sync::RwLock::new(None))
}

/// Run `<prog> -a` over `lines`, returning the misspellings per input line, or
/// None if no speller program is installed. Mirrors `ispell-program-name`'s
/// search order: aspell, then hunspell, then ispell.
fn ispell_check(lines: &[String]) -> Option<Vec<Vec<zemacs_core::ispell::Misspelling>>> {
    use std::io::Write;
    let dict = ispell_dictionary().read().ok().and_then(|d| d.clone());
    let args = zemacs_core::ispell::pipe_args(dict.as_deref());
    let mut input = String::new();
    for l in lines {
        input.push_str(&zemacs_core::ispell::escape_line(l));
        input.push('\n');
    }
    for prog in ["aspell", "hunspell", "ispell"] {
        let child = std::process::Command::new(prog)
            .args(&args)
            .stdin(std::process::Stdio::piped())
            .stdout(std::process::Stdio::piped())
            .stderr(std::process::Stdio::null())
            .spawn();
        let mut child = match child {
            Ok(c) => c,
            Err(_) => continue, // program not found — try the next
        };
        if let Some(stdin) = child.stdin.take() {
            let mut stdin = stdin;
            let _ = stdin.write_all(input.as_bytes());
            // dropping stdin closes it, signalling EOF
        }
        let out = match child.wait_with_output() {
            Ok(o) => o,
            Err(_) => return None,
        };
        let text = String::from_utf8_lossy(&out.stdout);
        // Drop the version banner, then split into per-input-line blocks by the
        // blank line the program prints after each checked line.
        let body: Vec<&str> = text.lines().skip_while(|l| l.starts_with("@(#)")).collect();
        let mut per_line = Vec::with_capacity(lines.len());
        let mut cur: Vec<zemacs_core::ispell::Misspelling> = Vec::new();
        for l in body {
            if l.trim().is_empty() {
                per_line.push(std::mem::take(&mut cur));
            } else if let Some(zemacs_core::ispell::WordCheck::Misspelled {
                word,
                offset,
                suggestions,
            }) = zemacs_core::ispell::parse_line(l)
            {
                cur.push(zemacs_core::ispell::Misspelling {
                    word,
                    offset,
                    suggestions,
                });
            }
        }
        if !cur.is_empty() {
            per_line.push(cur);
        }
        // Pad to one entry per input line so callers can index by line.
        while per_line.len() < lines.len() {
            per_line.push(Vec::new());
        }
        return Some(per_line);
    }
    None
}

/// Emacs `ispell-word` (M-$): check the word at point with the external speller
/// and, if misspelled, offer its suggestions for replacement.
fn ispell_word(cx: &mut Context) {
    let Some((start, end, word)) = spell_word_under_cursor(cx) else {
        cx.editor.set_status("No word at point");
        return;
    };
    let Some(per_line) = ispell_check(std::slice::from_ref(&word)) else {
        cx.editor
            .set_error("no speller found (install aspell, hunspell, or ispell)");
        return;
    };
    let miss = per_line.into_iter().next().unwrap_or_default();
    let Some(m) = miss.into_iter().next() else {
        cx.editor.set_status(format!("\"{word}\" is correct"));
        return;
    };
    if m.suggestions.is_empty() {
        cx.editor
            .set_status(format!("\"{word}\" is misspelled (no suggestions)"));
        return;
    }
    let suggestions: Vec<String> = m.suggestions.into_iter().take(9).collect();
    let rows: Vec<(String, String)> = suggestions
        .iter()
        .enumerate()
        .map(|(i, s)| (format!("{}", i + 1), s.clone()))
        .collect();
    cx.editor.autoinfo = Some(Info::new(format!("Change \"{word}\" to"), &rows));
    cx.on_next_key(move |cx, ev| {
        cx.editor.autoinfo = None;
        let Some(d) = ev.char().and_then(|c| c.to_digit(10)) else {
            return;
        };
        let idx = d as usize;
        if idx == 0 || idx > suggestions.len() {
            return;
        }
        let repl = suggestions[idx - 1].clone();
        let (view, doc) = current!(cx.editor);
        let tx = Transaction::change(
            doc.text(),
            [(start, end, Some(repl.as_str().into()))].into_iter(),
        );
        doc.apply(&tx, view.id);
    });
}

/// Check a char range of the current buffer, move point to the first
/// misspelling, and report the count. Shared by `ispell-region`/`-buffer`.
fn ispell_range(cx: &mut Context, from: usize, to: usize, label: &str) {
    let text = doc!(cx.editor).text().clone();
    let slice = text.slice(from..to);
    // Feed line by line so offsets map back per line.
    let lines: Vec<String> = slice.to_string().split('\n').map(str::to_string).collect();
    let Some(per_line) = ispell_check(&lines) else {
        cx.editor
            .set_error("no speller found (install aspell, hunspell, or ispell)");
        return;
    };
    // Map (line index, in-line offset) back to a buffer char position.
    let mut first: Option<usize> = None;
    let mut count = 0usize;
    let mut line_start = from;
    for (i, line) in lines.iter().enumerate() {
        if let Some(miss) = per_line.get(i) {
            for m in miss {
                count += 1;
                if first.is_none() {
                    first = Some(line_start + m.offset.min(line.chars().count()));
                }
            }
        }
        line_start += line.chars().count() + 1; // +1 for the split '\n'
    }
    if count == 0 {
        cx.editor.set_status(format!("{label}: no misspellings"));
        return;
    }
    if let Some(pos) = first {
        let (view, doc) = current!(cx.editor);
        push_jump(view, doc);
        let pos = pos.min(doc.text().len_chars());
        doc.set_selection(view.id, Selection::point(pos));
    }
    cx.editor.set_status(format!(
        "{label}: {count} misspelling{} — M-$ to correct the word at point",
        if count == 1 { "" } else { "s" }
    ));
}

/// Emacs `ispell-region`: spell-check the selection.
fn ispell_region(cx: &mut Context) {
    let (from, to) = {
        let (view, doc) = current!(cx.editor);
        let r = doc.selection(view.id).primary();
        (r.from(), r.to())
    };
    if from == to {
        cx.editor.set_status("ispell-region: no region selected");
        return;
    }
    ispell_range(cx, from, to, "ispell-region");
}

/// Emacs `ispell-buffer`: spell-check the whole buffer.
fn ispell_buffer(cx: &mut Context) {
    let len = doc!(cx.editor).text().len_chars();
    ispell_range(cx, 0, len, "ispell-buffer");
}

/// Emacs `ispell` (M-x ispell): check the region if one is selected, else the
/// whole buffer.
fn ispell(cx: &mut Context) {
    let has_region = {
        let (view, doc) = current!(cx.editor);
        let r = doc.selection(view.id).primary();
        r.from() != r.to()
    };
    if has_region {
        ispell_region(cx);
    } else {
        ispell_buffer(cx);
    }
}

/// Emacs `ispell-kill-ispell`: there is no persistent speller process (each
/// check spawns a fresh one), so this just reports that.
fn ispell_kill_ispell(cx: &mut Context) {
    cx.editor
        .set_status("ispell: no persistent process to kill");
}

/// Emacs `ispell-change-dictionary`: prompt for the dictionary passed to the
/// speller as `-d` (e.g. "en_GB", "de_DE"); empty restores the default.
fn ispell_change_dictionary(cx: &mut Context) {
    ui::prompt(
        cx,
        "Change dictionary to: ".into(),
        None,
        |_editor, _input| Vec::new(),
        move |cx, input, event| {
            if event != PromptEvent::Validate {
                return;
            }
            let dict = input.trim().to_string();
            if let Ok(mut slot) = ispell_dictionary().write() {
                *slot = if dict.is_empty() {
                    None
                } else {
                    Some(dict.clone())
                };
            }
            cx.editor.set_status(format!(
                "ispell dictionary: {}",
                if dict.is_empty() { "default" } else { &dict }
            ));
        },
    );
}

/// Open the unified Preferences window (tabs: Settings, Keymap, Color Scheme, Run Configs).
fn preferences(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::preferences::PreferencesPanel::new(0)) as Box<dyn Component>)
    });
}

/// Emacs `set-selective-display` (`C-x $`): with a numeric prefix N, hide every
/// line indented N columns or more (only lines starting with fewer than N columns
/// of indentation stay visible); with no prefix, turn selective display off.
///
/// Implemented over the fold model — each run of over-indented lines is collapsed
/// under the nearest preceding visible line. Because it reuses folds, invoking it
/// first clears any existing folds in the buffer.
fn set_selective_display(cx: &mut Context) {
    let column = cx.count.map(|n| n.get()).unwrap_or(0);
    let (_view, doc) = current!(cx.editor);
    doc.folds_mut().clear();
    let msg = if column == 0 {
        "selective display disabled".to_string()
    } else {
        let tab_width = doc.tab_width();
        let text = doc.text();
        let slice = text.slice(..);
        let last = slice.len_lines().saturating_sub(1);
        let indents: Vec<usize> = (0..slice.len_lines())
            .map(|l| {
                let ws: String = slice
                    .line(l)
                    .chars()
                    .take_while(|c| *c == ' ' || *c == '\t')
                    .collect();
                zemacs_core::selective_display::leading_indent_columns(&ws, tab_width)
            })
            .collect();
        let ranges = zemacs_core::selective_display::selective_display_folds(&indents, column);
        let n = ranges.len();
        for (start, end) in ranges {
            doc.folds_mut().create(start, end);
        }
        doc.folds_mut().clamp(last);
        format!("selective display: hiding lines indented past column {column} ({n} region(s))")
    };
    cx.editor.set_status(msg);
}

/// Emacs `global-whitespace-toggle-options` / whitespace-mode: toggle rendering of
/// whitespace characters (spaces, tabs, newlines) in every buffer.
fn global_whitespace_toggle_options(cx: &mut Context) {
    use zemacs_view::editor::{WhitespaceRender, WhitespaceRenderValue};
    let on = matches!(
        cx.editor.config().whitespace.render.space(),
        WhitespaceRenderValue::All
    );
    let new = if on {
        WhitespaceRenderValue::None
    } else {
        WhitespaceRenderValue::All
    };
    edit_live_config(cx, move |c| {
        c.whitespace.render = WhitespaceRender::Basic(new);
    });
    cx.editor.set_status(format!(
        "whitespace display {}",
        if on { "off" } else { "on" }
    ));
}

/// Emacs `global-tab-line-mode`: toggle the per-window buffer tab line (zemacs's
/// bufferline) between always-on and off.
fn global_tab_line_mode(cx: &mut Context) {
    use zemacs_view::editor::BufferLine;
    let on = !matches!(cx.editor.config().bufferline, BufferLine::Never);
    let new = if on {
        BufferLine::Never
    } else {
        BufferLine::Always
    };
    edit_live_config(cx, move |c| c.bufferline = new);
    cx.editor
        .set_status(format!("tab-line {}", if on { "off" } else { "on" }));
}

/// Emacs `global-visual-wrap-prefix-mode`: continuation lines of a wrapped line
/// keep the original line's indentation as a prefix. zemacs has no prefix-only
/// mode, so this toggles soft-wrap with indentation carry-over (`max-indent-retain`).
fn global_visual_wrap_prefix_mode(cx: &mut Context) {
    let on = cx.editor.config().soft_wrap.enable.unwrap_or(false);
    let new = !on;
    edit_live_config(cx, move |c| {
        c.soft_wrap.enable = Some(new);
        if new && c.soft_wrap.max_indent_retain.is_none() {
            c.soft_wrap.max_indent_retain = Some(40);
        }
    });
    cx.editor.set_status(format!(
        "visual wrap prefix (soft-wrap with indent) {}",
        if new { "on" } else { "off" }
    ));
}

/// Open the configuration page on the Help tab (searchable: commands, keybindings, topics).
fn help(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::preferences::PreferencesPanel::new(4)) as Box<dyn Component>)
    });
}

/// Open the embedded-language REPL panel (defaults to elisp; Tab switches).
fn repl(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::repl::ReplPanel::new(
            crate::ui::repl::ReplLang::Elisp,
        )) as Box<dyn Component>)
    });
}

/// Open Preferences on the Run/Debug Configurations tab.
fn run_config_manager(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::preferences::PreferencesPanel::new(3)) as Box<dyn Component>)
    });
}

/// Open Preferences on the Dashboard tab (live system/process stats).
fn dashboard(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::preferences::PreferencesPanel::new(5)) as Box<dyn Component>)
    });
}

/// Open an integrated terminal running the user's `$SHELL` in a PTY.
///
/// Pushes the panel through the job queue (an `EditorCompositor` callback)
/// rather than `cx.push_layer`, because the command palette executes commands
/// with a throwaway context and drops `push_layer` callbacks — so a `push_layer`
/// here would do nothing from `SPC SPC terminal`. Jobs are carried through, so
/// this works both from a keybinding and from the palette.
fn terminal(cx: &mut Context) {
    let call: job::Callback = Callback::EditorCompositor(Box::new(|editor, compositor| {
        match crate::ui::terminal::TerminalPanel::new() {
            Ok(panel) => compositor.push(Box::new(panel)),
            Err(e) => editor.set_error(format!("terminal: {e}")),
        }
    }));
    cx.jobs.callback(async move { Ok(call) });
}

/// Open a comint line-oriented shell buffer on `$SHELL` (emacs `M-x shell`).
fn comint_shell(cx: &mut Context) {
    let call: job::Callback = Callback::EditorCompositor(Box::new(|editor, compositor| {
        match crate::ui::comint::Comint::shell() {
            Ok(panel) => compositor.push(Box::new(panel)),
            Err(e) => editor.set_error(format!("shell: {e}")),
        }
    }));
    cx.jobs.callback(async move { Ok(call) });
}

/// Run `gdb` in a comint buffer — the classic comint-driven `gud-gdb` (distinct
/// from the DAP-backed `gdb`/`dap-launch`, which drives GDB over the Debug
/// Adapter Protocol instead of its text CLI).
fn gud_gdb(cx: &mut Context) {
    let call: job::Callback = Callback::EditorCompositor(Box::new(|editor, compositor| {
        match crate::ui::comint::Comint::with_program("gdb", &["--fullname"]) {
            Ok(panel) => compositor.push(Box::new(panel)),
            Err(e) => editor.set_error(format!("gud-gdb: {e}")),
        }
    }));
    cx.jobs.callback(async move { Ok(call) });
}

/// Send an owned command line to the active comint buffer (the inferior
/// debugger). Shared by every `gud-*` driver.
fn gud_send_owned(cx: &mut Context, cmd: String) {
    cx.callback
        .push(Box::new(move |compositor: &mut Compositor, cx| {
            if let Some(comint) = compositor.find::<crate::ui::comint::Comint>() {
                comint.send_command(&cmd);
            } else {
                cx.editor.set_error("gud: no active comint debugger buffer");
            }
        }));
}

/// Send a fixed command to the active comint buffer, for the no-argument
/// `gud-*` stepping/frame commands.
fn gud_send(cx: &mut Context, cmd: &'static str) {
    gud_send_owned(cx, cmd.to_string());
}

/// The raw (non-regex-escaped) word/symbol at the cursor, for `gud-print` /
/// `gud-watch` debugger expressions.
fn gud_word_at_point(cx: &mut Context) -> Option<String> {
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);
    let range = doc.selection(view.id).primary();
    let word = if range.from() != range.to() {
        range
    } else {
        textobject::textobject_word(text, range, textobject::TextObject::Inside, 1, false)
    };
    let s = text.slice(word.from()..word.to()).to_string();
    let s = s.trim().to_string();
    if s.is_empty() {
        None
    } else {
        Some(s)
    }
}

/// The current buffer's file path and 1-based cursor line, for `gud-*`
/// breakpoint commands.
fn gud_file_line(cx: &mut Context) -> Option<(String, usize)> {
    let (view, doc) = current!(cx.editor);
    let path = doc.path()?.to_string_lossy().to_string();
    let text = doc.text().slice(..);
    let line = text.char_to_line(doc.selection(view.id).primary().cursor(text)) + 1;
    Some((path, line))
}

/// `gud-tbreak`: set a temporary breakpoint at the current source line.
fn gud_tbreak(cx: &mut Context) {
    let Some((file, line)) = gud_file_line(cx) else {
        cx.editor.set_error("gud-tbreak: buffer has no file");
        return;
    };
    gud_send_owned(cx, format!("tbreak {file}:{line}"));
}

/// `gud-print`: print the value of the expression at point in the debugger.
fn gud_print(cx: &mut Context) {
    let Some(word) = gud_word_at_point(cx) else {
        cx.editor.set_error("gud-print: no symbol at point");
        return;
    };
    gud_send_owned(cx, format!("print {word}"));
}

/// `gud-watch`: set a watch on the expression at point.
fn gud_watch(cx: &mut Context) {
    let Some(word) = gud_word_at_point(cx) else {
        cx.editor.set_error("gud-watch: no symbol at point");
        return;
    };
    gud_send_owned(cx, format!("watch {word}"));
}

/// `gud-gdb-complete-command`: complete the gdb command word at point. zemacs
/// sends gdb's own `complete WORD` to the inferior debugger; the candidates are
/// printed in the debugger (comint) buffer. This is a partial port: unlike
/// Emacs there is no in-place completion of the command line itself.
fn gud_gdb_complete_command(cx: &mut Context) {
    let Some(word) = gud_word_at_point(cx) else {
        cx.editor
            .set_error("gud-gdb-complete-command: no command word at point");
        return;
    };
    gud_send_owned(cx, format!("complete {word}"));
    cx.editor.set_status(
        "gud-gdb-complete-command: sent `complete` to gdb (candidates print in the debugger buffer)",
    );
}

/// `gud-up`: select the stack frame one level up (emacs `gud-up`).
fn gud_up(cx: &mut Context) {
    gud_send(cx, "up");
}

/// `gud-down`: select the stack frame one level down (emacs `gud-down`).
fn gud_down(cx: &mut Context) {
    gud_send(cx, "down");
}

/// `gud-stepi`: step one machine instruction (emacs `gud-stepi`).
fn gud_stepi(cx: &mut Context) {
    gud_send(cx, "stepi");
}

/// `gud-jump`: set the debugger's execution point to the current source line
/// (emacs `gud-jump`) by sending `jump FILE:LINE` to the inferior debugger.
fn gud_jump(cx: &mut Context) {
    let Some((file, line)) = gud_file_line(cx) else {
        cx.editor.set_error("gud-jump: buffer has no file");
        return;
    };
    gud_send_owned(cx, format!("jump {file}:{line}"));
}

/// `gud-refresh` (C-l): redisplay the debugger buffer / recenter output. zemacs
/// requests a redraw and scrolls the comint to the newest output.
fn gud_refresh(cx: &mut Context) {
    comint_action(cx, |comint, cx| {
        comint.show_maximum_output();
        cx.editor.set_status("gud-refresh: redisplayed");
    });
    zemacs_event::request_redraw();
}

// --------------------------------------------------------------------------
// comint editing / job-control / navigation commands.
//
// Each acts on the active `Comint` overlay found in the compositor (the buffer
// opened by `M-x shell` / `gud-gdb`). The job-control commands deliver real Unix
// signals to the child process; the editing/navigation commands drive the
// comint input line and scrollback via unit-tested helpers in
// `zemacs_core::comint`.
// --------------------------------------------------------------------------

/// Find the active comint overlay and run `f` against it; error if none is open.
fn comint_action<F>(cx: &mut Context, f: F)
where
    F: FnOnce(&mut crate::ui::comint::Comint, &mut crate::compositor::Context) + Send + 'static,
{
    cx.callback
        .push(Box::new(move |compositor: &mut Compositor, cx| {
            if let Some(comint) = compositor.find::<crate::ui::comint::Comint>() {
                f(comint, cx);
            } else {
                cx.editor.set_error("comint: no active shell/comint buffer");
            }
        }));
}

/// `comint-kill-input` (C-c C-u): discard the pending (unsubmitted) input line.
fn comint_kill_input(cx: &mut Context) {
    comint_action(cx, |comint, _| comint.kill_input());
}

/// `comint-bol-or-process-mark` (C-a): move to the process mark, or the true
/// beginning of line when already there.
fn comint_bol_or_process_mark(cx: &mut Context) {
    comint_action(cx, |comint, _| comint.bol_or_process_mark());
}

/// `comint-delchar-or-maybe-eof` (C-d): delete the char after point, or send EOF
/// (close the child's stdin) when the input line is empty.
fn comint_delchar_or_maybe_eof(cx: &mut Context) {
    comint_action(cx, |comint, cx| {
        if comint.delchar_or_maybe_eof() {
            cx.editor.set_status("comint: sent EOF");
        }
    });
}

/// `comint-magic-space`: expand history designators (`!!`, `!$`, …) then insert
/// a space on the input line.
fn comint_magic_space(cx: &mut Context) {
    comint_action(cx, |comint, _| comint.magic_space());
}

