// --- Emacs list / s-expression motion (C-M-n/p/d/u, kill-sexp) --------------
// Balanced-paren movement over the pure zemacs_core::list_motion.

/// Move point to the target of a pure list-motion function (or report a scan
/// error and stay put).
fn list_motion(cx: &mut Context, f: fn(&str, usize) -> Option<usize>) {
    let (text, cursor) = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        (
            doc.text().to_string(),
            doc.selection(view.id).primary().cursor(slice),
        )
    };
    match f(&text, cursor) {
        Some(pos) => {
            let scrolloff = cx.editor.config().scrolloff;
            let (view, doc) = current!(cx.editor);
            push_jump(view, doc);
            let pos = pos.min(doc.text().len_chars());
            doc.set_selection(view.id, Selection::point(pos));
            view.ensure_cursor_in_view(doc, scrolloff);
        }
        None => cx.editor.set_status("scan error: unbalanced or no list"),
    }
}

fn forward_list(cx: &mut Context) {
    list_motion(cx, zemacs_core::list_motion::forward_list);
}
fn backward_list(cx: &mut Context) {
    list_motion(cx, zemacs_core::list_motion::backward_list);
}
fn down_list(cx: &mut Context) {
    list_motion(cx, zemacs_core::list_motion::down_list);
}
fn up_list(cx: &mut Context) {
    list_motion(cx, zemacs_core::list_motion::up_list);
}
fn backward_up_list(cx: &mut Context) {
    list_motion(cx, zemacs_core::list_motion::backward_up_list);
}

/// Emacs `kill-sexp` (C-M-k): kill the s-expression after point.
fn kill_sexp(cx: &mut Context) {
    let (text, cursor) = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        (
            doc.text().to_string(),
            doc.selection(view.id).primary().cursor(slice),
        )
    };
    let Some(end) = zemacs_core::list_motion::forward_sexp(&text, cursor) else {
        cx.editor.set_status("no s-expression after point");
        return;
    };
    let (from, to) = (cursor.min(end), cursor.max(end));
    if from == to {
        return;
    }
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(doc.text(), [(from, to, None)].into_iter());
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
}

/// Emacs `mark-sexp` (C-M-SPC): set the region from point to the end of the
/// following s-expression, leaving point at its end (the mark stays behind).
fn mark_sexp(cx: &mut Context) {
    let (text, cursor) = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        (
            doc.text().to_string(),
            doc.selection(view.id).primary().cursor(slice),
        )
    };
    let Some(end) = zemacs_core::list_motion::forward_sexp(&text, cursor) else {
        cx.editor.set_status("no s-expression after point");
        return;
    };
    if end == cursor {
        return;
    }
    let (view, doc) = current!(cx.editor);
    let end = end.min(doc.text().len_chars());
    doc.set_selection(view.id, Selection::single(cursor, end));
}

/// Emacs `forward-sexp` (C-M-f): move point forward over the next balanced
/// s-expression (a list or an atom).
fn forward_sexp(cx: &mut Context) {
    list_motion(cx, zemacs_core::list_motion::forward_sexp);
}

/// Emacs `backward-sexp` (C-M-b): move point backward over the previous balanced
/// s-expression.
fn backward_sexp(cx: &mut Context) {
    list_motion(cx, zemacs_core::list_motion::backward_sexp);
}

/// Emacs `copy-region-as-kill` (M-w): copy the region to the kill ring without
/// deleting it (the non-destructive companion of `kill-region`).
fn copy_region_as_kill(cx: &mut Context) {
    let text = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        let sel = doc.selection(view.id).primary();
        if sel.from() == sel.to() {
            None
        } else {
            Some(slice.slice(sel.from()..sel.to()).to_string())
        }
    };
    match text {
        Some(t) => {
            let n = t.chars().count();
            crate::emacs_kill::record(t);
            cx.editor
                .set_status(format!("copied {n} char(s) to the kill ring"));
        }
        None => cx.editor.set_status("no region to copy"),
    }
}

/// Emacs `mark-word` (M-@): set the region from point over the next word, leaving
/// the mark behind and point at the word end (the count-th word with a count).
fn mark_word(cx: &mut Context) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    let slice = doc.text().slice(..);
    let point = doc.selection(view.id).primary().cursor(slice);
    let moved = movement::move_next_word_end(slice, Range::point(point), count);
    let head = moved.cursor(slice);
    if head == point {
        cx.editor.set_status("no word after point");
        return;
    }
    doc.set_selection(view.id, Selection::single(point, head));
}

/// Emacs `mark-paragraph` (M-h): select the paragraph around point, leaving point
/// at its beginning and the mark at its end.
fn mark_paragraph(cx: &mut Context) {
    let count = cx.count();
    let (view, doc) = current!(cx.editor);
    let slice = doc.text().slice(..);
    let point = doc.selection(view.id).primary().cursor(slice);
    let obj = textobject::textobject_paragraph(
        slice,
        Range::point(point),
        textobject::TextObject::Around,
        count,
    );
    // point (head) at paragraph start, mark (anchor) at end.
    doc.set_selection(view.id, Selection::single(obj.to(), obj.from()));
}

/// Emacs `mark-defun` (C-M-h): select the function/defun around point via the
/// tree-sitter `function` object, leaving point at its start and mark at its end.
fn mark_defun(cx: &mut Context) {
    let count = cx.count();
    let loader = cx.editor.syn_loader.load();
    let result = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        let range = doc.selection(view.id).primary();
        doc.syntax().map(|syntax| {
            let obj = textobject::textobject_treesitter(
                slice,
                range,
                textobject::TextObject::Around,
                "function",
                syntax,
                &loader,
                count,
            );
            (view.id, obj.from(), obj.to())
        })
    };
    match result {
        Some((vid, from, to)) if from != to => {
            let (_view, doc) = current!(cx.editor);
            let len = doc.text().len_chars();
            doc.set_selection(vid, Selection::single(to.min(len), from.min(len)));
        }
        _ => cx
            .editor
            .set_status("mark-defun: no function at point (needs a parsed syntax tree)"),
    }
}

/// Emacs `kill-sentence` (M-k): kill from point to the end of the sentence,
/// saving the killed text to the kill ring.
fn kill_sentence(cx: &mut Context) {
    let (from, to, killed) = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        let cursor = doc.selection(view.id).primary().cursor(slice);
        let end = zemacs_core::movement::next_sentence_boundary(slice, cursor);
        if end <= cursor {
            (cursor, cursor, String::new())
        } else {
            (cursor, end, slice.slice(cursor..end).to_string())
        }
    };
    if from == to {
        cx.editor.set_status("end of buffer");
        return;
    }
    crate::emacs_kill::record(killed);
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(doc.text(), [(from, to, None)].into_iter());
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
}

/// Emacs `backward-kill-sentence` (C-x DEL): kill from the start of the sentence
/// to point, saving the killed text to the kill ring.
fn backward_kill_sentence(cx: &mut Context) {
    let (from, to, killed) = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        let cursor = doc.selection(view.id).primary().cursor(slice);
        let start = zemacs_core::movement::prev_sentence_boundary(slice, cursor);
        if start >= cursor {
            (cursor, cursor, String::new())
        } else {
            (start, cursor, slice.slice(start..cursor).to_string())
        }
    };
    if from == to {
        cx.editor.set_status("beginning of buffer");
        return;
    }
    // Backward kill: `append-next-kill` prepends this text to the previous entry.
    crate::emacs_kill::record_prepend(killed);
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(doc.text(), [(from, to, None)].into_iter());
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
}

/// Emacs `append-next-kill` (C-M-w): tell the following command, if it is a kill
/// command, to treat its kill as part of the sequence of previous kills — the
/// text is appended to the most-recent kill-ring entry for a forward kill and
/// prepended for a backward kill, so several separated pieces yank back as one.
fn append_next_kill(cx: &mut Context) {
    crate::emacs_kill::arm_append();
    cx.editor
        .set_status("if the next command is a kill, it will be appended to the last kill");
}

/// Move point to a page boundary computed by a pure `zemacs_core::page` function
/// (`forward-page` / `backward-page`). Pages are delimited by the `^L` form feed.
fn page_motion(cx: &mut Context, f: fn(&str, usize) -> usize) {
    let (text, cursor) = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        (
            doc.text().to_string(),
            doc.selection(view.id).primary().cursor(slice),
        )
    };
    let pos = f(&text, cursor);
    let scrolloff = cx.editor.config().scrolloff;
    let (view, doc) = current!(cx.editor);
    push_jump(view, doc);
    let pos = pos.min(doc.text().len_chars());
    doc.set_selection(view.id, Selection::point(pos));
    view.ensure_cursor_in_view(doc, scrolloff);
}

/// Emacs `forward-page` (C-x ]): move to the start of the next `^L`-delimited page.
fn forward_page(cx: &mut Context) {
    page_motion(cx, zemacs_core::page::forward_page);
}

/// Emacs `backward-page` (C-x [): move to the start of the previous page.
fn backward_page(cx: &mut Context) {
    page_motion(cx, zemacs_core::page::backward_page);
}

/// Emacs `mark-page` (C-x C-p): select the current `^L`-delimited page, leaving
/// point at its start and the mark at its end.
fn mark_page(cx: &mut Context) {
    let (text, cursor) = {
        let (view, doc) = current_ref!(cx.editor);
        let slice = doc.text().slice(..);
        (
            doc.text().to_string(),
            doc.selection(view.id).primary().cursor(slice),
        )
    };
    let (start, end) = zemacs_core::page::page_bounds(&text, cursor);
    let (view, doc) = current!(cx.editor);
    let len = doc.text().len_chars();
    // anchor at page end, head (point) at page start — matches Emacs mark-page.
    doc.set_selection(view.id, Selection::single(end.min(len), start.min(len)));
}

/// SPC b w: toggle the current buffer's read-only (writable) state.
fn toggle_readonly(cx: &mut Context) {
    let (_view, doc) = current!(cx.editor);
    doc.readonly = !doc.readonly;
    let state = if doc.readonly {
        "read-only"
    } else {
        "writable"
    };
    cx.editor.set_status(format!("buffer is now {state}"));
}

/// Spacemacs `SPC w t`: toggle window dedication. A dedicated window keeps its
/// buffer — opening a different buffer is redirected to a split (see
/// `Editor::switch`) instead of replacing this one.
fn toggle_window_dedication(cx: &mut Context) {
    let view = view_mut!(cx.editor);
    view.dedicated = !view.dedicated;
    let on = view.dedicated;
    cx.editor.set_status(format!(
        "window dedication: {}",
        if on { "on" } else { "off" }
    ));
}

/// Spacemacs subword-mode (`SPC t c`): toggle sub-word `w`/`b`/`e` motions.
fn toggle_subword(cx: &mut Context) {
    cx.editor.subword = !cx.editor.subword;
    let on = cx.editor.subword;
    cx.editor
        .set_status(format!("subword motion: {}", if on { "on" } else { "off" }));
}

/// Spacemacs follow-mode (`SPC w f`): toggle synchronized scrolling of windows
/// that show the same document (one continuous view).
fn toggle_follow_mode(cx: &mut Context) {
    cx.editor.follow = !cx.editor.follow;
    let on = cx.editor.follow;
    if on {
        cx.editor.sync_follow_windows();
    }
    cx.editor
        .set_status(format!("follow mode: {}", if on { "on" } else { "off" }));
}

/// Spacemacs auto-fill-mode (`SPC t F`): toggle auto-wrapping at text_width.
fn toggle_auto_fill(cx: &mut Context) {
    cx.editor.auto_fill = !cx.editor.auto_fill;
    let on = cx.editor.auto_fill;
    cx.editor.set_status(format!(
        "auto-fill: {} (text-width {})",
        if on { "on" } else { "off" },
        cx.editor.config().text_width
    ));
}

// Subword-aware word-motion dispatchers: when subword-mode is on, the `w`/`b`/`e`
// motions (and every operator built on the `extend_*` variants) move by sub-word
// instead of word. When off they call the original command, so behavior is
// identical. This keeps the core motion fns untouched.
fn subword_w(cx: &mut Context) {
    if cx.editor.subword {
        // vim-faithful landing (ON the next sub-word start), like vim_move_*.
        move_word_vim_impl(cx, movement::move_next_sub_word_start, false)
    } else {
        vim_move_next_word_start(cx)
    }
}
fn subword_b(cx: &mut Context) {
    if cx.editor.subword {
        move_word_vim_impl(cx, movement::move_prev_sub_word_start, false)
    } else {
        vim_move_prev_word_start(cx)
    }
}
fn subword_e(cx: &mut Context) {
    if cx.editor.subword {
        move_word_vim_impl(cx, movement::move_next_sub_word_end, true)
    } else {
        vim_move_next_word_end(cx)
    }
}
fn subword_extend_w(cx: &mut Context) {
    if cx.editor.subword {
        extend_next_sub_word_start(cx)
    } else {
        extend_next_word_start(cx)
    }
}
fn subword_extend_b(cx: &mut Context) {
    if cx.editor.subword {
        extend_prev_sub_word_start(cx)
    } else {
        extend_prev_word_start(cx)
    }
}
fn subword_extend_e(cx: &mut Context) {
    if cx.editor.subword {
        extend_next_sub_word_end(cx)
    } else {
        extend_next_word_end(cx)
    }
}

fn scroll_up(cx: &mut Context) {
    scroll(cx, cx.count(), Direction::Backward, false);
}

fn scroll_down(cx: &mut Context) {
    scroll(cx, cx.count(), Direction::Forward, false);
}

fn goto_ts_object_impl(cx: &mut Context, object: &'static str, direction: Direction) {
    let count = cx.count();
    let motion = move |editor: &mut Editor| {
        let (view, doc) = current!(editor);
        let loader = editor.syn_loader.load();
        if let Some(syntax) = doc.syntax() {
            let text = doc.text().slice(..);

            let selection = doc.selection(view.id).clone().transform(|range| {
                let new_range = movement::goto_treesitter_object(
                    text, range, object, direction, syntax, &loader, count,
                );

                if editor.mode == Mode::Select {
                    let head = if new_range.head < range.anchor {
                        new_range.anchor
                    } else {
                        new_range.head
                    };

                    Range::new(range.anchor, head)
                } else {
                    new_range.with_direction(direction)
                }
            });

            push_jump(view, doc);
            doc.set_selection(view.id, selection);
        } else {
            editor.set_status("Syntax-tree is not available in current buffer");
        }
    };
    cx.editor.apply_motion(motion);
}

fn goto_next_function(cx: &mut Context) {
    goto_ts_object_impl(cx, "function", Direction::Forward)
}

fn goto_prev_function(cx: &mut Context) {
    goto_ts_object_impl(cx, "function", Direction::Backward)
}

fn goto_next_class(cx: &mut Context) {
    goto_ts_object_impl(cx, "class", Direction::Forward)
}

fn goto_prev_class(cx: &mut Context) {
    goto_ts_object_impl(cx, "class", Direction::Backward)
}

fn goto_next_parameter(cx: &mut Context) {
    goto_ts_object_impl(cx, "parameter", Direction::Forward)
}

fn goto_prev_parameter(cx: &mut Context) {
    goto_ts_object_impl(cx, "parameter", Direction::Backward)
}

fn goto_next_comment(cx: &mut Context) {
    goto_ts_object_impl(cx, "comment", Direction::Forward)
}

fn goto_prev_comment(cx: &mut Context) {
    goto_ts_object_impl(cx, "comment", Direction::Backward)
}

fn goto_next_test(cx: &mut Context) {
    goto_ts_object_impl(cx, "test", Direction::Forward)
}

fn goto_prev_test(cx: &mut Context) {
    goto_ts_object_impl(cx, "test", Direction::Backward)
}

/// Runs of ≥2 consecutive `true` flags as inclusive (start, end) ranges. Pure.
fn comment_fold_runs(flags: &[bool]) -> Vec<(usize, usize)> {
    let mut out = Vec::new();
    let n = flags.len();
    let mut l = 0;
    while l < n {
        if flags[l] {
            let s = l;
            while l < n && flags[l] {
                l += 1;
            }
            if l - 1 > s {
                out.push((s, l - 1));
            }
        } else {
            l += 1;
        }
    }
    out
}

/// SPC c h: hide/show comments by folding multi-line comment blocks (lines whose
/// trimmed text starts with the language's line-comment token). Toggles: if any
/// comment fold is open, re-fold; the widen is on SPC n w / zR.
fn fold_comments(cx: &mut Context) {
    let loader = cx.editor.syn_loader.load();
    let (view, doc) = current!(cx.editor);
    let tokens: Vec<String> = doc
        .language_config_at(&loader, 0)
        .and_then(|c| c.comment_tokens.as_deref())
        .map(<[String]>::to_vec)
        .unwrap_or_default();
    if tokens.is_empty() {
        cx.editor.set_status("no comment syntax for this buffer");
        return;
    }
    let text = doc.text();
    let n = text.len_lines();
    let flags: Vec<bool> = (0..n)
        .map(|l| {
            let s = text.line(l).to_string();
            let t = s.trim_start();
            tokens.iter().any(|tok| t.starts_with(tok.as_str()))
        })
        .collect();
    let runs = comment_fold_runs(&flags);
    if runs.is_empty() {
        cx.editor.set_status("no multi-line comment blocks to fold");
        return;
    }
    let count = runs.len();
    for (s, e) in runs {
        doc.folds_mut().create(s, e);
    }
    doc.folds_mut().clamp(n.saturating_sub(1));
    let _ = view;
    cx.editor
        .set_status(format!("folded {count} comment block(s)"));
}

/// Candidate counterpart file names for impl<->test toggling. If `name` looks
/// like a test file, returns the implementation name; otherwise returns common
/// test-file names. Pure (tested).
fn test_counterpart_names(name: &str) -> Vec<String> {
    let (stem, dotext) = match name.rfind('.') {
        Some(i) => (&name[..i], &name[i..]),
        None => (name, ""),
    };
    let mut out = Vec::new();
    if let Some(s) = stem
        .strip_suffix("_test")
        .or_else(|| stem.strip_suffix("_spec"))
    {
        out.push(format!("{s}{dotext}"));
    }
    if let Some(s) = stem
        .strip_prefix("test_")
        .or_else(|| stem.strip_prefix("spec_"))
    {
        out.push(format!("{s}{dotext}"));
    }
    if let Some(s) = stem
        .strip_suffix(".test")
        .or_else(|| stem.strip_suffix(".spec"))
    {
        out.push(format!("{s}{dotext}"));
    }
    if !out.is_empty() {
        return out;
    }
    out.push(format!("{stem}_test{dotext}"));
    out.push(format!("{stem}_spec{dotext}"));
    out.push(format!("test_{stem}{dotext}"));
    if !dotext.is_empty() {
        let ext = &dotext[1..];
        out.push(format!("{stem}.test.{ext}"));
        out.push(format!("{stem}.spec.{ext}"));
    }
    out
}

/// SPC p a: toggle between an implementation file and its test counterpart,
/// trying common naming conventions in the same directory and a `tests/` sibling.
fn toggle_test_file(cx: &mut Context) {
    let Some(path) = doc!(cx.editor).path().map(|p| p.to_path_buf()) else {
        cx.editor.set_error("buffer has no file path");
        return;
    };
    let Some(name) = path.file_name().and_then(|n| n.to_str()).map(String::from) else {
        return;
    };
    let dir = path.parent().map(|p| p.to_path_buf()).unwrap_or_default();
    let cands = test_counterpart_names(&name);
    // search dirs: same dir, a `tests/` subdir, and a sibling `tests/` dir
    let mut dirs = vec![dir.clone(), dir.join("tests")];
    if let Some(parent) = dir.parent() {
        dirs.push(parent.join("tests"));
        dirs.push(parent.join("src"));
    }
    for d in &dirs {
        for cand in &cands {
            let p = d.join(cand);
            if p.exists() && p != path {
                match cx.editor.open(&p, Action::Replace) {
                    Ok(_) => cx.editor.set_status(format!("→ {}", p.display())),
                    Err(e) => cx.editor.set_error(format!("{e}")),
                }
                return;
            }
        }
    }
    cx.editor
        .set_status("no implementation/test counterpart found");
}

